{
  "name": "Industrial-Grade CNC Digital Twin",
  "description": "A comprehensive Digital Twin platform for CNC drilling machines featuring real-time 3D visualization, IoT telemetry monitoring, and AI-driven predictive maintenance (RUL) using Gemini 3 Pro."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum MachineHealth {
  HEALTHY = 'HEALTHY',
  WARNING = 'WARNING',
  CRITICAL = 'CRITICAL'
}

export interface TelemetryData {
  timestamp: number;
  rpm: number;
  feedRate: number;
  spindleLoad: number;
  vibration: number; // in Gs
  temperature: number; // in Celsius
  toolWear: number; // 0-100%
  powerConsumption: number; // in kW
}

export interface TwinState {
  id: string;
  name: string;
  model: string;
  health: MachineHealth;
  status: 'IDLE' | 'RUNNING' | 'ERROR' | 'MAINTENANCE';
  telemetry: TelemetryData;
  predictions: {
    rul: number; // Remaining Useful Life in hours
    failureProbability: number; // 0-1
    nextMaintenanceDate: string;
    anomalyDetected: boolean;
  };
}

export interface ChartDataPoint {
  time: string;
  value: number;
}

export const MACHINE_CONFIG = {
  MAX_RPM: 5000,
  MAX_FEED: 1000,
  SAFE_TEMP_THRESHOLD: 75,
  SAFE_VIBRATION_THRESHOLD: 3.5,
  POLLING_INTERVAL_MS: 1000,
};

export const COLORS = {
  HEALTHY: '#22c55e',
  WARNING: '#eab308',
  CRITICAL: '#ef4444',
  ACCENT: '#3b82f6',
  BG_DARK: '#0f172a',
  CARD_DARK: '#1e293b'
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Dashboard } from './components/Dashboard';
import { TelemetryData, TwinState, MachineHealth } from './types';
import { MACHINE_CONFIG } from './constants';

const INITIAL_TELEMETRY: TelemetryData = {
  timestamp: Date.now(),
  rpm: 0,
  feedRate: 0,
  spindleLoad: 0,
  vibration: 0.1,
  temperature: 24,
  toolWear: 5,
  powerConsumption: 0.5
};

const INITIAL_STATE: TwinState = {
  id: 'CNC-X1-DR-001',
  name: 'Main CNC Drill - Line A',
  model: 'Acu-Drill Pro 5000',
  health: MachineHealth.HEALTHY,
  status: 'IDLE',
  telemetry: INITIAL_TELEMETRY,
  predictions: {
    rul: 425.5,
    failureProbability: 0.02,
    nextMaintenanceDate: '2024-06-15',
    anomalyDetected: false
  }
};

const App: React.FC = () => {
  const [twinState, setTwinState] = useState<TwinState>(INITIAL_STATE);
  const [history, setHistory] = useState<TelemetryData[]>([]);
  const stateRef = useRef<TwinState>(INITIAL_STATE);

  // Simulated IoT Ingestion Loop
  useEffect(() => {
    const interval = setInterval(() => {
      setTwinState(prev => {
        const isRunning = prev.status === 'RUNNING';

        // Simulate machine noise and physics
        const noise = (val: number, range: number) => val + (Math.random() - 0.5) * range;

        const nextTelemetry: TelemetryData = {
          timestamp: Date.now(),
          rpm: isRunning ? noise(3200, 50) : 0,
          feedRate: isRunning ? noise(450, 20) : 0,
          spindleLoad: isRunning ? noise(45, 10) : 0,
          vibration: isRunning ? noise(1.2, 0.4) : noise(0.05, 0.02),
          temperature: isRunning ? Math.min(95, prev.telemetry.temperature + 0.1) : Math.max(24, prev.telemetry.temperature - 0.05),
          toolWear: prev.telemetry.toolWear + (isRunning ? 0.0001 : 0),
          powerConsumption: isRunning ? noise(4.5, 0.8) : 0.2
        };

        // Health Logic
        let health = MachineHealth.HEALTHY;
        if (nextTelemetry.temperature > MACHINE_CONFIG.SAFE_TEMP_THRESHOLD || nextTelemetry.vibration > MACHINE_CONFIG.SAFE_VIBRATION_THRESHOLD) {
          health = MachineHealth.WARNING;
        }
        if (nextTelemetry.temperature > 85 || nextTelemetry.vibration > 4.5) {
          health = MachineHealth.CRITICAL;
        }

        const newState = {
          ...prev,
          health,
          telemetry: nextTelemetry,
          predictions: {
            ...prev.predictions,
            rul: Math.max(0, prev.predictions.rul - (isRunning ? 0.001 : 0)),
            failureProbability: health === MachineHealth.CRITICAL ? 0.85 : (health === MachineHealth.WARNING ? 0.35 : 0.02)
          }
        };

        stateRef.current = newState;
        return newState;
      });

      // Keep 50 points of history for charts
      setHistory(prev => {
        const newHist = [...prev, stateRef.current.telemetry];
        return newHist.slice(-50);
      });
    }, MACHINE_CONFIG.POLLING_INTERVAL_MS);

    return () => clearInterval(interval);
  }, []);

  const toggleMachine = useCallback(() => {
    setTwinState(prev => ({
      ...prev,
      status: prev.status === 'RUNNING' ? 'IDLE' : 'RUNNING'
    }));
  }, []);

  const resetMachine = useCallback(() => {
    setTwinState(prev => ({
      ...prev,
      status: 'IDLE',
      telemetry: { ...prev.telemetry, temperature: 24, toolWear: 0 },
      predictions: { ...prev.predictions, rul: 500, failureProbability: 0 }
    }));
  }, []);

  return (
    <div className="w-full h-screen bg-[#0f172a] overflow-hidden flex flex-col">
      <header className="px-6 py-4 bg-[#1e293b] border-b border-slate-700 flex justify-between items-center z-50">
        <div className="flex items-center space-x-4">
          <div className="w-10 h-10 bg-blue-600 rounded-lg flex items-center justify-center">
            <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
            </svg>
          </div>
          <div>
            <h1 className="text-xl font-bold text-white tracking-tight">TwinView Industrial</h1>
            <p className="text-xs text-slate-400 font-medium uppercase tracking-widest">CNC Precision Digital Twin</p>
          </div>
        </div>

        <div className="flex items-center space-x-6">
          <div className="flex flex-col items-end">
            <span className="text-[10px] text-slate-400 font-bold uppercase">System Status</span>
            <div className="flex items-center space-x-2">
              <span className={`w-2 h-2 rounded-full animate-pulse ${twinState.status === 'RUNNING' ? 'bg-green-500' : 'bg-amber-500'}`}></span>
              <span className="text-sm font-semibold text-white">{twinState.status}</span>
            </div>
          </div>
          <div className="h-8 w-[1px] bg-slate-700"></div>
          <div className="flex space-x-3">
             <button 
                onClick={toggleMachine}
                className={`px-4 py-2 rounded font-bold text-sm transition-all ${twinState.status === 'RUNNING' ? 'bg-red-500 hover:bg-red-600 text-white' : 'bg-green-500 hover:bg-green-600 text-white'}`}
              >
                {twinState.status === 'RUNNING' ? 'EMERGENCY STOP' : 'START CYCLE'}
             </button>
             <button 
                onClick={resetMachine}
                className="px-4 py-2 bg-slate-700 hover:bg-slate-600 rounded font-bold text-sm text-white"
              >
                MAINTENANCE RESET
             </button>
          </div>
        </div>
      </header>

      <main className="flex-1 relative overflow-hidden">
        <Dashboard twinState={twinState} history={history} />
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { ThreeScene } from './ThreeScene';
import { TelemetryData, TwinState, MachineHealth } from '../types';
import { TelemetryCharts } from './TelemetryCharts';
import { AIInsights } from './AIInsights';
import { Activity, Thermometer, Zap, Gauge, Tool, Clock, ShieldAlert } from 'lucide-react';

interface DashboardProps {
  twinState: TwinState;
  history: TelemetryData[];
}

export const Dashboard: React.FC<DashboardProps> = ({ twinState, history }) => {
  const stats = [
    { label: 'Spindle RPM', value: `${Math.round(twinState.telemetry.rpm)}`, icon: Activity, color: 'text-blue-400' },
    { label: 'Feed Rate', value: `${Math.round(twinState.telemetry.feedRate)} mm/m`, icon: Gauge, color: 'text-purple-400' },
    { label: 'Load', value: `${Math.round(twinState.telemetry.spindleLoad)}%`, icon: Zap, color: 'text-amber-400' },
    { label: 'Temperature', value: `${twinState.telemetry.temperature.toFixed(1)}°C`, icon: Thermometer, color: twinState.telemetry.temperature > 70 ? 'text-red-400' : 'text-green-400' },
  ];

  const maintenance = [
    { label: 'Remaining Useful Life', value: `${twinState.predictions.rul.toFixed(1)} hrs`, icon: Clock },
    { label: 'Tool Wear Index', value: `${twinState.telemetry.toolWear.toFixed(2)}%`, icon: Tool },
    { label: 'Failure Prob.', value: `${(twinState.predictions.failureProbability * 100).toFixed(1)}%`, icon: ShieldAlert },
  ];

  return (
    <div className="h-full flex flex-col md:flex-row">
      {/* 3D Visualizer - Large Left Column */}
      <div className="flex-1 relative bg-[#020617] min-h-[400px]">
        <div className="absolute top-4 left-4 z-10 space-y-2">
            <div className="bg-slate-900/80 backdrop-blur-md border border-slate-700 p-3 rounded-lg shadow-2xl">
                <h3 className="text-xs font-bold text-slate-400 uppercase mb-1">Live Asset Model</h3>
                <p className="text-white font-mono text-sm">{twinState.id}</p>
                <div className={`mt-2 text-[10px] font-bold px-2 py-0.5 rounded-full inline-block ${
                    twinState.health === MachineHealth.HEALTHY ? 'bg-green-500/20 text-green-400' : 
                    twinState.health === MachineHealth.WARNING ? 'bg-amber-500/20 text-amber-400' : 'bg-red-500/20 text-red-400'
                }`}>
                    {twinState.health}
                </div>
            </div>
        </div>

        <ThreeScene twinState={twinState} />

        <div className="absolute bottom-6 left-6 right-6 grid grid-cols-2 lg:grid-cols-4 gap-4 z-10">
          {stats.map((stat, i) => (
            <div key={i} className="bg-slate-900/80 backdrop-blur-md border border-slate-700 p-4 rounded-xl shadow-xl hover:border-slate-500 transition-colors">
              <div className="flex justify-between items-start mb-2">
                <stat.icon size={20} className={stat.color} />
                <span className="text-[10px] text-slate-500 font-bold uppercase tracking-wider">{stat.label}</span>
              </div>
              <div className="text-2xl font-mono font-bold text-white">{stat.value}</div>
            </div>
          ))}
        </div>
      </div>

      {/* Analytics Sidebar */}
      <div className="w-full md:w-[450px] bg-[#0f172a] border-l border-slate-800 flex flex-col overflow-y-auto">
        <div className="p-6 space-y-6">
          {/* Predictive Maintenance Panel */}
          <section>
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-sm font-bold text-slate-400 uppercase tracking-widest">Predictive AI</h2>
              <span className="px-2 py-1 bg-blue-500/10 text-blue-400 text-[10px] font-bold rounded">MODEL: LSTM-GENV2</span>
            </div>
            <div className="grid grid-cols-1 gap-3">
               {maintenance.map((item, i) => (
                 <div key={i} className="flex items-center justify-between p-3 bg-slate-800/50 rounded-lg border border-slate-700">
                    <div className="flex items-center space-x-3">
                      <div className="p-2 bg-slate-900 rounded-md">
                        <item.icon size={18} className="text-slate-400" />
                      </div>
                      <span className="text-sm font-medium text-slate-300">{item.label}</span>
                    </div>
                    <span className="text-md font-mono font-bold text-white">{item.value}</span>
                 </div>
               ))}
            </div>
          </section>

          {/* Real-time Charts */}
          <section className="flex-1">
             <h2 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-4">Live Telemetry Streams</h2>
             <TelemetryCharts history={history} />
          </section>

          {/* AI Reasoning / Gemini Integration */}
          <section>
             <h2 className="text-sm font-bold text-slate-400 uppercase tracking-widest mb-4">Industrial Insights</h2>
             <AIInsights twinState={twinState} />
          </section>
        </div>
      </div>
    </div>
  );
};

import React, { Suspense } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, PerspectiveCamera, Environment, Grid, ContactShadows, Float } from '@react-three/drei';
import { MachineModel } from './MachineModel';
import { TwinState } from '../types';

interface ThreeSceneProps {
  twinState: TwinState;
}

export const ThreeScene: React.FC<ThreeSceneProps> = ({ twinState }) => {
  return (
    <Canvas shadows className="w-full h-full">
      <Suspense fallback={null}>
        <PerspectiveCamera makeDefault position={[5, 4, 5]} fov={45} />
        <OrbitControls 
            enableDamping 
            dampingFactor={0.05} 
            maxPolarAngle={Math.PI / 2} 
            minDistance={3}
            maxDistance={15}
        />

        {/* Lighting */}
        <ambientLight intensity={0.5} />
        <spotLight position={[10, 10, 10]} angle={0.15} penumbra={1} intensity={1} castShadow />
        <pointLight position={[-10, -10, -10]} intensity={0.5} color="#3b82f6" />

        {/* Environment */}
        <Environment preset="city" />

        {/* Machine Assets */}
        <Float speed={1.5} rotationIntensity={0.2} floatIntensity={0.5}>
           <MachineModel twinState={twinState} />
        </Float>

        {/* Floor and Ground */}
        <Grid 
          infiniteGrid 
          fadeDistance={25} 
          fadeStrength={5} 
          cellSize={1} 
          sectionSize={5} 
          sectionColor="#334155" 
          cellColor="#1e293b" 
        />
        <ContactShadows opacity={0.4} scale={10} blur={2.5} far={4} />
      </Suspense>
    </Canvas>
  );
};

import React, { useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import { Mesh, Color } from 'three';
import { TwinState, MachineHealth } from '../types';
import { COLORS } from '../constants';

interface MachineModelProps {
  twinState: TwinState;
}

export const MachineModel: React.FC<MachineModelProps> = ({ twinState }) => {
  const spindleRef = useRef<Mesh>(null);
  const bitRef = useRef<Mesh>(null);
  const columnRef = useRef<Mesh>(null);

  // Animation and physics mirroring
  useFrame((state, delta) => {
    if (twinState.status === 'RUNNING') {
      // Rotation synced to telemetry RPM
      const rotationSpeed = (twinState.telemetry.rpm / 60) * delta * 2 * Math.PI;
      if (spindleRef.current) spindleRef.current.rotation.y += rotationSpeed;
      if (bitRef.current) bitRef.current.rotation.y += rotationSpeed;

      // Vertical oscillation based on feed rate (drilling simulation)
      const feedDepth = Math.sin(state.clock.elapsedTime * (twinState.telemetry.feedRate / 100)) * 0.5;
      if (bitRef.current) bitRef.current.position.y = 1.2 + feedDepth;
    }
  });

  // Dynamic health color
  const healthColor = twinState.health === MachineHealth.HEALTHY ? COLORS.HEALTHY : 
                  twinState.health === MachineHealth.WARNING ? COLORS.WARNING : COLORS.CRITICAL;

  return (
    <group position={[0, 0, 0]}>
      {/* Base Platform */}
      <mesh position={[0, 0.1, 0]} receiveShadow>
        <boxGeometry args={[4, 0.2, 4]} />
        <meshStandardMaterial color="#1e293b" metalness={0.8} roughness={0.2} />
      </mesh>

      {/* Main Column */}
      <mesh position={[-1.5, 2, 0]} castShadow>
        <boxGeometry args={[0.5, 4, 1]} />
        <meshStandardMaterial color="#334155" metalness={0.6} roughness={0.4} />
      </mesh>

      {/* Horizontal Arm */}
      <mesh position={[-0.5, 3.5, 0]} castShadow>
        <boxGeometry args={[2, 0.5, 0.8]} />
        <meshStandardMaterial color="#475569" metalness={0.7} roughness={0.3} />
      </mesh>

      {/* Spindle Housing */}
      <mesh ref={spindleRef} position={[0.5, 3, 0]} castShadow>
        <cylinderGeometry args={[0.4, 0.4, 1.2, 32]} />
        <meshStandardMaterial color={healthColor} metalness={0.9} roughness={0.1} emissive={new Color(healthColor).multiplyScalar(0.2)} />
      </mesh>

      {/* Drill Bit */}
      <mesh ref={bitRef} position={[0.5, 1.5, 0]} castShadow>
        <cylinderGeometry args={[0.05, 0.05, 1.5, 16]} />
        <meshStandardMaterial color="#94a3b8" metalness={1} roughness={0} />
      </mesh>

      {/* Workpiece Simulation */}
      <mesh position={[0.5, 0.3, 0]} receiveShadow>
        <boxGeometry args={[1, 0.4, 1]} />
        <meshStandardMaterial color="#64748b" metalness={0.2} roughness={0.8} />
      </mesh>

      {/* Health Indicator Light */}
      <pointLight 
        position={[0.5, 3.8, 0]} 
        intensity={1} 
        distance={2} 
        color={healthColor} 
      />
    </group>
  );
};

import React from 'react';
import { 
  LineChart, 
  Line, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  AreaChart,
  Area
} from 'recharts';
import { TelemetryData } from '../types';

interface TelemetryChartsProps {
  history: TelemetryData[];
}

export const TelemetryCharts: React.FC<TelemetryChartsProps> = ({ history }) => {
  const chartData = history.map(h => ({
    time: new Date(h.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' }),
    vibration: parseFloat(h.vibration.toFixed(2)),
    temp: parseFloat(h.temperature.toFixed(1)),
    load: h.spindleLoad
  }));

  return (
    <div className="space-y-6">
      {/* Vibration Monitoring */}
      <div className="bg-slate-900 rounded-xl p-4 border border-slate-800 h-[180px]">
        <h3 className="text-[10px] font-bold text-slate-500 uppercase mb-3">Vibration Spectrum (G)</h3>
        <ResponsiveContainer width="100%" height="100%">
          <AreaChart data={chartData}>
            <defs>
              <linearGradient id="vibeColor" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.3}/>
                <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
              </linearGradient>
            </defs>
            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#1e293b" />
            <XAxis dataKey="time" hide />
            <YAxis hide domain={[0, 5]} />
            <Tooltip 
               contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #1e293b', fontSize: '12px' }}
               itemStyle={{ color: '#60a5fa' }}
            />
            <Area type="monotone" dataKey="vibration" stroke="#3b82f6" fillOpacity={1} fill="url(#vibeColor)" animationDuration={300} isAnimationActive={false} />
          </AreaChart>
        </ResponsiveContainer>
      </div>

      {/* Temperature Trend */}
      <div className="bg-slate-900 rounded-xl p-4 border border-slate-800 h-[180px]">
        <h3 className="text-[10px] font-bold text-slate-500 uppercase mb-3">Thermal Gradient (°C)</h3>
        <ResponsiveContainer width="100%" height="100%">
          <LineChart data={chartData}>
            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#1e293b" />
            <XAxis dataKey="time" hide />
            <YAxis hide domain={[20, 100]} />
            <Tooltip 
               contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #1e293b', fontSize: '12px' }}
               itemStyle={{ color: '#ef4444' }}
            />
            <Line type="step" dataKey="temp" stroke="#ef4444" strokeWidth={2} dot={false} animationDuration={300} isAnimationActive={false} />
          </LineChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getIndustrialInsights(machineState: any) {
  try {
    const prompt = `Act as a senior Industry 4.0 Reliability Engineer. 
    Analyze the current telemetry of a CNC Drill:
    - Current State: ${JSON.stringify(machineState.telemetry)}
    - Predictive Model RUL: ${machineState.predictions.rul} hours
    - Current Health: ${machineState.health}

    Provide a concise (3 sentence max) expert assessment of current operation and maintenance recommendations. 
    Focus on vibration and heat signature. Be technical.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.7,
        systemInstruction: "You are an expert industrial automation consultant. Provide strictly technical, data-driven advice."
      }
    });

    return response.text;
  } catch (error) {
    console.error("Gemini Insight Error:", error);
    return "Analysis unavailable. Ensure sensor data quality meets standards for Edge-AI inference.";
  }
}

import React, { useState, useEffect } from 'react';
import { TwinState } from '../types';
import { getIndustrialInsights } from '../services/geminiService';
import { BrainCircuit, Loader2 } from 'lucide-react';

interface AIInsightsProps {
  twinState: TwinState;
}

export const AIInsights: React.FC<AIInsightsProps> = ({ twinState }) => {
  const [insight, setInsight] = useState<string>('');
  const [loading, setLoading] = useState<boolean>(true);

  useEffect(() => {
    // Only refresh insights when state changes to running or maintenance
    let isMounted = true;

    const fetchInsight = async () => {
      setLoading(true);
      const text = await getIndustrialInsights(twinState);
      if (isMounted) {
        setInsight(text);
        setLoading(false);
      }
    };

    fetchInsight();

    // Refresh every 30 seconds for live updates
    const interval = setInterval(fetchInsight, 30000);

    return () => {
      isMounted = false;
      clearInterval(interval);
    };
  }, [twinState.status]);

  return (
    <div className="bg-blue-900/10 border border-blue-500/30 rounded-xl p-5 relative overflow-hidden">
      <div className="absolute top-0 right-0 p-3 opacity-10">
        <BrainCircuit size={64} className="text-blue-400" />
      </div>

      <div className="flex items-center space-x-2 mb-3">
        <BrainCircuit size={18} className="text-blue-400" />
        <h3 className="text-xs font-bold text-blue-400 uppercase tracking-widest">Expert Inference</h3>
      </div>

      {loading ? (
        <div className="flex items-center space-x-2 text-slate-400 py-2">
          <Loader2 size={16} className="animate-spin" />
          <span className="text-xs font-mono">Running LLM-assisted diagnostics...</span>
        </div>
      ) : (
        <div className="text-xs text-slate-300 leading-relaxed font-mono">
          {insight}
        </div>
      )}

      <div className="mt-4 pt-4 border-t border-blue-500/10 flex justify-between items-center">
        <div className="flex space-x-1">
          <div className="w-1.5 h-1.5 bg-green-500 rounded-full"></div>
          <div className="w-1.5 h-1.5 bg-green-500 rounded-full"></div>
          <div className="w-1.5 h-1.5 bg-slate-700 rounded-full"></div>
        </div>
        <span className="text-[10px] text-blue-400/60 font-bold italic">Generated by Gemini 3.0 Pro</span>
      </div>
    </div>
  );
};

import React from 'react';
import { ThreeScene } from './ThreeScene';
import { TelemetryData, TwinState, MachineHealth } from '../types';
import { TelemetryCharts } from './TelemetryCharts';
import { AIInsights } from './AIInsights';
