import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getIndustrialInsights(machineState: any) {
  try {
    const prompt = `Act as a senior Industry 4.0 Reliability Engineer. 
    Analyze the current telemetry of a CNC Drill with the following configuration:
    - Workpiece Material: ${machineState.config.material.name} (Hardness: ${machineState.config.material.hardnessFactor})
    - Tool Grade: ${machineState.config.toolGrade.name}

    Current Telemetry:
    - State: ${JSON.stringify(machineState.telemetry)}
    - Predictive Model RUL: ${machineState.predictions.rul.toFixed(2)} hours
    - Current Health: ${machineState.health}

    Provide a concise (max 3 sentences) expert assessment. 
    Evaluate if the current tool grade is optimal for the material hardness under these temperature and vibration conditions.
    Be technical and data-driven.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.7,
        systemInstruction: "You are an expert industrial automation consultant. Provide strictly technical, data-driven advice regarding machining physics, chip formation, and tool longevity."
      }
    });

    return response.text;
  } catch (error) {
    console.error("Gemini Insight Error:", error);
    return "Analysis unavailable. Ensure sensor data quality meets standards for Edge-AI inference.";
  }
}

import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import { Mesh, Color, Group, Vector3 } from 'three';
import { Text, Float } from '@react-three/drei';
import { TwinState, MachineHealth } from '../types';
import { COLORS } from '../constants';

interface MachineModelProps {
  twinState: TwinState;
}

export const MachineModel: React.FC<MachineModelProps> = ({ twinState }) => {
  const spindleRef = useRef<Mesh>(null);
  const bitRef = useRef<Mesh>(null);
  const cycleTimeRef = useRef(0);
  const alarmRef = useRef<Group>(null);

  // Constants for movement
  const HOME_Y = 1.6; // Slightly higher idle position
  const CLEARANCE_Y = 1.3; // Rapid to this height
  const DEPTH_Y = 0.4; // Target drilling depth

  // Realistic CNC Drilling Cycle Logic
  useFrame((state, delta) => {
    const isRunning = twinState.status === 'RUNNING';
    const toolWear = twinState.telemetry.toolWear;

    if (isRunning) {
      // 1. Spindle Rotation (RPM synced)
      const rotationSpeed = (twinState.telemetry.rpm / 60) * delta * 2 * Math.PI;
      if (spindleRef.current) spindleRef.current.rotation.y += rotationSpeed;
      if (bitRef.current) bitRef.current.rotation.y += rotationSpeed;

      // 2. Realistic Drilling Cycle (G1 Feed, Dwell, G0 Retract)
      // Total cycle: 4 seconds
      const cycleDuration = 4.0;
      cycleTimeRef.current = (cycleTimeRef.current + delta) % cycleDuration;
      const t = cycleTimeRef.current;

      let currentY = HOME_Y;

      if (t < 0.5) {
        // Rapid Approach (G0) to clearance
        const p = t / 0.5;
        currentY = HOME_Y - (p * (HOME_Y - CLEARANCE_Y));
      } else if (t < 2.5) {
        // Controlled Feed (G1)
        const p = (t - 0.5) / 2.0;
        currentY = CLEARANCE_Y - (p * (CLEARANCE_Y - DEPTH_Y));
      } else if (t < 3.0) {
        // Dwell at bottom
        currentY = DEPTH_Y;
      } else {
        // Rapid Retract (G0)
        const p = (t - 3.0) / 1.0;
        currentY = DEPTH_Y + (p * (HOME_Y - DEPTH_Y));
      }

      if (bitRef.current) {
        bitRef.current.position.y = currentY;
      }
    } else {
      // Reset position when IDLE
      if (bitRef.current) {
        bitRef.current.position.y = HOME_Y;
      }
      cycleTimeRef.current = 0;
    }

    // Alarm Animation (Blinking)
    if (alarmRef.current) {
      const isCritical = toolWear > 80 || twinState.health === MachineHealth.CRITICAL;
      alarmRef.current.visible = isCritical && Math.sin(state.clock.elapsedTime * 10) > 0;
    }
  });

  // Dynamic health color
  const healthColor = twinState.health === MachineHealth.HEALTHY ? COLORS.HEALTHY : 
                  twinState.health === MachineHealth.WARNING ? COLORS.WARNING : COLORS.CRITICAL;

  return (
    <group position={[0, 0, 0]}>
      {/* Base Platform */}
      <mesh position={[0, 0.1, 0]} receiveShadow>
        <boxGeometry args={[4, 0.2, 4]} />
        <meshStandardMaterial color="#1e293b" metalness={0.8} roughness={0.2} />
      </mesh>

      {/* Main Column */}
      <mesh position={[-1.5, 2, 0]} castShadow>
        <boxGeometry args={[0.5, 4, 1]} />
        <meshStandardMaterial color="#334155" metalness={0.6} roughness={0.4} />
      </mesh>

      {/* Horizontal Arm */}
      <mesh position={[-0.5, 3.5, 0]} castShadow>
        <boxGeometry args={[2, 0.5, 0.8]} />
        <meshStandardMaterial color="#475569" metalness={0.7} roughness={0.3} />
      </mesh>

      {/* Spindle Housing */}
      <mesh ref={spindleRef} position={[0.5, 3, 0]} castShadow>
        <cylinderGeometry args={[0.4, 0.4, 1.2, 32]} />
        <meshStandardMaterial color={healthColor} metalness={0.9} roughness={0.1} emissive={new Color(healthColor).multiplyScalar(0.2)} />
      </mesh>

      {/* Drill Bit */}
      <mesh ref={bitRef} position={[0.5, HOME_Y, 0]} castShadow>
        <cylinderGeometry args={[0.05, 0.05, 1.2, 16]} />
        <meshStandardMaterial color="#cbd5e1" metalness={1} roughness={0} />
      </mesh>

      {/* Milling Dynamometer (Force Sensor Plate) */}
      <group position={[0.5, 0.3, 0]}>
        <mesh receiveShadow>
          <boxGeometry args={[1.8, 0.15, 1.8]} />
          <meshStandardMaterial color="#4b5563" metalness={0.9} roughness={0.1} />
        </mesh>
        {/* Sensor connection visual */}
        <mesh position={[0.9, 0, 0]}>
          <boxGeometry args={[0.2, 0.05, 0.1]} />
          <meshStandardMaterial color="#1f2937" />
        </mesh>

        {/* Workpiece on top of Dynamometer */}
        <mesh position={[0, 0.3, 0]} receiveShadow>
          <boxGeometry args={[1.4, 0.4, 1.4]} />
          <meshStandardMaterial color="#64748b" metalness={0.2} roughness={0.8} />
        </mesh>
      </group>

      {/* Tool Wear Alarm Notification */}
      <group ref={alarmRef} position={[0.5, 4.2, 0]}>
        <Float speed={5} rotationIntensity={0} floatIntensity={0.5}>
          <Text
            fontSize={0.2}
            color="#ef4444"
            anchorX="center"
            anchorY="middle"
            font="https://fonts.gstatic.com/s/inter/v12/UcCO3FwrK3iLTeHuS_fvQtMwCp50KnMw2boKoduKmMEVuLyfMZhrib2Bg-4.ttf"
          >
            CRITICAL TOOL WEAR
          </Text>
          <mesh position={[0, -0.2, 0]}>
             <sphereGeometry args={[0.05, 16, 16]} />
             <meshBasicMaterial color="#ef4444" />
          </mesh>
        </Float>
      </group>

      {/* Health Indicator Light */}
      <pointLight 
        position={[0.5, 3.8, 0]} 
        intensity={2} 
        distance={4} 
        color={healthColor} 
      />
    </group>
  );
};

export enum MachineHealth {
  HEALTHY = 'HEALTHY',
  WARNING = 'WARNING',
  CRITICAL = 'CRITICAL'
}

export interface Material {
  id: string;
  name: string;
  hardnessFactor: number; // 1.0 is baseline
  thermalFactor: number; // Higher means better cooling/chip evacuation
}

export interface ToolGrade {
  id: string;
  name: string;
  durabilityFactor: number; // 1.0 is baseline
  heatResistance: number; // 1.0 is baseline
}

export interface TelemetryData {
  timestamp: number;
  rpm: number;
  feedRate: number;
  spindleLoad: number;
  vibration: number; // in Gs
  temperature: number; // in Celsius
  toolWear: number; // 0-100%
  powerConsumption: number; // in kW
  forces: {
    fx: number; // Lateral X in N
    fy: number; // Lateral Y in N
    fz: number; // Axial Z in N
  };
}

export interface TwinState {
  id: string;
  name: string;
  model: string;
  health: MachineHealth;
  status: 'IDLE' | 'RUNNING' | 'ERROR' | 'MAINTENANCE';
  telemetry: TelemetryData;
  config: {
    material: Material;
    toolGrade: ToolGrade;
  };
  predictions: {
    rul: number; // Remaining Useful Life in hours
    failureProbability: number; // 0-1
    nextMaintenanceDate: string;
    anomalyDetected: boolean;
  };
}

export interface ChartDataPoint {
  time: string;
  value: number;
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Dashboard } from './components/Dashboard';
import { TelemetryData, TwinState, MachineHealth, Material, ToolGrade } from './types';
import { MACHINE_CONFIG } from './constants';

const MATERIALS: Material[] = [
  { id: 'al6061', name: 'Aluminum 6061', hardnessFactor: 0.7, thermalFactor: 1.5 },
  { id: 'st1045', name: 'Steel AISI 1045', hardnessFactor: 1.2, thermalFactor: 0.9 },
  { id: 'ti64', name: 'Titanium Ti-6Al-4V', hardnessFactor: 2.2, thermalFactor: 0.4 },
  { id: 'in718', name: 'Inconel 718', hardnessFactor: 3.5, thermalFactor: 0.2 },
];

const TOOL_GRADES: ToolGrade[] = [
  { id: 'hss', name: 'HSS (Standard)', durabilityFactor: 0.5, heatResistance: 0.6 },
  { id: 'carbide', name: 'Carbide (Micrograin)', durabilityFactor: 2.5, heatResistance: 2.0 },
  { id: 'cobalt', name: 'Cobalt (M42)', durabilityFactor: 1.5, heatResistance: 1.5 },
  { id: 'pcd', name: 'PCD Diamond', durabilityFactor: 5.0, heatResistance: 3.0 },
];

const INITIAL_TELEMETRY: TelemetryData = {
  timestamp: Date.now(),
  rpm: 0,
  feedRate: 0,
  spindleLoad: 0,
  vibration: 0.1,
  temperature: 24,
  toolWear: 5,
  powerConsumption: 0.5,
  forces: { fx: 0, fy: 0, fz: 0 }
};

const INITIAL_STATE: TwinState = {
  id: 'CNC-X1-DR-001',
  name: 'Main CNC Drill - Line A',
  model: 'Acu-Drill Pro 5000',
  health: MachineHealth.HEALTHY,
  status: 'IDLE',
  telemetry: INITIAL_TELEMETRY,
  config: {
    material: MATERIALS[0],
    toolGrade: TOOL_GRADES[1],
  },
  predictions: {
    rul: 425.5,
    failureProbability: 0.02,
    nextMaintenanceDate: '2024-06-15',
    anomalyDetected: false
  }
};

const App: React.FC = () => {
  const [twinState, setTwinState] = useState<TwinState>(INITIAL_STATE);
  const [history, setHistory] = useState<TelemetryData[]>([]);
  const stateRef = useRef<TwinState>(INITIAL_STATE);

  // Simulated IoT Ingestion Loop
  useEffect(() => {
    const interval = setInterval(() => {
      setTwinState(prev => {
        const isRunning = prev.status === 'RUNNING';
        const { material, toolGrade } = prev.config;

        // Simulation modifiers based on material/tool selection
        const loadMod = material.hardnessFactor;
        const heatMod = (material.hardnessFactor / material.thermalFactor) / toolGrade.heatResistance;
        const wearMod = (material.hardnessFactor / toolGrade.durabilityFactor) * (isRunning ? 0.0001 : 0);

        // Simulate machine noise and physics
        const noise = (val: number, range: number) => val + (Math.random() - 0.5) * range;

        // Dynamometer Force Simulation
        // Cycle is 4s. Let's use internal timestamp to simulate the G1/G0 phases for force spikes.
        const cycleSec = (Date.now() / 1000) % 4;
        const isCutting = isRunning && cycleSec > 0.5 && cycleSec < 3.0;

        const baseForce = isCutting ? 150 * loadMod : 0;
        const nextForces = {
          fx: isCutting ? noise(baseForce * 0.1, 10) : noise(0, 1),
          fy: isCutting ? noise(baseForce * 0.1, 10) : noise(0, 1),
          fz: isCutting ? noise(baseForce * 1.5, 40) : noise(0, 2)
        };

        const nextTelemetry: TelemetryData = {
          timestamp: Date.now(),
          rpm: isRunning ? noise(3200, 50) : 0,
          feedRate: isRunning ? noise(450, 20) : 0,
          spindleLoad: isRunning ? noise(45 * loadMod, 10) : 0,
          vibration: isRunning ? noise(1.2 * loadMod, 0.4) : noise(0.05, 0.02),
          temperature: isRunning 
            ? Math.min(120, prev.telemetry.temperature + (0.5 * heatMod)) 
            : Math.max(24, prev.telemetry.temperature - 0.1),
          toolWear: Math.min(100, prev.telemetry.toolWear + wearMod),
          powerConsumption: isRunning ? noise(4.5 * loadMod, 0.8) : 0.2,
          forces: nextForces
        };

        // Health Logic
        let health = MachineHealth.HEALTHY;
        if (nextTelemetry.temperature > MACHINE_CONFIG.SAFE_TEMP_THRESHOLD || nextTelemetry.vibration > MACHINE_CONFIG.SAFE_VIBRATION_THRESHOLD || nextTelemetry.toolWear > 80) {
          health = MachineHealth.WARNING;
        }
        if (nextTelemetry.temperature > 95 || nextTelemetry.vibration > 4.5 || nextTelemetry.toolWear > 95) {
          health = MachineHealth.CRITICAL;
        }

        const newState = {
          ...prev,
          health,
          telemetry: nextTelemetry,
          predictions: {
            ...prev.predictions,
            rul: Math.max(0, prev.predictions.rul - (isRunning ? (0.001 * (1/toolGrade.durabilityFactor) * material.hardnessFactor) : 0)),
            failureProbability: health === MachineHealth.CRITICAL ? 0.85 : (health === MachineHealth.WARNING ? 0.35 : 0.02)
          }
        };

        stateRef.current = newState;
        return newState;
      });

      // Keep 50 points of history for charts
      setHistory(prev => {
        const newHist = [...prev, stateRef.current.telemetry];
        return newHist.slice(-50);
      });
    }, MACHINE_CONFIG.POLLING_INTERVAL_MS);

    return () => clearInterval(interval);
  }, []);

  const toggleMachine = useCallback(() => {
    setTwinState(prev => ({
      ...prev,
      status: prev.status === 'RUNNING' ? 'IDLE' : 'RUNNING'
    }));
  }, []);

  const resetMachine = useCallback(() => {
    setTwinState(prev => ({
      ...prev,
      status: 'IDLE',
      telemetry: { ...prev.telemetry, temperature: 24, toolWear: 0 },
      predictions: { ...prev.predictions, rul: 500, failureProbability: 0 }
    }));
  }, []);

  const setConfig = useCallback((config: { material?: Material, toolGrade?: ToolGrade }) => {
    setTwinState(prev => ({
      ...prev,
      config: {
        ...prev.config,
        ...config
      }
    }));
  }, []);

  return (
    <div className="w-full h-screen bg-[#0f172a] overflow-hidden flex flex-col">
      <header className="px-6 py-4 bg-[#1e293b] border-b border-slate-700 flex justify-between items-center z-50">
        <div className="flex items-center space-x-4">
          <div className="w-10 h-10 bg-blue-600 rounded-lg flex items-center justify-center">
            <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11H5m14 0a2 2 0 012 2v6a2 2 0 01-2 2H5a2 2 0 01-2-2v-6a2 2 0 012-2m14 0V9a2 2 0 00-2-2M5 11V9a2 2 0 012-2m0 0V5a2 2 0 012-2h6a2 2 0 012 2v2M7 7h10" />
            </svg>
          </div>
          <div>
            <h1 className="text-xl font-bold text-white tracking-tight">TwinView Industrial</h1>
            <p className="text-xs text-slate-400 font-medium uppercase tracking-widest">CNC Precision Digital Twin</p>
          </div>
        </div>

        <div className="flex items-center space-x-6">
          <div className="flex flex-col items-end">
            <span className="text-[10px] text-slate-400 font-bold uppercase">System Status</span>
            <div className="flex items-center space-x-2">
              <span className={`w-2 h-2 rounded-full animate-pulse ${twinState.status === 'RUNNING' ? 'bg-green-500' : 'bg-amber-500'}`}></span>
              <span className="text-sm font-semibold text-white">{twinState.status}</span>
            </div>
          </div>
          <div className="h-8 w-[1px] bg-slate-700"></div>
          <div className="flex space-x-3">
             <button 
                onClick={toggleMachine}
                className={`px-4 py-2 rounded font-bold text-sm transition-all ${twinState.status === 'RUNNING' ? 'bg-red-500 hover:bg-red-600 text-white' : 'bg-green-500 hover:bg-green-600 text-white'}`}
              >
                {twinState.status === 'RUNNING' ? 'EMERGENCY STOP' : 'START CYCLE'}
             </button>
             <button 
                onClick={resetMachine}
                className="px-4 py-2 bg-slate-700 hover:bg-slate-600 rounded font-bold text-sm text-white"
              >
                MAINTENANCE RESET
             </button>
          </div>
        </div>
      </header>

      <main className="flex-1 relative overflow-hidden">
        <Dashboard 
          twinState={twinState} 
          history={history} 
          materials={MATERIALS} 
          toolGrades={TOOL_GRADES} 
          onConfigChange={setConfig}
        />
      </main>
    </div>
  );
};

export default App;

export enum MachineHealth {
  HEALTHY = 'HEALTHY',
  WARNING = 'WARNING',
  CRITICAL = 'CRITICAL'
}

export interface Material {
  id: string;
  name: string;
  hardnessFactor: number;
  thermalFactor: number;
}

export interface ToolGrade {
  id: string;
  name: string;
  durabilityFactor: number;
  heatResistance: number;
}

export interface TelemetryData {
  timestamp: number;
  rpm: number;
  feedRate: number;
  spindleLoad: number;
  vibration: number;
  temperature: number;
  toolWear: number;
  powerConsumption: number;
  forces: {
    fx: number;
    fy: number;
    fz: number;
  };
}

export interface TwinState {
  id: string;
  name: string;
  model: string;
  health: MachineHealth;
  status: 'IDLE' | 'RUNNING' | 'ERROR' | 'MAINTENANCE';
  mode: 'SIMULATED' | 'MQTT_LIVE';
  mqttStatus: 'CONNECTED' | 'DISCONNECTED' | 'CONNECTING';
  cloudSync: 'SYNCED' | 'SYNCING' | 'ERROR' | 'OFFLINE';
  telemetry: TelemetryData;
  config: {
    material: Material;
    toolGrade: ToolGrade;
    thingSpeakKey: string;
    mqttBroker: string;
  };
  predictions: {
    rul: number;
    failureProbability: number;
    nextMaintenanceDate: string;
    anomalyDetected: boolean;
  };
}

export interface ChartDataPoint {
  time: string;
  value: number;
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Dashboard } from './components/Dashboard';
import { TelemetryData, TwinState, MachineHealth, Material, ToolGrade } from './types';
import { MACHINE_CONFIG } from './constants';
import mqtt from 'mqtt';

const MATERIALS: Material[] = [
  { id: 'al6061', name: 'Aluminum 6061', hardnessFactor: 0.7, thermalFactor: 1.5 },
  { id: 'st1045', name: 'Steel AISI 1045', hardnessFactor: 1.2, thermalFactor: 0.9 },
  { id: 'ti64', name: 'Titanium Ti-6Al-4V', hardnessFactor: 2.2, thermalFactor: 0.4 },
  { id: 'in718', name: 'Inconel 718', hardnessFactor: 3.5, thermalFactor: 0.2 },
];

const TOOL_GRADES: ToolGrade[] = [
  { id: 'hss', name: 'HSS (Standard)', durabilityFactor: 0.5, heatResistance: 0.6 },
  { id: 'carbide', name: 'Carbide (Micrograin)', durabilityFactor: 2.5, heatResistance: 2.0 },
  { id: 'cobalt', name: 'Cobalt (M42)', durabilityFactor: 1.5, heatResistance: 1.5 },
  { id: 'pcd', name: 'PCD Diamond', durabilityFactor: 5.0, heatResistance: 3.0 },
];

const INITIAL_TELEMETRY: TelemetryData = {
  timestamp: Date.now(),
  rpm: 0,
  feedRate: 0,
  spindleLoad: 0,
  vibration: 0.1,
  temperature: 24,
  toolWear: 5,
  powerConsumption: 0.5,
  forces: { fx: 0, fy: 0, fz: 0 }
};

const INITIAL_STATE: TwinState = {
  id: 'CNC-PRO-G3-001',
  name: 'Smart Factory Alpha - Unit 01',
  model: 'Acu-Drill Pro 5000 Edge',
  health: MachineHealth.HEALTHY,
  status: 'IDLE',
  mode: 'SIMULATED',
  mqttStatus: 'DISCONNECTED',
  cloudSync: 'OFFLINE',
  telemetry: INITIAL_TELEMETRY,
  config: {
    material: MATERIALS[0],
    toolGrade: TOOL_GRADES[1],
    thingSpeakKey: 'YOUR_KEY_HERE',
    mqttBroker: 'wss://broker.emqx.io:8084/mqtt',
  },
  predictions: {
    rul: 425.5,
    failureProbability: 0.02,
    nextMaintenanceDate: '2025-01-20',
    anomalyDetected: false
  }
};

const App: React.FC = () => {
  const [twinState, setTwinState] = useState<TwinState>(INITIAL_STATE);
  const [history, setHistory] = useState<TelemetryData[]>([]);
  const stateRef = useRef<TwinState>(INITIAL_STATE);
  const mqttClientRef = useRef<any>(null);

  // AI Prediction Engine (Simulating an LSTM inference in browser)
  const runAIInference = (currentHistory: TelemetryData[], config: any) => {
    if (currentHistory.length < 10) return stateRef.current.predictions;

    // Simple regression mimicking LSTM trend analysis
    const recentWear = currentHistory.slice(-10).map(h => h.toolWear);
    const recentTemp = currentHistory.slice(-10).map(h => h.temperature);

    const wearTrend = (recentWear[9] - recentWear[0]) / 10;
    const avgTemp = recentTemp.reduce((a, b) => a + b, 0) / 10;

    // RUL Calculation based on wear trend and operating conditions
    const materialImpact = config.material.hardnessFactor;
    const estimatedLife = 500 / (wearTrend > 0 ? wearTrend * 1000 : 0.001);
    const adjustedRul = Math.max(0, estimatedLife * (1 - (avgTemp / 150)));

    return {
      rul: adjustedRul,
      failureProbability: avgTemp > 90 ? 0.9 : avgTemp > 75 ? 0.4 : 0.02,
      nextMaintenanceDate: adjustedRul < 50 ? 'IMMEDIATE' : '2025-02-15',
      anomalyDetected: avgTemp > 110 || wearTrend > 0.5
    };
  };

  // ThingSpeak Cloud Push
  const pushToCloud = async (data: TelemetryData) => {
    if (stateRef.current.config.thingSpeakKey === 'YOUR_KEY_HERE') return;
    try {
      setTwinState(s => ({ ...s, cloudSync: 'SYNCING' }));
      // Simulation of ThingSpeak API call
      // await fetch(`https://api.thingspeak.com/update?api_key=${stateRef.current.config.thingSpeakKey}&field1=${data.rpm}&field2=${data.temperature}`);
      setTwinState(s => ({ ...s, cloudSync: 'SYNCED' }));
    } catch (e) {
      setTwinState(s => ({ ...s, cloudSync: 'ERROR' }));
    }
  };

  // MQTT Client Lifecycle
  useEffect(() => {
    if (twinState.mode === 'MQTT_LIVE') {
      const client = mqtt.connect(twinState.config.mqttBroker);
      mqttClientRef.current = client;

      client.on('connect', () => {
        setTwinState(s => ({ ...s, mqttStatus: 'CONNECTED' }));
        client.subscribe('cnc/telemetry');
      });

      client.on('message', (topic, message) => {
        if (topic === 'cnc/telemetry') {
          const payload = JSON.parse(message.toString());
          // Update state with real MQTT data from ESP32
          setTwinState(s => ({
            ...s,
            telemetry: { ...s.telemetry, ...payload, timestamp: Date.now() }
          }));
        }
      });

      client.on('error', () => setTwinState(s => ({ ...s, mqttStatus: 'DISCONNECTED' })));
      client.on('close', () => setTwinState(s => ({ ...s, mqttStatus: 'DISCONNECTED' })));
    } else {
      if (mqttClientRef.current) {
        mqttClientRef.current.end();
        mqttClientRef.current = null;
      }
      setTwinState(s => ({ ...s, mqttStatus: 'DISCONNECTED' }));
    }

    return () => {
      if (mqttClientRef.current) mqttClientRef.current.end();
    };
  }, [twinState.mode]);

  // Main Simulation & Data Pipeline Loop
  useEffect(() => {
    const interval = setInterval(() => {
      setTwinState(prev => {
        if (prev.mode === 'MQTT_LIVE') return prev; // Live mode handled by MQTT listener

        const isRunning = prev.status === 'RUNNING';
        const { material, toolGrade } = prev.config;
        const loadMod = material.hardnessFactor;
        const heatMod = (material.hardnessFactor / material.thermalFactor) / toolGrade.heatResistance;
        const wearMod = (material.hardnessFactor / toolGrade.durabilityFactor) * (isRunning ? 0.0005 : 0);
        const noise = (val: number, range: number) => val + (Math.random() - 0.5) * range;

        const cycleSec = (Date.now() / 1000) % 4;
        const isCutting = isRunning && cycleSec > 0.5 && cycleSec < 3.0;
        const baseForce = isCutting ? 150 * loadMod : 0;

        const nextTelemetry: TelemetryData = {
          timestamp: Date.now(),
          rpm: isRunning ? noise(3200, 50) : 0,
          feedRate: isRunning ? noise(450, 20) : 0,
          spindleLoad: isRunning ? noise(45 * loadMod, 10) : 0,
          vibration: isRunning ? noise(1.2 * loadMod, 0.4) : noise(0.05, 0.02),
          temperature: isRunning 
            ? Math.min(120, prev.telemetry.temperature + (0.8 * heatMod)) 
            : Math.max(24, prev.telemetry.temperature - 0.3),
          toolWear: Math.min(100, prev.telemetry.toolWear + wearMod),
          powerConsumption: isRunning ? noise(4.5 * loadMod, 0.8) : 0.2,
          forces: {
            fx: isCutting ? noise(baseForce * 0.1, 10) : noise(0, 1),
            fy: isCutting ? noise(baseForce * 0.1, 10) : noise(0, 1),
            fz: isCutting ? noise(baseForce * 1.5, 40) : noise(0, 2)
          }
        };

        let health = MachineHealth.HEALTHY;
        if (nextTelemetry.temperature > 85 || nextTelemetry.vibration > 4.0 || nextTelemetry.toolWear > 85) health = MachineHealth.WARNING;
        if (nextTelemetry.temperature > 105 || nextTelemetry.vibration > 6.0 || nextTelemetry.toolWear > 98) health = MachineHealth.CRITICAL;

        const newState = {
          ...prev,
          health,
          telemetry: nextTelemetry,
          predictions: runAIInference(history, prev.config)
        };

        stateRef.current = newState;
        return newState;
      });

      setHistory(prev => {
        const newHist = [...prev, stateRef.current.telemetry];
        return newHist.slice(-100);
      });

      // Periodically push to cloud (every 5 seconds)
      if (Date.now() % 5000 < 1000) pushToCloud(stateRef.current.telemetry);

    }, MACHINE_CONFIG.POLLING_INTERVAL_MS);

    return () => clearInterval(interval);
  }, [history]);

  const toggleMachine = useCallback(() => {
    setTwinState(prev => ({ ...prev, status: prev.status === 'RUNNING' ? 'IDLE' : 'RUNNING' }));
  }, []);

  const resetMachine = useCallback(() => {
    setTwinState(prev => ({
      ...prev,
      status: 'IDLE',
      telemetry: { ...prev.telemetry, temperature: 24, toolWear: 0 },
      predictions: { ...prev.predictions, rul: 500, failureProbability: 0 }
    }));
  }, []);

  const toggleMode = useCallback(() => {
    setTwinState(prev => ({
      ...prev,
      mode: prev.mode === 'SIMULATED' ? 'MQTT_LIVE' : 'SIMULATED'
    }));
  }, []);

  return (
    <div className="w-full h-screen bg-[#020617] overflow-hidden flex flex-col font-sans">
      <header className="px-6 py-4 bg-slate-900/50 backdrop-blur-xl border-b border-white/5 flex justify-between items-center z-50">
        <div className="flex items-center space-x-4">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13 10V3L4 14h7v7l9-11h-7z" />
            </svg>
          </div>
          <div>
            <h1 className="text-xl font-black text-white tracking-tighter italic">TWIN<span className="text-indigo-400">CORE</span> CNC</h1>
            <div className="flex items-center space-x-2">
               <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Digital Twin v4.2.1</span>
               <span className="w-1 h-1 bg-slate-700 rounded-full"></span>
               <span className="text-[10px] text-indigo-400 font-bold">EDGE-AI ENABLED</span>
            </div>
          </div>
        </div>

        <div className="flex items-center space-x-6">
          <div className="flex space-x-4 bg-black/40 p-1.5 rounded-lg border border-white/5">
            <button 
              onClick={toggleMode}
              className={`px-3 py-1.5 rounded-md text-[10px] font-black tracking-widest uppercase transition-all ${twinState.mode === 'SIMULATED' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-white'}`}
            >
              SIMULATION
            </button>
            <button 
              onClick={toggleMode}
              className={`px-3 py-1.5 rounded-md text-[10px] font-black tracking-widest uppercase transition-all ${twinState.mode === 'MQTT_LIVE' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-500 hover:text-white'}`}
            >
              LIVE MQTT
            </button>
          </div>

          <div className="h-10 w-[1px] bg-white/10"></div>

          <div className="flex space-x-3">
             <button 
                onClick={toggleMachine}
                className={`px-5 py-2 rounded-lg font-black text-[11px] uppercase tracking-wider transition-all shadow-xl ${twinState.status === 'RUNNING' ? 'bg-red-500 hover:bg-red-600 text-white' : 'bg-emerald-500 hover:bg-emerald-600 text-white'}`}
              >
                {twinState.status === 'RUNNING' ? 'STOP PRODUCTION' : 'INITIALIZE CYCLE'}
             </button>
             <button 
                onClick={resetMachine}
                className="px-5 py-2 bg-slate-800 hover:bg-slate-700 rounded-lg font-black text-[11px] uppercase tracking-wider text-white border border-white/5"
              >
                SYSTEM RESET
             </button>
          </div>
        </div>
      </header>

      <main className="flex-1 relative overflow-hidden">
        <Dashboard 
          twinState={twinState} 
          history={history} 
          materials={MATERIALS} 
          toolGrades={TOOL_GRADES} 
          onConfigChange={(cfg) => setTwinState(s => ({ ...s, config: { ...s.config, ...cfg } }))}
        />
      </main>
    </div>
  );
};

export default App;

import React, { useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import { Mesh, Color, Group, Vector3 } from 'three';
import { Text, Float, RoundedBox } from '@react-three/drei';
import { TwinState, MachineHealth } from '../types';
import { COLORS } from '../constants';

interface MachineModelProps {
  twinState: TwinState;
}

export const MachineModel: React.FC<MachineModelProps> = ({ twinState }) => {
  const spindleRef = useRef<Mesh>(null);
  const bitRef = useRef<Mesh>(null);
  const tableXRef = useRef<Group>(null);
  const tableYRef = useRef<Group>(null);
  const cycleTimeRef = useRef(0);
  const alarmRef = useRef<Group>(null);

  const HOME_Y = 1.6;
  const CLEARANCE_Y = 1.3;
  const DEPTH_Y = 0.4;

  useFrame((state, delta) => {
    const isRunning = twinState.status === 'RUNNING';
    const toolWear = twinState.telemetry.toolWear;

    if (isRunning) {
      // 1. Spindle Rotation
      const rotationSpeed = (twinState.telemetry.rpm / 60) * delta * 2 * Math.PI;
      if (spindleRef.current) spindleRef.current.rotation.y += rotationSpeed;
      if (bitRef.current) bitRef.current.rotation.y += rotationSpeed;

      // 2. Realistic Drilling & Table Movement
      const cycleDuration = 4.0;
      cycleTimeRef.current = (cycleTimeRef.current + delta) % cycleDuration;
      const t = cycleTimeRef.current;

      let currentBitY = HOME_Y;
      let currentTableX = 0;
      let currentTableY = 0;

      if (t < 0.5) {
        // Rapid Approach
        currentBitY = HOME_Y - ((t / 0.5) * (HOME_Y - CLEARANCE_Y));
        // Table positioning
        currentTableX = Math.sin(state.clock.elapsedTime * 0.5) * 0.5;
        currentTableY = Math.cos(state.clock.elapsedTime * 0.5) * 0.5;
      } else if (t < 2.5) {
        // Feed Stroke
        const p = (t - 0.5) / 2.0;
        currentBitY = CLEARANCE_Y - (p * (CLEARANCE_Y - DEPTH_Y));
        currentTableX = tableXRef.current?.position.x || 0; // Lock during cutting
        currentTableY = tableYRef.current?.position.z || 0;
      } else if (t < 3.0) {
        // Dwell
        currentBitY = DEPTH_Y;
      } else {
        // Retract
        const p = (t - 3.0) / 1.0;
        currentBitY = DEPTH_Y + (p * (HOME_Y - DEPTH_Y));
      }

      if (bitRef.current) bitRef.current.position.y = currentBitY;
      if (tableXRef.current) tableXRef.current.position.x = currentTableX;
      if (tableYRef.current) tableYRef.current.position.z = currentTableY;
    } else {
      if (bitRef.current) bitRef.current.position.y = HOME_Y;
      cycleTimeRef.current = 0;
    }

    if (alarmRef.current) {
      const isCritical = toolWear > 80 || twinState.health === MachineHealth.CRITICAL;
      alarmRef.current.visible = isCritical && Math.sin(state.clock.elapsedTime * 10) > 0;
    }
  });

  const healthColor = twinState.health === MachineHealth.HEALTHY ? COLORS.HEALTHY : 
                  twinState.health === MachineHealth.WARNING ? COLORS.WARNING : COLORS.CRITICAL;

  return (
    <group>
      {/* Machine Enclosure / Frame */}
      <mesh position={[0, 2.25, -1.8]}>
        <boxGeometry args={[4.2, 4.5, 0.2]} />
        <meshStandardMaterial color="#0f172a" metalness={0.8} roughness={0.2} />
      </mesh>
      <mesh position={[2, 2.25, 0]}>
        <boxGeometry args={[0.2, 4.5, 3.8]} />
        <meshStandardMaterial color="#1e293b" metalness={0.8} transparent opacity={0.3} />
      </mesh>
      <mesh position={[-2, 2.25, 0]}>
        <boxGeometry args={[0.2, 4.5, 3.8]} />
        <meshStandardMaterial color="#1e293b" metalness={0.8} />
      </mesh>

      {/* Main Base */}
      <RoundedBox args={[4, 0.4, 4]} radius={0.05} smoothness={4} position={[0, 0, 0]}>
        <meshStandardMaterial color="#0f172a" metalness={1} roughness={0.1} />
      </RoundedBox>

      {/* Y-Axis Table (Moves Forward/Back) */}
      <group ref={tableYRef}>
        <mesh position={[0, 0.3, 0]}>
          <boxGeometry args={[3.2, 0.2, 3.2]} />
          <meshStandardMaterial color="#334155" metalness={0.8} />
        </mesh>

        {/* X-Axis Table (Moves Left/Right on top of Y) */}
        <group ref={tableXRef} position={[0, 0.2, 0]}>
          {/* Dynamometer Plate */}
          <mesh position={[0, 0.25, 0]}>
            <boxGeometry args={[1.6, 0.1, 1.6]} />
            <meshStandardMaterial color="#475569" metalness={0.9} />
          </mesh>
          {/* Workpiece */}
          <mesh position={[0, 0.5, 0]}>
            <boxGeometry args={[1, 0.4, 1]} />
            <meshStandardMaterial color="#cbd5e1" metalness={0.1} roughness={0.8} />
          </mesh>
        </group>
      </group>

      {/* Z-Axis Column */}
      <mesh position={[-1.2, 2.5, -1]} castShadow>
        <boxGeometry args={[0.8, 5, 0.8]} />
        <meshStandardMaterial color="#1e293b" metalness={0.5} />
      </mesh>

      {/* Z-Axis Head Carriage */}
      <group position={[0, 3.2, -0.6]}>
        <mesh position={[0, 0, 0]}>
          <boxGeometry args={[1.5, 1.2, 1.2]} />
          <meshStandardMaterial color="#334155" metalness={0.8} />
        </mesh>
        {/* Spindle */}
        <mesh ref={spindleRef} position={[0, -0.5, 0.4]}>
          <cylinderGeometry args={[0.4, 0.4, 1.2, 32]} />
          <meshStandardMaterial color={healthColor} metalness={0.9} roughness={0.1} />
        </mesh>
        {/* Bit */}
        <mesh ref={bitRef} position={[0, -1.8, 0.4]}>
          <cylinderGeometry args={[0.04, 0.04, 1, 16]} />
          <meshStandardMaterial color="#fff" metalness={1} />
        </mesh>
      </group>

      {/* Alarms */}
      <group ref={alarmRef} position={[0, 5, 0]}>
         <Text fontSize={0.25} color="#ef4444" font="https://fonts.gstatic.com/s/inter/v12/UcCO3FwrK3iLTeHuS_fvQtMwCp50KnMw2boKoduKmMEVuLyfMZhrib2Bg-4.ttf">
           ! WEAR CRITICAL !
         </Text>
      </group>

      <pointLight position={[0, 4.5, 1]} intensity={1.5} color={healthColor} />
    </group>
  );
};

