                  <div className="flex items-center justify-between text-[10px] text-slate-400">
                    <span className="flex items-center"><Wifi size={10} className="mr-1" /> MQTT Broker</span>
                    <span className={twinState.mqttStatus === 'CONNECTED' ? 'text-emerald-400 font-bold' : 'text-red-400'}>
                      {twinState.mqttStatus}
                    </span>
                  </div>
                  <div className="flex items-center justify-between text-[10px] text-slate-400">
                    <span className="flex items-center"><Cloud size={10} className="mr-1" /> Cloud Sync</span>
                    <span className={twinState.cloudSync === 'SYNCED' ? 'text-indigo-400 font-bold' : 'text-amber-400'}>
                      {twinState.cloudSync}
