import { GoogleGenAI } from "@google/genai";

const wait = (ms: number) => new Promise(res => setTimeout(res, ms));

export async function getIndustrialInsights(machineState: any, retryCount = 0): Promise<string> {
  // Always initialize GoogleGenAI inside the function to ensure the latest API key is used
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const prompt = `Act as a senior Industry 4.0 Reliability Engineer. 
    Analyze the current telemetry of a CNC Drill with the following configuration:
    - Workpiece Material: ${machineState.config.material.name} (Hardness: ${machineState.config.material.hardnessFactor})
    - Tool Grade: ${machineState.config.toolGrade.name}

    Current Telemetry:
    - State: ${JSON.stringify(machineState.telemetry)}
    - Predictive Model RUL: ${machineState.predictions.rul.toFixed(2)} hours
    - Current Health: ${machineState.health}

    Provide a concise (max 3 sentences) expert assessment. 
    Evaluate if the current tool grade is optimal for the material hardness under these temperature and vibration conditions.
    Be technical and data-driven.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.7,
        systemInstruction: "You are an expert industrial automation consultant. Provide strictly technical, data-driven advice regarding machining physics, chip formation, and tool longevity."
      }
    });

    // The text property provides the response string
    return response.text || "Analysis complete. System operating within nominal parameters.";
  } catch (error: any) {
    console.error("Gemini Insight Error:", error);

    // Handle Rate Limiting (429) specifically with exponential backoff
    const isRateLimited = error?.message?.includes('429') || error?.status === 429 || error?.message?.includes('RESOURCE_EXHAUSTED');

    if (isRateLimited && retryCount < 2) {
      const backoff = Math.pow(2, retryCount) * 2000; // 2s, 4s...
      await wait(backoff);
      return getIndustrialInsights(machineState, retryCount + 1);
    }

    if (isRateLimited) {
      return "Rate limit reached for expert diagnostics. Monitoring continues using Edge-AI logic.";
    }

    return "Analysis unavailable. Local predictive models are currently maintaining safety thresholds.";
  }
}

import React, { useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import { Mesh, Color, Group, MeshStandardMaterial } from 'three';
import { Text, Float, RoundedBox } from '@react-three/drei';
import { TwinState, MachineHealth } from '../types';
import { COLORS } from '../constants';

interface MachineModelProps {
  twinState: TwinState;
}

export const MachineModel: React.FC<MachineModelProps> = ({ twinState }) => {
  const spindleRef = useRef<Mesh>(null);
  const bitRef = useRef<Group>(null);
  const bitMaterialRef = useRef<MeshStandardMaterial>(null);
  const tableXRef = useRef<Group>(null);
  const tableYRef = useRef<Group>(null);
  const cycleTimeRef = useRef(0);
  const alarmRef = useRef<Group>(null);
  const hazardLightRef = useRef<any>(null);
  const alarmLampRef = useRef<Mesh>(null);

  // Adjusted Local Y positions for the bit relative to the Z-axis Head (y=3.2)
  const HOME_Y = -1.2;      
  const CLEARANCE_Y = -1.8; 
  const DEPTH_Y = -2.6;     

  useFrame((state, delta) => {
    const isRunning = twinState.status === 'RUNNING';
    const toolWear = twinState.telemetry.toolWear;
    const isCritical = toolWear > 80 || twinState.health === MachineHealth.CRITICAL;

    // 1. Tool Visual Wear Color logic
    if (bitMaterialRef.current) {
      const wearFactor = toolWear / 100;
      // Interpolate from steel silver (#cbd5e1) to hot red (#ef4444)
      const baseColor = new Color("#cbd5e1");
      const warningColor = new Color("#ef4444");
      bitMaterialRef.current.color.lerpColors(baseColor, warningColor, Math.pow(wearFactor, 1.5));

      // Add glowing emissive effect as tool gets hotter/more worn
      if (toolWear > 40) {
        bitMaterialRef.current.emissive.set("#ff0000");
        bitMaterialRef.current.emissiveIntensity = (toolWear - 40) / 60 * 2.5;
      } else {
        bitMaterialRef.current.emissive.set(0, 0, 0);
      }
    }

    if (isRunning) {
      const rotationSpeed = (twinState.telemetry.rpm / 60) * delta * 2 * Math.PI;
      if (spindleRef.current) spindleRef.current.rotation.y -= rotationSpeed;
      if (bitRef.current) bitRef.current.rotation.y -= rotationSpeed;

      const cycleDuration = 4.0;
      cycleTimeRef.current = (cycleTimeRef.current + delta) % cycleDuration;
      const t = cycleTimeRef.current;

      let currentBitY = HOME_Y;
      let currentTableX = 0;
      let currentTableY = 0;

      const lerp = (start: number, end: number, t: number) => start + t * (end - start);
      const easeInOut = (t: number) => t < 0.5 ? 2 * t * t : -1 + (4 - 2 * t) * t;

      if (t < 0.8) {
        const p = easeInOut(t / 0.8);
        currentBitY = lerp(HOME_Y, CLEARANCE_Y, p);
        currentTableX = Math.sin(state.clock.elapsedTime * 0.4) * 0.4;
        currentTableY = Math.cos(state.clock.elapsedTime * 0.4) * 0.4;
      } else if (t < 2.5) {
        const p = (t - 0.8) / 1.7;
        currentBitY = lerp(CLEARANCE_Y, DEPTH_Y, p);
        currentTableX = tableXRef.current?.position.x || 0;
        currentTableY = tableYRef.current?.position.z || 0;
      } else if (t < 3.0) {
        currentBitY = DEPTH_Y;
        currentTableX = tableXRef.current?.position.x || 0;
        currentTableY = tableYRef.current?.position.z || 0;
      } else {
        const p = easeInOut((t - 3.0) / 1.0);
        currentBitY = lerp(DEPTH_Y, HOME_Y, p);
      }

      if (bitRef.current) bitRef.current.position.y = currentBitY;
      if (tableXRef.current) tableXRef.current.position.x = currentTableX;
      if (tableYRef.current) tableYRef.current.position.z = currentTableY;
    } else {
      if (bitRef.current) {
        const targetY = HOME_Y;
        bitRef.current.position.y += (targetY - bitRef.current.position.y) * 0.1;
      }
      cycleTimeRef.current = 0;
    }

    // Blinking Hazard Logic
    const blinkState = Math.sin(state.clock.elapsedTime * 12) > 0;
    const shouldAlarm = isCritical && blinkState;

    if (alarmRef.current) {
      alarmRef.current.visible = shouldAlarm;
    }
    if (hazardLightRef.current) {
      hazardLightRef.current.intensity = shouldAlarm ? 8 : 0;
    }
    if (alarmLampRef.current) {
      const mat = alarmLampRef.current.material as MeshStandardMaterial;
      mat.emissiveIntensity = shouldAlarm ? 4 : 0;
      mat.color.set(shouldAlarm ? "#ff0000" : "#330000");
    }
  });

  const healthColor = twinState.health === MachineHealth.HEALTHY ? COLORS.HEALTHY : 
                  twinState.health === MachineHealth.WARNING ? COLORS.WARNING : COLORS.CRITICAL;

  return (
    <group>
      {/* Machine Enclosure */}
      <mesh position={[0, 2.25, -1.8]}>
        <boxGeometry args={[4.2, 4.5, 0.2]} />
        <meshStandardMaterial color="#0f172a" metalness={0.8} roughness={0.2} />
      </mesh>

      {/* Sides */}
      <mesh position={[2, 2.25, 0]}>
        <boxGeometry args={[0.2, 4.5, 3.8]} />
        <meshStandardMaterial color="#1e293b" metalness={0.5} transparent opacity={0.2} />
      </mesh>
      <mesh position={[-2, 2.25, 0]}>
        <boxGeometry args={[0.2, 4.5, 3.8]} />
        <meshStandardMaterial color="#1e293b" metalness={0.8} />
      </mesh>

      {/* Base */}
      <RoundedBox args={[4, 0.4, 4]} radius={0.05} smoothness={4} position={[0, 0, 0]}>
        <meshStandardMaterial color="#0f172a" metalness={1} roughness={0.1} />
      </RoundedBox>

      {/* Y-Axis Table */}
      <group ref={tableYRef}>
        <mesh position={[0, 0.3, 0]}>
          <boxGeometry args={[3.2, 0.2, 3.2]} />
          <meshStandardMaterial color="#334155" metalness={0.8} />
        </mesh>
        <group ref={tableXRef} position={[0, 0.2, 0]}>
          <mesh position={[0, 0.25, 0]}>
            <boxGeometry args={[1.6, 0.15, 1.6]} />
            <meshStandardMaterial color="#475569" metalness={0.9} roughness={0.05} />
          </mesh>
          <mesh position={[0, 0.5, 0]} castShadow>
            <boxGeometry args={[1, 0.4, 1]} />
            <meshStandardMaterial color="#94a3b8" metalness={0.2} roughness={0.7} />
          </mesh>
        </group>
      </group>

      {/* Z-Column */}
      <mesh position={[-1.2, 2.5, -1]} castShadow>
        <boxGeometry args={[0.8, 5, 0.8]} />
        <meshStandardMaterial color="#1e293b" metalness={0.5} />
      </mesh>

      {/* Head Carriage */}
      <group position={[0, 3.2, -0.6]}>
        <mesh position={[0, 0, 0]} castShadow>
          <boxGeometry args={[1.5, 1.2, 1.2]} />
          <meshStandardMaterial color="#334155" metalness={0.8} />
        </mesh>

        {/* Alarm Lamp (Physical indication) */}
        <mesh ref={alarmLampRef} position={[0, 0.65, 0]} castShadow>
          <cylinderGeometry args={[0.15, 0.15, 0.2, 16]} />
          <meshStandardMaterial color="#330000" emissive="#ff0000" emissiveIntensity={0} />
        </mesh>

        {/* Physical Hazard Warning Light */}
        <pointLight ref={hazardLightRef} position={[0, -0.2, 0.8]} color="#ff0000" intensity={0} distance={4} />

        <mesh ref={spindleRef} position={[0, -0.5, 0.4]} castShadow>
          <cylinderGeometry args={[0.3, 0.35, 1, 32]} />
          <meshStandardMaterial color={healthColor} metalness={0.9} roughness={0.1} />
        </mesh>

        <group ref={bitRef} position={[0, HOME_Y, 0.4]}>
          <mesh position={[0, 0.4, 0]}>
            <cylinderGeometry args={[0.15, 0.1, 0.3, 16]} />
            <meshStandardMaterial color="#475569" metalness={1} />
          </mesh>
          <mesh position={[0, -0.2, 0]} castShadow>
            <cylinderGeometry args={[0.04, 0.04, 0.8, 16]} />
            <meshStandardMaterial ref={bitMaterialRef} color="#cbd5e1" metalness={1} roughness={0} />
          </mesh>
        </group>
      </group>

      {/* Visual Alarm HUD */}
      <group ref={alarmRef} position={[0, 4.8, 0]}>
         <Float speed={10} rotationIntensity={0} floatIntensity={0.2}>
           <Text 
             fontSize={0.25} 
             color="#ff0000" 
             anchorX="center" 
             anchorY="middle"
             outlineWidth={0.015}
             outlineColor="#000000"
             font="https://fonts.gstatic.com/s/inter/v12/UcCO3FwrK3iLTeHuS_fvQtMwCp50KnMw2boKoduKmMEVuLyeMZhrib2Bg-4.ttf"
           >
             ⚠ TOOL GOT WEARED ⚠
           </Text>
         </Float>
      </group>

      <pointLight position={[0, 4.2, 1]} intensity={2.5} distance={10} color={healthColor} />
      <spotLight position={[0, 5, 2]} angle={0.5} intensity={1} color="#ffffff" castShadow />
    </group>
  );
};

