import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Dashboard } from './components/Dashboard';
import { TelemetryData, TwinState, MachineHealth, Material, ToolGrade } from './types';
import { MACHINE_CONFIG } from './constants';
import * as mqtt from 'mqtt';
import { Wifi, Shield, Globe, Cpu, ChevronUp, Link, Settings } from 'lucide-react';

const MATERIALS: Material[] = [
  { id: 'al6061', name: 'Aluminum 6061', hardnessFactor: 0.7, thermalFactor: 1.5 },
  { id: 'st1045', name: 'Steel AISI 1045', hardnessFactor: 1.2, thermalFactor: 0.9 },
  { id: 'ti64', name: 'Titanium Ti-6Al-4V', hardnessFactor: 2.2, thermalFactor: 0.4 },
  { id: 'in718', name: 'Inconel 718', hardnessFactor: 3.5, thermalFactor: 0.2 },
];

const TOOL_GRADES: ToolGrade[] = [
  { id: 'hss', name: 'HSS (Standard)', durabilityFactor: 0.5, heatResistance: 0.6 },
  { id: 'carbide', name: 'Carbide (Micrograin)', durabilityFactor: 2.5, heatResistance: 2.0 },
  { id: 'cobalt', name: 'Cobalt (M42)', durabilityFactor: 1.5, heatResistance: 1.5 },
  { id: 'pcd', name: 'PCD Diamond', durabilityFactor: 5.0, heatResistance: 3.0 },
];

const INITIAL_TELEMETRY: TelemetryData = {
  timestamp: Date.now(),
  rpm: 0,
  feedRate: 0,
  spindleLoad: 0,
  vibration: 0.1,
  temperature: 24,
  toolWear: 5,
  powerConsumption: 0.5,
  forces: { fx: 0, fy: 0, fz: 0 }
};

const INITIAL_STATE: TwinState = {
  id: 'CNC-PRO-G3-001',
  name: 'Smart Factory Alpha - Unit 01',
  model: 'Acu-Drill Pro 5000 Edge',
  health: MachineHealth.HEALTHY,
  status: 'IDLE',
  mode: 'SIMULATED',
  mqttStatus: 'DISCONNECTED',
  cloudSync: 'OFFLINE',
  lastCommandSent: null,
  telemetry: INITIAL_TELEMETRY,
  materialTest: {
    isActive: false,
    durationSeconds: 30,
    targetWear: 95,
    startTime: null
  },
  config: {
    material: MATERIALS[0],
    toolGrade: TOOL_GRADES[1],
    thingSpeakKey: 'YOUR_KEY_HERE',
    mqttBroker: 'wss://broker.emqx.io:8084/mqtt',
    telemetryTopic: 'cnc/telemetry',
    commandTopic: 'cnc/control',
    wifiSsid: '',
    wifiPassword: '',
    espIp: '192.168.1.100',
    espPort: '80'
  },
  predictions: {
    rul: 425.5,
    failureProbability: 0.02,
    nextMaintenanceDate: '2025-01-20',
    anomalyDetected: false
  }
};

const App: React.FC = () => {
  const [twinState, setTwinState] = useState<TwinState>(INITIAL_STATE);
  const [history, setHistory] = useState<TelemetryData[]>([]);
  const [showWifiConfig, setShowWifiConfig] = useState(false);
  const stateRef = useRef<TwinState>(INITIAL_STATE);
  const mqttClientRef = useRef<any>(null);

  const runAIInference = (currentHistory: TelemetryData[], config: any) => {
    if (currentHistory.length < 10) return stateRef.current.predictions;
    const recentWear = currentHistory.slice(-10).map(h => h.toolWear || 0);
    const recentTemp = currentHistory.slice(-10).map(h => h.temperature || 24);
    const wearTrend = (recentWear[recentWear.length - 1] - recentWear[0]) / 10;
    const avgTemp = recentTemp.reduce((a, b) => a + b, 0) / 10;
    const estimatedLife = 500 / (wearTrend > 0 ? wearTrend * 1000 : 0.001);
    const adjustedRul = Math.max(0, estimatedLife * (1 - (avgTemp / 150)));
    return {
      rul: adjustedRul,
      failureProbability: avgTemp > 90 ? 0.9 : avgTemp > 75 ? 0.4 : 0.02,
      nextMaintenanceDate: adjustedRul < 50 ? 'IMMEDIATE' : '2025-02-15',
      anomalyDetected: avgTemp > 110 || wearTrend > 0.5
    };
  };

  const sendWifiCommand = useCallback(async (action: string, value?: string) => {
    const { espIp, espPort } = stateRef.current.config;
    const url = `http://${espIp}:${espPort}/control?action=${action}${value ? `&value=${value}` : ''}`;

    try {
      setTwinState(s => ({ ...s, lastCommandSent: `UPLINK [HTTP]: ${action}${value ? `=${value}` : ''}` }));
      await fetch(url, { mode: 'no-cors' }); 
    } catch (error) {
      console.error('WiFi Uplink Error:', error);
      setTwinState(s => ({ ...s, lastCommandSent: 'UPLINK ERROR: TARGET UNREACHABLE' }));
    }
  }, []);

  const publishMqttCommand = useCallback((cmd: object) => {
    if (mqttClientRef.current && stateRef.current.mqttStatus === 'CONNECTED') {
      const payload = JSON.stringify({ ...cmd, timestamp: Date.now() });
      mqttClientRef.current.publish(stateRef.current.config.commandTopic, payload);
      setTwinState(s => ({ ...s, lastCommandSent: `UPLINK [MQTT]: ${payload}` }));
    }
  }, []);

  useEffect(() => {
    if (twinState.mode === 'MQTT_LIVE') {
      try {
        const client = mqtt.connect(twinState.config.mqttBroker);
        mqttClientRef.current = client;

        client.on('connect', () => {
          setTwinState(s => ({ ...s, mqttStatus: 'CONNECTED' }));
          client.subscribe(stateRef.current.config.telemetryTopic);
        });

        client.on('message', (topic, message) => {
          if (topic === stateRef.current.config.telemetryTopic) {
            try {
              const payload = JSON.parse(message.toString());
              setTwinState(s => ({
                ...s,
                status: payload.status || s.status,
                telemetry: { ...s.telemetry, ...payload, timestamp: Date.now() }
              }));
            } catch (e) {
              console.error("MQTT Parse Error", e);
            }
          }
        });

        client.on('error', () => setTwinState(s => ({ ...s, mqttStatus: 'DISCONNECTED' })));
        client.on('close', () => setTwinState(s => ({ ...s, mqttStatus: 'DISCONNECTED' })));
      } catch (e) {
        console.error("MQTT Client Init Error", e);
      }
    } else {
      if (mqttClientRef.current) {
        mqttClientRef.current.end();
        mqttClientRef.current = null;
      }
      setTwinState(s => ({ ...s, mqttStatus: 'DISCONNECTED' }));
    }

    return () => {
      if (mqttClientRef.current) mqttClientRef.current.end();
    };
  }, [twinState.mode, twinState.config.mqttBroker, twinState.config.telemetryTopic]);

  useEffect(() => {
    const interval = setInterval(() => {
      setTwinState(prev => {
        if (prev.mode !== 'SIMULATED') return prev; 

        if (prev.materialTest.isActive) {
          const now = Date.now();
          const elapsed = (now - (prev.materialTest.startTime || now)) / 1000;
          const isDurationReached = elapsed >= prev.materialTest.durationSeconds;
          const isWearReached = prev.telemetry.toolWear >= prev.materialTest.targetWear;

          if (isDurationReached || isWearReached) {
            return {
              ...prev,
              status: 'IDLE',
              materialTest: { ...prev.materialTest, isActive: false, startTime: null }
            };
          }
        }

        const isRunning = prev.status === 'RUNNING';
        const { material, toolGrade } = prev.config;
        const loadMod = material.hardnessFactor || 1;
        const heatMod = ((material.hardnessFactor || 1) / (material.thermalFactor || 1)) / (toolGrade.heatResistance || 1);
        const wearMod = ((material.hardnessFactor || 1) / (toolGrade.durabilityFactor || 1)) * (isRunning ? 0.0005 : 0);
        const noise = (val: number, range: number) => val + (Math.random() - 0.5) * range;
        const cycleSec = (Date.now() / 1000) % 4;
        const isCutting = isRunning && cycleSec > 0.5 && cycleSec < 3.0;
        const baseForce = isCutting ? 150 * loadMod : 0;

        const nextTelemetry: TelemetryData = {
          timestamp: Date.now(),
          rpm: isRunning ? noise(3200, 50) : 0,
          feedRate: isRunning ? noise(450, 20) : 0,
          spindleLoad: isRunning ? noise(45 * loadMod, 10) : 0,
          vibration: isRunning ? noise(1.2 * loadMod, 0.4) : noise(0.05, 0.02),
          temperature: isRunning 
            ? Math.min(120, prev.telemetry.temperature + (0.8 * heatMod)) 
            : Math.max(24, prev.telemetry.temperature - 0.3),
          toolWear: Math.min(100, prev.telemetry.toolWear + wearMod),
          powerConsumption: isRunning ? noise(4.5 * loadMod, 0.8) : 0.2,
          forces: {
            fx: isCutting ? noise(baseForce * 0.1, 10) : noise(0, 1),
            fy: isCutting ? noise(baseForce * 0.1, 10) : noise(0, 1),
            fz: isCutting ? noise(baseForce * 1.5, 40) : noise(0, 2)
          }
        };

        let health = MachineHealth.HEALTHY;
        if (nextTelemetry.temperature > 85 || nextTelemetry.vibration > 4.0 || nextTelemetry.toolWear > 85) health = MachineHealth.WARNING;
        if (nextTelemetry.temperature > 105 || nextTelemetry.vibration > 6.0 || nextTelemetry.toolWear > 98) health = MachineHealth.CRITICAL;

        const newState = {
          ...prev,
          health,
          telemetry: nextTelemetry,
          predictions: runAIInference(history, prev.config)
        };
        stateRef.current = newState;
        return newState;
      });

      setHistory(prev => {
        const newHist = [...prev, stateRef.current.telemetry];
        return newHist.slice(-100);
      });
    }, MACHINE_CONFIG.POLLING_INTERVAL_MS);

    return () => clearInterval(interval);
  }, [history]);

  const toggleMachine = useCallback(() => {
    const nextStatus = twinState.status === 'RUNNING' ? 'IDLE' : 'RUNNING';
    if (twinState.mode === 'WIFI_LIVE') {
      sendWifiCommand('SET_STATUS', nextStatus);
    } else if (twinState.mode === 'MQTT_LIVE') {
      publishMqttCommand({ action: 'SET_STATUS', value: nextStatus });
    } else {
      setTwinState(prev => ({ ...prev, status: nextStatus }));
    }
  }, [twinState.status, twinState.mode, publishMqttCommand, sendWifiCommand]);

  const resetMachine = useCallback(() => {
    if (twinState.mode === 'WIFI_LIVE') {
      sendWifiCommand('RESET_SYSTEM');
    } else if (twinState.mode === 'MQTT_LIVE') {
      publishMqttCommand({ action: 'RESET_SYSTEM' });
    } else {
      setTwinState(prev => ({
        ...prev,
        status: 'IDLE',
        telemetry: { ...prev.telemetry, temperature: 24, toolWear: 0 },
        materialTest: { ...prev.materialTest, isActive: false, startTime: null },
        predictions: { ...prev.predictions, rul: 500, failureProbability: 0 }
      }));
    }
  }, [twinState.mode, publishMqttCommand, sendWifiCommand]);

  const setMode = (mode: 'SIMULATED' | 'MQTT_LIVE' | 'WIFI_LIVE') => {
    setTwinState(prev => ({ ...prev, mode }));
  };

  const startMaterialTest = useCallback(() => {
    setTwinState(prev => ({
      ...prev,
      status: 'RUNNING',
      materialTest: { ...prev.materialTest, isActive: true, startTime: Date.now() }
    }));
  }, []);

  const isWifiReady = twinState.config.espIp && twinState.config.espPort;

  return (
    <div className="w-full h-screen bg-[#020617] overflow-hidden flex flex-col font-sans">
      <header className="px-6 py-4 bg-slate-900/50 backdrop-blur-xl border-b border-white/5 flex justify-between items-center z-50">
        <div className="flex items-center space-x-4">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <Wifi className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-xl font-black text-white tracking-tighter italic uppercase">Twin<span className="text-indigo-400">Core</span></h1>
            <div className="flex items-center space-x-2">
               <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Digital Twin v4.8.2</span>
               {twinState.mode === 'WIFI_LIVE' && isWifiReady && (
                 <span className="text-[10px] text-emerald-400 font-black flex items-center animate-pulse">
                   <div className="w-1.5 h-1.5 bg-emerald-400 rounded-full mr-1.5"></div>
                   WIFI-CONTROL READY
                 </span>
               )}
            </div>
          </div>
        </div>

        <div className="flex items-center space-x-4">
          <div className="flex bg-black/40 p-1 rounded-lg border border-white/5">
            {[
              { id: 'SIMULATED', label: 'SIM' },
              { id: 'MQTT_LIVE', label: 'MQTT' },
              { id: 'WIFI_LIVE', label: 'WIFI' }
            ].map(m => (
              <button 
                key={m.id}
                onClick={() => setMode(m.id as any)}
                className={`px-4 py-1.5 rounded-md text-[10px] font-black tracking-widest uppercase transition-all ${twinState.mode === m.id ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-white'}`}
              >
                {m.label}
              </button>
            ))}
          </div>

          <button 
            onClick={() => setShowWifiConfig(!showWifiConfig)}
            className={`p-2 rounded-lg border transition-all ${showWifiConfig ? 'bg-indigo-600 text-white border-indigo-400' : 'bg-slate-800 text-slate-400 border-white/5 hover:text-white'}`}
            title="WIFI Provisioning"
          >
            {showWifiConfig ? <ChevronUp size={18} /> : <Settings size={18} />}
          </button>

          <div className="h-8 w-[1px] bg-white/10 mx-2"></div>

          <div className="flex space-x-2">
             <button 
                onClick={toggleMachine}
                disabled={twinState.materialTest.isActive}
                className={`px-6 py-2 rounded-lg font-black text-[11px] uppercase tracking-wider transition-all ${twinState.status === 'RUNNING' ? 'bg-red-500 hover:bg-red-600 shadow-red-500/20 shadow-xl' : 'bg-emerald-500 hover:bg-emerald-600 shadow-emerald-500/20 shadow-xl'} text-white disabled:opacity-50`}
              >
                {twinState.status === 'RUNNING' ? 'STOP' : 'INITIALIZE'}
             </button>
             <button 
                onClick={resetMachine}
                className="px-6 py-2 bg-slate-800 hover:bg-slate-700 rounded-lg font-black text-[11px] uppercase tracking-wider text-white border border-white/5"
              >
                RESET
             </button>
          </div>
        </div>
      </header>

      {showWifiConfig && (
        <div className="bg-slate-900 border-b border-indigo-500/30 p-6 z-40 animate-in slide-in-from-top duration-300">
          <div className="max-w-7xl mx-auto flex items-start justify-between">
            <div className="flex-1 grid grid-cols-4 gap-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-indigo-400 uppercase flex items-center"><Wifi size={12} className="mr-1.5"/> ESP32 SSID</label>
                <input 
                  type="text" 
                  value={twinState.config.wifiSsid}
                  onChange={(e) => setTwinState(s => ({ ...s, config: { ...s.config, wifiSsid: e.target.value }}))}
                  placeholder="Network SSID"
                  className="w-full bg-black/40 border border-white/10 rounded-lg px-4 py-2 text-xs text-white outline-none focus:border-indigo-500/50"
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-indigo-400 uppercase flex items-center"><Shield size={12} className="mr-1.5"/> WPA2 PASSWORD</label>
                <input 
                  type="password" 
                  value={twinState.config.wifiPassword}
                  onChange={(e) => setTwinState(s => ({ ...s, config: { ...s.config, wifiPassword: e.target.value }}))}
                  placeholder="••••••••"
                  className="w-full bg-black/40 border border-white/10 rounded-lg px-4 py-2 text-xs text-white outline-none focus:border-indigo-400/50"
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-emerald-400 uppercase flex items-center"><Globe size={12} className="mr-1.5"/> ESP32 IP ADDRESS</label>
                <input 
                  type="text" 
                  value={twinState.config.espIp}
                  onChange={(e) => setTwinState(s => ({ ...s, config: { ...s.config, espIp: e.target.value }}))}
                  className="w-full bg-black/40 border border-white/10 rounded-lg px-4 py-2 text-xs font-mono text-emerald-400 outline-none focus:border-emerald-500/50"
                  placeholder="192.168.1.xxx"
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-500 uppercase flex items-center"><Cpu size={12} className="mr-1.5"/> CONTROLLER PORT</label>
                <input 
                  type="text" 
                  value={twinState.config.espPort}
                  onChange={(e) => setTwinState(s => ({ ...s, config: { ...s.config, espPort: e.target.value }}))}
                  className="w-full bg-black/40 border border-white/10 rounded-lg px-4 py-2 text-xs font-mono text-white outline-none focus:border-indigo-500/50"
                />
              </div>
            </div>
            <div className="ml-8 border-l border-white/10 pl-8 flex flex-col justify-center">
               <h4 className="text-[10px] font-black text-slate-400 uppercase mb-2">Connectivity Status</h4>
               <div className={`px-4 py-2 rounded-xl text-[10px] font-black flex items-center transition-all ${isWifiReady ? 'bg-emerald-500/20 text-emerald-400 border border-emerald-500/30' : 'bg-slate-800 text-slate-500 border border-white/5'}`}>
                   {isWifiReady ? (
                     <><Link size={12} className="mr-2"/> WIFI-CONTROL READY</>
                   ) : (
                     'CONFIGURATION INCOMPLETE'
                   )}
               </div>
            </div>
          </div>
        </div>
      )}

      <main className="flex-1 relative overflow-hidden">
        <Dashboard 
          twinState={twinState} 
          history={history} 
          materials={MATERIALS} 
          toolGrades={TOOL_GRADES} 
          onConfigChange={(cfg) => setTwinState(s => ({ ...s, config: { ...s.config, ...cfg }, materialTest: { ...s.materialTest, ...cfg.materialTest } }))}
          onStartTest={startMaterialTest}
        />
      </main>
    </div>
  );
};

