    { label: 'Force Axial (Fz)', value: `${Math.round(twinState.telemetry.forces.fz)} N`, icon: Gauge, color: 'text-emerald-400' },
    { label: 'Vibration', value: `${twinState.telemetry.vibration.toFixed(2)} G`, icon: Zap, color: 'text-amber-400' },
