import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Dashboard } from './components/Dashboard';
import { TelemetryData, TwinState, MachineHealth, Material, ToolGrade } from './types';
import { MACHINE_CONFIG } from './constants';
import mqtt from 'mqtt';
import { Wifi, Shield, Globe, Cpu, ChevronUp, Link, Settings, AlertCircle, Bell, X } from 'lucide-react';

const MATERIALS: Material[] = [
  { id: 'al6061', name: 'Aluminum 6061', hardnessFactor: 0.7, thermalFactor: 1.5 },
  { id: 'st1045', name: 'Steel AISI 1045', hardnessFactor: 1.2, thermalFactor: 0.9 },
  { id: 'ti64', name: 'Titanium Ti-6Al-4V', hardnessFactor: 2.2, thermalFactor: 0.4 },
  { id: 'in718', name: 'Inconel 718', hardnessFactor: 3.5, thermalFactor: 0.2 },
];

const TOOL_GRADES: ToolGrade[] = [
  { id: 'hss', name: 'HSS (Standard)', durabilityFactor: 0.5, heatResistance: 0.6 },
  { id: 'carbide', name: 'Carbide (Micrograin)', durabilityFactor: 2.5, heatResistance: 2.0 },
  { id: 'cobalt', name: 'Cobalt (M42)', durabilityFactor: 1.5, heatResistance: 1.5 },
  { id: 'pcd', name: 'PCD Diamond', durabilityFactor: 5.0, heatResistance: 3.0 },
];

const INITIAL_TELEMETRY: TelemetryData = {
  timestamp: Date.now(),
  rpm: 0,
  feedRate: 0,
  spindleLoad: 0,
  vibration: 0.1,
  temperature: 24,
  toolWear: 5,
  powerConsumption: 0.5,
  forces: { fx: 0, fy: 0, fz: 0 }
};

const INITIAL_STATE: TwinState = {
  id: 'CNC-PRO-G3-001',
  name: 'Smart Factory Alpha - Unit 01',
  model: 'Acu-Drill Pro 5000 Edge',
  health: MachineHealth.HEALTHY,
  status: 'IDLE',
  mode: 'SIMULATED',
  mqttStatus: 'DISCONNECTED',
  cloudSync: 'OFFLINE',
  lastCommandSent: null,
  telemetry: INITIAL_TELEMETRY,
  materialTest: {
    isActive: false,
    durationSeconds: 30,
    targetWear: 95,
    startTime: null,
    scenario: 'NORMAL'
  },
  config: {
    material: MATERIALS[0],
    toolGrade: TOOL_GRADES[1],
    thingSpeakKey: 'YOUR_KEY_HERE',
    mqttBroker: 'wss://broker.emqx.io:8084/mqtt',
    telemetryTopic: 'cnc/telemetry',
    commandTopic: 'cnc/control',
    wifiSsid: '',
    wifiPassword: '',
    espIp: '192.168.1.100',
    espPort: '80'
  },
  predictions: {
    rul: 425.5,
    failureProbability: 0.02,
    nextMaintenanceDate: '2025-01-20',
    anomalyDetected: false
  }
};

const App: React.FC = () => {
  const [twinState, setTwinState] = useState<TwinState>(INITIAL_STATE);
  const [history, setHistory] = useState<TelemetryData[]>([]);
  const [activeAlarm, setActiveAlarm] = useState<{ type: string; message: string } | null>(null);
  const stateRef = useRef<TwinState>(INITIAL_STATE);
  const mqttClientRef = useRef<any>(null);

  // Request notification permissions on mount
  useEffect(() => {
    if ("Notification" in window) {
      Notification.requestPermission();
    }
  }, []);

  const handleConfigChange = useCallback((cfg: any) => {
    setTwinState(s => {
      const newState = { ...s };

      // Correctly route materialTest updates at the top level
      if (cfg.materialTest) {
        newState.materialTest = { ...s.materialTest, ...cfg.materialTest };
      }

      // Update nested configuration properties
      if (cfg.material || cfg.toolGrade || cfg.thingSpeakKey || cfg.mqttBroker || 
          cfg.telemetryTopic || cfg.commandTopic || cfg.wifiSsid || cfg.wifiPassword || 
          cfg.espIp || cfg.espPort) {
        newState.config = { ...s.config, ...cfg };
      }

      stateRef.current = newState;
      return newState;
    });
  }, []);

  const runAIInference = (currentHistory: TelemetryData[]) => {
    if (currentHistory.length < 5) return stateRef.current.predictions;
    const recentWear = currentHistory.slice(-10).map(h => h.toolWear || 0);
    const recentTemp = currentHistory.slice(-10).map(h => h.temperature || 24);
    const wearTrend = (recentWear[recentWear.length - 1] - (recentWear[0] || 0)) / 10;
    const avgTemp = recentTemp.reduce((a, b) => a + b, 0) / recentTemp.length;
    const estimatedLife = 500 / (wearTrend > 0 ? wearTrend * 1000 : 0.001);
    const adjustedRul = Math.max(0, estimatedLife * (1 - (avgTemp / 200)));
    return {
      rul: adjustedRul,
      failureProbability: avgTemp > 95 ? 0.95 : avgTemp > 80 ? 0.45 : 0.02,
      nextMaintenanceDate: adjustedRul < 50 ? 'IMMEDIATE' : '2025-02-15',
      anomalyDetected: avgTemp > 110 || wearTrend > 0.5
    };
  };

  const sendHardwareCommand = useCallback(async (action: string, value?: string) => {
    const { espIp, espPort } = stateRef.current.config;
    if (!espIp) return;

    const url = `http://${espIp}:${espPort}/control?action=${action}${value ? `&value=${value}` : ''}`;
    try {
      setTwinState(s => ({ ...s, lastCommandSent: `UPLINK [FETCH]: ${action}${value ? `=${value}` : ''}` }));
      await fetch(url, { mode: 'no-cors' }); 
    } catch (error) {
      setTwinState(s => ({ ...s, lastCommandSent: 'UPLINK ERROR: TARGET UNREACHABLE' }));
    }
  }, []);

  const handleStartTest = useCallback(() => {
    setTwinState(prev => ({
      ...prev,
      status: 'RUNNING',
      materialTest: {
        ...prev.materialTest,
        isActive: true,
        startTime: Date.now()
      }
    }));
    setActiveAlarm(null);
  }, []);

  useEffect(() => {
    if (twinState.mode === 'MQTT_LIVE') {
      try {
        const client = mqtt.connect(twinState.config.mqttBroker);
        mqttClientRef.current = client;
        client.on('connect', () => {
          setTwinState(s => ({ ...s, mqttStatus: 'CONNECTED' }));
          client.subscribe(stateRef.current.config.telemetryTopic);
        });
        client.on('message', (topic, message) => {
          if (topic === stateRef.current.config.telemetryTopic) {
            try {
              const payload = JSON.parse(message.toString());
              setTwinState(s => ({
                ...s,
                status: payload.status || s.status,
                telemetry: { ...s.telemetry, ...payload, timestamp: Date.now() }
              }));
            } catch (e) {}
          }
        });
        client.on('error', () => setTwinState(s => ({ ...s, mqttStatus: 'DISCONNECTED' })));
        client.on('close', () => setTwinState(s => ({ ...s, mqttStatus: 'DISCONNECTED' })));
      } catch (e) {}
    } else {
      if (mqttClientRef.current) {
        mqttClientRef.current.end();
        mqttClientRef.current = null;
      }
      setTwinState(s => ({ ...s, mqttStatus: 'DISCONNECTED' }));
    }
    return () => { if (mqttClientRef.current) mqttClientRef.current.end(); };
  }, [twinState.mode, twinState.config.mqttBroker]);

  useEffect(() => {
    const interval = setInterval(() => {
      setTwinState(prev => {
        if (prev.mode !== 'SIMULATED') return prev; 

        let isRunning = prev.status === 'RUNNING';
        let currentStatus = prev.status;
        let testActive = prev.materialTest.isActive;
        let startTime = prev.materialTest.startTime;
        const scenario = prev.materialTest.scenario || 'NORMAL';
        const targetWear = prev.materialTest.targetWear;

        // 1. Universal Safety Check: Tool wear limit breach (Independent of Test Mode)
        if (isRunning && prev.telemetry.toolWear >= targetWear) {
          isRunning = false;
          currentStatus = 'IDLE';
          testActive = false;

          if (!activeAlarm) {
            const scenarioInfo = testActive && scenario !== 'NORMAL' ? ` during ${scenario} scenario` : '';
            const alarmMsg = `SAFETY SHUTDOWN: Tool wear exceeded user-defined limit of ${targetWear}%${scenarioInfo}. Urgent inspection required.`;

            setActiveAlarm({ type: 'CRITICAL', message: alarmMsg });

            // Trigger OS Notification
            if (Notification.permission === "granted") {
              new Notification("CNC CRITICAL ALARM", {
                body: alarmMsg,
                icon: "https://cdn-icons-png.flaticon.com/512/595/595067.png",
                silent: false,
                requireInteraction: true
              });
            }
          }
        }

        // 2. Test Run Lifecycle: Success case (Duration complete)
        if (testActive && startTime && isRunning) {
          const elapsed = (Date.now() - startTime) / 1000;
          if (elapsed >= prev.materialTest.durationSeconds) {
            testActive = false;
            currentStatus = 'IDLE';
            isRunning = false;
          }
        }

        const { material, toolGrade } = prev.config;
        const loadMod = material.hardnessFactor || 1;

        let wearMultiplier = testActive ? 8 : 1; 
        let heatMultiplier = 1;
        let forceMultiplier = 1;

        if (testActive) {
          switch(scenario) {
            case 'AGGRESSIVE': 
              wearMultiplier *= 3.0; 
              forceMultiplier = 2.2;
              break;
            case 'THERMAL': 
              heatMultiplier = 3.5; 
              wearMultiplier *= 1.5;
              break;
            case 'IMPACT':
              wearMultiplier *= 6.0;
              forceMultiplier = 3.5;
              break;
          }
        }

        const heatMod = ((loadMod / (material.thermalFactor || 1)) / (toolGrade.heatResistance || 1)) * heatMultiplier;
        const wearMod = (loadMod / (toolGrade.durabilityFactor || 1)) * (isRunning ? 0.0008 : 0) * wearMultiplier;
        const noise = (val: number, range: number) => val + (Math.random() - 0.5) * range;
        const cycleSec = (Date.now() / 1000) % 4;
        const isCutting = isRunning && cycleSec > 0.5 && cycleSec < 3.0;
        const baseForce = isCutting ? 180 * loadMod * forceMultiplier : 0;

        const nextTelemetry: TelemetryData = {
          timestamp: Date.now(),
          rpm: isRunning ? noise(3200, 50) : 0,
          feedRate: isRunning ? noise(450, 20) : 0,
          spindleLoad: isRunning ? noise(42 * loadMod * forceMultiplier, 10) : 0,
          vibration: isRunning ? noise(1.4 * loadMod * forceMultiplier, 0.4) : noise(0.05, 0.02),
          temperature: isRunning 
            ? Math.min(125, prev.telemetry.temperature + (1.2 * heatMod)) 
            : Math.max(24, prev.telemetry.temperature - 0.5),
          toolWear: Math.min(100, prev.telemetry.toolWear + wearMod),
          powerConsumption: isRunning ? noise(4.8 * loadMod * forceMultiplier, 0.8) : 0.2,
          forces: {
            fx: isCutting ? noise(baseForce * 0.1, 10) : noise(0, 1),
            fy: isCutting ? noise(baseForce * 0.1, 10) : noise(0, 1),
            fz: isCutting ? noise(baseForce * 1.6, 40) : noise(0, 2)
          }
        };

        let health = MachineHealth.HEALTHY;
        if (nextTelemetry.temperature > 85 || nextTelemetry.toolWear > targetWear * 0.8) health = MachineHealth.WARNING;
        if (nextTelemetry.temperature > 105 || nextTelemetry.toolWear >= targetWear) health = MachineHealth.CRITICAL;

        const newState = {
          ...prev,
          status: currentStatus,
          health,
          telemetry: nextTelemetry,
          materialTest: {
            ...prev.materialTest,
            isActive: testActive
          },
          predictions: runAIInference(history)
        };
        stateRef.current = newState;
        return newState;
      });

      setHistory(prev => {
        const newHist = [...prev, stateRef.current.telemetry];
        return newHist.slice(-50);
      });
    }, MACHINE_CONFIG.POLLING_INTERVAL_MS);
    return () => clearInterval(interval);
  }, [history, activeAlarm]);

  const toggleMachine = useCallback(() => {
    const nextStatus = twinState.status === 'RUNNING' ? 'IDLE' : 'RUNNING';
    if (twinState.mode === 'SIMULATED') {
      setTwinState(prev => ({ ...prev, status: nextStatus }));
    } else {
      sendHardwareCommand('SET_STATUS', nextStatus);
    }
  }, [twinState.status, twinState.mode, sendHardwareCommand]);

  const resetMachine = useCallback(() => {
    setActiveAlarm(null);
    if (twinState.mode === 'SIMULATED') {
      setTwinState(prev => ({ 
        ...prev, 
        status: 'IDLE', 
        telemetry: { ...prev.telemetry, temperature: 24, toolWear: 0 },
        materialTest: { ...prev.materialTest, isActive: false, startTime: null }
      }));
    } else {
      sendHardwareCommand('RESET_SYSTEM');
    }
  }, [twinState.mode, sendHardwareCommand]);

  return (
    <div className="w-full h-full bg-[#020617] flex flex-col overflow-hidden">
      <header className="px-6 py-4 bg-slate-900/50 backdrop-blur-xl border-b border-white/5 flex justify-between items-center z-50">
        <div className="flex items-center space-x-4">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <Wifi className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-xl font-black text-white tracking-tighter uppercase italic">Twin<span className="text-indigo-400">Core</span></h1>
            <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Digital Force Twin</span>
          </div>
        </div>
        <div className="flex items-center space-x-4">
          <div className="flex bg-black/40 p-1 rounded-lg border border-white/5">
            {['SIMULATED', 'MQTT_LIVE', 'WIFI_LIVE'].map(m => (
              <button 
                key={m}
                onClick={() => setTwinState(s => ({ ...s, mode: m as any }))}
                className={`px-4 py-1.5 rounded-md text-[10px] font-black tracking-widest uppercase transition-all ${twinState.mode === m ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-white'}`}
              >
                {m.split('_')[0]}
              </button>
            ))}
          </div>
          <div className="flex space-x-2">
             <button onClick={toggleMachine} className={`px-6 py-2 rounded-lg font-black text-[11px] uppercase tracking-wider transition-all shadow-lg ${twinState.status === 'RUNNING' ? 'bg-red-500 shadow-red-500/20' : 'bg-emerald-500 shadow-emerald-500/20'} text-white`}>{twinState.status === 'RUNNING' ? 'STOP' : 'START'}</button>
             <button onClick={resetMachine} className="px-6 py-2 bg-slate-800 hover:bg-slate-700 rounded-lg font-black text-[11px] uppercase tracking-wider text-white border border-white/5">RESET</button>
          </div>
        </div>
      </header>

      {activeAlarm && (
        <div className="fixed top-20 right-6 z-[60] animate-in slide-in-from-right duration-300">
           <div className="bg-red-600 border border-red-400 p-4 rounded-2xl shadow-2xl shadow-red-500/30 flex items-start space-x-4 max-w-md">
              <div className="p-2 bg-white/20 rounded-full">
                <Bell size={20} className="text-white animate-bounce" />
              </div>
              <div className="flex-1">
                <h4 className="text-sm font-black text-white uppercase tracking-tight">Industrial Alarm Triggered</h4>
                <p className="text-xs text-red-50 font-medium mt-1 leading-relaxed">
                  {activeAlarm.message}
                </p>
                <div className="mt-3 flex space-x-2">
                  <button 
                    onClick={resetMachine}
                    className="px-3 py-1 bg-white text-red-600 text-[10px] font-black rounded-lg uppercase tracking-widest hover:bg-red-50 transition-colors"
                  >
                    Halt System & Clear
                  </button>
                  <button 
                    onClick={() => setActiveAlarm(null)}
                    className="p-1 text-white hover:bg-white/10 rounded-lg"
                  >
                    <X size={16} />
                  </button>
                </div>
              </div>
           </div>
        </div>
      )}

      <main className="flex-1 relative overflow-hidden">
        <Dashboard 
          twinState={twinState} 
          history={history} 
          materials={MATERIALS} 
          toolGrades={TOOL_GRADES} 
          onConfigChange={handleConfigChange}
          onStartTest={handleStartTest}
        />
      </main>
    </div>
  );
};

export default App;

import React, { useRef, useState } from 'react';
import { useFrame } from '@react-three/fiber';
import { Mesh, Color, Group, MeshStandardMaterial, PointLight } from 'three';
import { Text, Float, RoundedBox } from '@react-three/drei';
import { TwinState, MachineHealth } from '../types';
import { COLORS } from '../constants';

interface MachineModelProps {
  twinState: TwinState;
  onSelectPart: (part: string | null) => void;
  selectedPart: string | null;
}

export const MachineModel: React.FC<MachineModelProps> = ({ twinState, onSelectPart, selectedPart }) => {
  const spindleRef = useRef<Mesh>(null);
  const bitRef = useRef<Group>(null);
  const bitMaterialRef = useRef<MeshStandardMaterial>(null);
  const tableXRef = useRef<Group>(null);
  const tableYRef = useRef<Group>(null);
  const cycleTimeRef = useRef(0);
  const alarmRef = useRef<Group>(null);
  const hazardLightRef = useRef<PointLight>(null);
  const alarmLampRef = useRef<Mesh>(null);
  const headMatRef = useRef<MeshStandardMaterial>(null);
  const dynamometerRef = useRef<Group>(null);

  const [hovered, setHovered] = useState<string | null>(null);

  const HOME_Y = -1.2;      
  const CLEARANCE_Y = -1.8; 
  const DEPTH_Y = -2.6;     

  useFrame((state, delta) => {
    const isRunning = twinState.status === 'RUNNING';
    const telemetry = twinState.telemetry || { toolWear: 0, temperature: 24, rpm: 0, forces: { fx: 0, fy: 0, fz: 0 } };
    const toolWear = telemetry.toolWear || 0;
    const targetWear = twinState.materialTest.targetWear;

    // Critical if wear exceeds threshold or machine health is critical
    const isCritical = toolWear >= targetWear || twinState.health === MachineHealth.CRITICAL;

    if (bitMaterialRef.current) {
      const wearFactor = toolWear / 100;
      const baseColor = new Color("#cbd5e1");
      const warningColor = new Color("#ef4444");
      bitMaterialRef.current.color.lerpColors(baseColor, warningColor, Math.pow(wearFactor, 1.5));

      if (toolWear > targetWear * 0.5) {
        bitMaterialRef.current.emissive.set("#ff0000");
        bitMaterialRef.current.emissiveIntensity = ((toolWear - (targetWear * 0.5)) / (targetWear * 0.5)) * 3.0;
      } else {
        bitMaterialRef.current.emissive.set(0, 0, 0);
      }

      if (selectedPart === 'bit' || hovered === 'bit') {
        bitMaterialRef.current.emissive.set("#60a5fa");
        bitMaterialRef.current.emissiveIntensity = 2;
      }
    }

    if (isRunning) {
      const rotationSpeed = ((telemetry.rpm || 0) / 60) * delta * 2 * Math.PI;
      if (spindleRef.current) spindleRef.current.rotation.y -= rotationSpeed;
      if (bitRef.current) bitRef.current.rotation.y -= rotationSpeed;

      const cycleDuration = 4.0;
      cycleTimeRef.current = (cycleTimeRef.current + delta) % cycleDuration;
      const t = cycleTimeRef.current;

      let currentBitY = HOME_Y;
      let currentTableX = 0;
      let currentTableY = 0;

      const lerp = (start: number, end: number, t: number) => start + t * (end - start);
      const easeInOut = (t: number) => t < 0.5 ? 2 * t * t : -1 + (4 - 2 * t) * t;

      if (t < 0.8) {
        const p = easeInOut(t / 0.8);
        currentBitY = lerp(HOME_Y, CLEARANCE_Y, p);
        currentTableX = Math.sin(state.clock.elapsedTime * 0.4) * 0.4;
        currentTableY = Math.cos(state.clock.elapsedTime * 0.4) * 0.4;
      } else if (t < 2.5) {
        const p = (t - 0.8) / 1.7;
        currentBitY = lerp(CLEARANCE_Y, DEPTH_Y, p);
      } else if (t < 3.0) {
        currentBitY = DEPTH_Y;
      } else {
        const p = easeInOut((t - 3.0) / 1.0);
        currentBitY = lerp(DEPTH_Y, HOME_Y, p);
      }

      if (bitRef.current) bitRef.current.position.y = currentBitY;
      if (tableXRef.current) tableXRef.current.position.x = currentTableX;
      if (tableYRef.current) tableYRef.current.position.z = currentTableY;
    }

    // Micro-vibration on dynamometer based on actual forces
    if (dynamometerRef.current && isRunning) {
      const forceMag = Math.sqrt(telemetry.forces.fx**2 + telemetry.forces.fy**2 + telemetry.forces.fz**2) / 500;
      dynamometerRef.current.position.y = 0.4 + (Math.random() - 0.5) * 0.005 * forceMag;
    }

    // Alarm Blinking & Pulsing
    const blinkFreq = 14; 
    const blinkState = Math.sin(state.clock.elapsedTime * blinkFreq) > 0;
