interface MachineModelProps {
  twinState: TwinState;
  onSelectPart: (part: string | null) => void;
  selectedPart: string | null;
}

export const MachineModel: React.FC<MachineModelProps> = ({ twinState, onSelectPart, selectedPart }) => {
  const spindleRef = useRef<Mesh>(null);
  const bitRef = useRef<Group>(null);
  const bitMaterialRef = useRef<MeshStandardMaterial>(null);
  const tableXRef = useRef<Group>(null);
  const tableYRef = useRef<Group>(null);
  const cycleTimeRef = useRef(0);
  const alarmRef = useRef<Group>(null);
  const hazardLightRef = useRef<PointLight>(null);
  const alarmLampRef = useRef<Mesh>(null);
  const headMatRef = useRef<MeshStandardMaterial>(null);
  const dynamometerRef = useRef<Group>(null);

  const [hovered, setHovered] = useState<string | null>(null);

  const HOME_Y = -1.2;      
  const CLEARANCE_Y = -1.8; 
  const DEPTH_Y = -2.6;     

  useFrame((state, delta) => {
    const isRunning = twinState.status === 'RUNNING';
    const telemetry = twinState.telemetry || { toolWear: 0, temperature: 24, rpm: 0, forces: { fx: 0, fy: 0, fz: 0 } };
    const toolWear = telemetry.toolWear || 0;
    const targetWear = twinState.materialTest.targetWear;

    // UPDATED: Trigger alarm at 80% wear, target wear breach, or critical health state
    const isCritical = toolWear >= 80 || toolWear >= targetWear || twinState.health === MachineHealth.CRITICAL;

    if (bitMaterialRef.current) {
      const wearFactor = toolWear / 100;
      const baseColor = new Color("#cbd5e1");
      const warningColor = new Color("#ef4444");
      bitMaterialRef.current.color.lerpColors(baseColor, warningColor, Math.pow(wearFactor, 1.5));

      if (toolWear > targetWear * 0.5) {
        bitMaterialRef.current.emissive.set("#ff0000");
        bitMaterialRef.current.emissiveIntensity = ((toolWear - (targetWear * 0.5)) / (targetWear * 0.5)) * 3.0;
      } else {
        bitMaterialRef.current.emissive.set(0, 0, 0);
      }

      if (selectedPart === 'bit' || hovered === 'bit') {
        bitMaterialRef.current.emissive.set("#60a5fa");
        bitMaterialRef.current.emissiveIntensity = 2;
      }
    }

    if (isRunning) {
      const rotationSpeed = ((telemetry.rpm || 0) / 60) * delta * 2 * Math.PI;
      if (spindleRef.current) spindleRef.current.rotation.y -= rotationSpeed;
      if (bitRef.current) bitRef.current.rotation.y -= rotationSpeed;

      const cycleDuration = 4.0;
      cycleTimeRef.current = (cycleTimeRef.current + delta) % cycleDuration;
      const t = cycleTimeRef.current;

      let currentBitY = HOME_Y;
      let currentTableX = 0;
      let currentTableY = 0;

      const lerp = (start: number, end: number, t: number) => start + t * (end - start);
      const easeInOut = (t: number) => t < 0.5 ? 2 * t * t : -1 + (4 - 2 * t) * t;

      if (t < 0.8) {
        const p = easeInOut(t / 0.8);
        currentBitY = lerp(HOME_Y, CLEARANCE_Y, p);
        currentTableX = Math.sin(state.clock.elapsedTime * 0.4) * 0.4;
        currentTableY = Math.cos(state.clock.elapsedTime * 0.4) * 0.4;
      } else if (t < 2.5) {
        const p = (t - 0.8) / 1.7;
        currentBitY = lerp(CLEARANCE_Y, DEPTH_Y, p);
      } else if (t < 3.0) {
        currentBitY = DEPTH_Y;
      } else {
        const p = easeInOut((t - 3.0) / 1.0);
        currentBitY = lerp(DEPTH_Y, HOME_Y, p);
      }

      if (bitRef.current) bitRef.current.position.y = currentBitY;
      if (tableXRef.current) tableXRef.current.position.x = currentTableX;
      if (tableYRef.current) tableYRef.current.position.z = currentTableY;
    }

    if (dynamometerRef.current && isRunning) {
      const forceMag = Math.sqrt(telemetry.forces.fx**2 + telemetry.forces.fy**2 + telemetry.forces.fz**2) / 500;
      dynamometerRef.current.position.y = 0.4 + (Math.random() - 0.5) * 0.005 * forceMag;
    }

    // Alarm Blinking & Pulsing
    const blinkFreq = 16; 
    const blinkState = Math.sin(state.clock.elapsedTime * blinkFreq) > 0;
    const pulseScale = 1 + Math.sin(state.clock.elapsedTime * 10) * 0.15;
    const shouldAlarm = isCritical && blinkState;

    if (alarmRef.current) {
      alarmRef.current.visible = isCritical; 
      alarmRef.current.scale.set(pulseScale, pulseScale, pulseScale);
      alarmRef.current.children.forEach(child => {
        child.visible = shouldAlarm;
      });
    }

    if (hazardLightRef.current) {
      hazardLightRef.current.intensity = shouldAlarm ? 40 : 0;
    }

    if (alarmLampRef.current) {
      const mat = alarmLampRef.current.material as MeshStandardMaterial;
      if (mat) {
        mat.emissiveIntensity = shouldAlarm ? 15 : 0;
        mat.color.set(shouldAlarm ? "#ff0000" : "#220000");
      }
    }

    if (headMatRef.current) {
      const targetEmissive = isCritical ? new Color("#ff0000") : new Color("#000000");
      headMatRef.current.emissive.lerp(targetEmissive, 0.1);
      headMatRef.current.emissiveIntensity = isCritical ? (shouldAlarm ? 1.0 : 0.3) : 0;
    }
  });

  const healthColor = twinState.health === MachineHealth.HEALTHY ? COLORS.HEALTHY : 
                  twinState.health === MachineHealth.WARNING ? COLORS.WARNING : COLORS.CRITICAL;

  return (
    <group>
      {/* Structural Components */}
      <mesh position={[0, 2.25, -1.8]}>
        <boxGeometry args={[4.2, 4.5, 0.2]} />
        <meshStandardMaterial color="#0f172a" metalness={0.8} roughness={0.2} />
      </mesh>

      <mesh position={[2, 2.25, 0]}>
        <boxGeometry args={[0.2, 4.5, 3.8]} />
        <meshStandardMaterial color="#1e293b" metalness={0.5} transparent opacity={0.2} />
      </mesh>
      <mesh position={[-2, 2.25, 0]}>
        <boxGeometry args={[0.2, 4.5, 3.8]} />
        <meshStandardMaterial color="#1e293b" metalness={0.8} />
      </mesh>

      <RoundedBox args={[4, 0.4, 4]} radius={0.05} smoothness={4} position={[0, 0, 0]}>
        <meshStandardMaterial color="#0f172a" metalness={1} roughness={0.1} />
      </RoundedBox>

      {/* Table & Dynamometer & Workpiece */}
      <group ref={tableYRef}>
        <mesh position={[0, 0.3, 0]}>
          <boxGeometry args={[3.2, 0.2, 3.2]} />
          <meshStandardMaterial color="#334155" metalness={0.8} />
        </mesh>
        <group ref={tableXRef} position={[0, 0.2, 0]}>
          <group ref={dynamometerRef} position={[0, 0.4, 0]}>
            <mesh 
              onClick={(e) => { e.stopPropagation(); onSelectPart('dynamometer'); }}
              onPointerOver={() => setHovered('dynamometer')}
              onPointerOut={() => setHovered(null)}
            >
              <boxGeometry args={[1.8, 0.15, 1.8]} />
              <meshStandardMaterial 
                color={selectedPart === 'dynamometer' || hovered === 'dynamometer' ? "#60a5fa" : "#1e293b"} 
                metalness={0.9} 
                roughness={0.1} 
              />
            </mesh>
            {[[-0.7, -0.7], [0.7, -0.7], [-0.7, 0.7], [0.7, 0.7]].map((pos, idx) => (
              <mesh key={idx} position={[pos[0], -0.05, pos[1]]}>
                <cylinderGeometry args={[0.08, 0.08, 0.05, 12]} />
                <meshStandardMaterial color="#fbbf24" metalness={1} emissive="#fbbf24" emissiveIntensity={0.2} />
              </mesh>
            ))}
            <mesh position={[1, 0, 0]}>
              <boxGeometry args={[0.3, 0.08, 0.5]} />
              <meshStandardMaterial color="#334155" />
            </mesh>
            <mesh position={[0, 0.3, 0]} castShadow>
              <boxGeometry args={[1, 0.4, 1]} />
              <meshStandardMaterial color="#94a3b8" metalness={0.2} roughness={0.7} />
            </mesh>
            <Text
              position={[0, 0.08, 0.95]}
              rotation={[-Math.PI / 2, 0, 0]}
              fontSize={0.08}
              color="white"
              anchorX="center"
              anchorY="middle"
            >
              DYNAMOMETER MULTICOMPONENT TYPE 9257B
            </Text>
          </group>
        </group>
      </group>

      <mesh position={[-1.2, 2.5, -1]} castShadow>
        <boxGeometry args={[0.8, 5, 0.8]} />
        <meshStandardMaterial color="#1e293b" metalness={0.5} />
      </mesh>

      <group position={[0, 3.2, -0.6]}>
        <mesh position={[0, 0, 0]} castShadow>
          <boxGeometry args={[1.5, 1.2, 1.2]} />
          <meshStandardMaterial ref={headMatRef} color="#334155" metalness={0.8} />
        </mesh>

        <mesh ref={alarmLampRef} position={[0, 0.65, 0]} castShadow>
          <cylinderGeometry args={[0.15, 0.15, 0.2, 16]} />
          <meshStandardMaterial color="#220000" emissive="#ff0000" emissiveIntensity={0} />
        </mesh>

        <pointLight ref={hazardLightRef} position={[0, 1.5, 0.8]} color="#ff0000" intensity={0} distance={6} />

        <mesh 
          ref={spindleRef} 
          position={[0, -0.5, 0.4]} 
          castShadow
          onClick={(e) => { e.stopPropagation(); onSelectPart('spindle'); }}
          onPointerOver={(e) => { e.stopPropagation(); document.body.style.cursor = 'pointer'; setHovered('spindle'); }}
          onPointerOut={(e) => { e.stopPropagation(); document.body.style.cursor = 'auto'; setHovered(null); }}
        >
          <cylinderGeometry args={[0.3, 0.35, 1, 32]} />
          <meshStandardMaterial color={healthColor} metalness={0.9} roughness={0.1} />
        </mesh>

        <group 
          ref={bitRef} 
          position={[0, HOME_Y, 0.4]}
          onClick={(e) => { e.stopPropagation(); onSelectPart('bit'); }}
          onPointerOver={(e) => { e.stopPropagation(); document.body.style.cursor = 'pointer'; setHovered('bit'); }}
          onPointerOut={(e) => { e.stopPropagation(); document.body.style.cursor = 'auto'; setHovered(null); }}
        >
          <mesh position={[0, 0.4, 0]}>
            <cylinderGeometry args={[0.15, 0.1, 0.3, 16]} />
            <meshStandardMaterial color="#475569" metalness={1} />
