            <meshStandardMaterial ref={bitMaterialRef} color="#cbd5e1" metalness={1} roughness={0} />
          </mesh>
        </group>
      </group>

      <group ref={alarmRef} position={[0, 5.2, 0]}>
         <Float speed={5} rotationIntensity={0.5} floatIntensity={0.5}>
