import React, { useState } from 'react';
import { ThreeScene } from './ThreeScene';
import { TelemetryData, TwinState, MachineHealth, Material, ToolGrade } from '../types';
import { TelemetryCharts } from './TelemetryCharts';
import { AIInsights } from './AIInsights';
import { 
  Activity, Thermometer, Zap, Gauge, Wrench, Clock, ShieldAlert, 
  Layers, Wifi, Cloud, Globe, Box, Terminal, Settings, Beaker, Play, StopCircle, Flame, Hammer, ZapOff, Info,
  FileText, Upload, CheckCircle, ClipboardCheck
} from 'lucide-react';

interface DashboardProps {
  twinState: TwinState;
  history: TelemetryData[];
  materials: Material[];
  toolGrades: ToolGrade[];
  onConfigChange: (config: any) => void;
  onStartTest?: () => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ 
  twinState, 
  history, 
  materials, 
  toolGrades, 
  onConfigChange,
  onStartTest
}) => {
  const [reportText, setReportText] = useState('');
  const [conclusion, setConclusion] = useState<string | null>(null);

  const handleFinalizeConclusion = () => {
    if (!reportText.trim()) {
      setConclusion("Error: No test data provided for conclusion.");
      return;
    }
    // Simulate industrial reasoning logic
    const wear = twinState.telemetry.toolWear;
    const health = twinState.health;
    setConclusion(`Conclusion based on provided data: System status ${health} with ${wear.toFixed(1)}% wear. Observations noted: "${reportText.substring(0, 30)}...". Action recommended: ${wear > 80 ? 'Immediate change-out' : 'Continue monitoring'}.`);
  };

  const stats = [
    { label: 'Spindle RPM', value: `${Math.round(twinState.telemetry.rpm)}`, icon: Activity, color: 'text-indigo-400' },
    { label: 'Force Axial (Fz)', value: `${Math.round(twinState.telemetry.forces.fz)} N`, icon: Gauge, color: 'text-emerald-400' },
    { label: 'Vibration', value: `${twinState.telemetry.vibration.toFixed(2)} G`, icon: Zap, color: 'text-amber-400' },
    { label: 'Temperature', value: `${twinState.telemetry.temperature.toFixed(1)}°C`, icon: Thermometer, color: twinState.telemetry.temperature > 80 ? 'text-red-400' : 'text-emerald-400' },
  ];

  const maintenance = [
    { label: 'AI Predicted RUL', value: `${twinState.predictions.rul.toFixed(1)}h`, icon: Clock, color: twinState.predictions.rul < 100 ? 'text-red-400' : 'text-white' },
    { label: 'Wear Index', value: `${twinState.telemetry.toolWear.toFixed(2)}%`, icon: Wrench, color: 'text-white' },
    { label: 'Failure Prob.', value: `${(twinState.predictions.failureProbability * 100).toFixed(1)}%`, icon: ShieldAlert, color: 'text-white' },
  ];

  const getTestProgress = () => {
    if (!twinState.materialTest.isActive || !twinState.materialTest.startTime) return 0;
    const timeElapsed = (Date.now() - twinState.materialTest.startTime) / 1000;
    const timeProgress = (timeElapsed / twinState.materialTest.durationSeconds) * 100;
    const wearProgress = (twinState.telemetry.toolWear / twinState.materialTest.targetWear) * 100;
    return Math.min(100, Math.max(timeProgress, wearProgress));
  };

  const scenarios = [
    { id: 'NORMAL', label: 'Nominal', icon: Settings, desc: 'Standard operating cycle.' },
    { id: 'AGGRESSIVE', label: 'Aggressive Feed', icon: Hammer, desc: 'High feed pressure; 2.2x force impact.' },
    { id: 'THERMAL', label: 'Thermal Overload', icon: Flame, desc: 'Reduced cooling; 3.5x temperature ramp.' },
    { id: 'IMPACT', label: 'Brittle Impact', icon: ZapOff, desc: 'Structural shocks; 6x accelerated wear.' },
  ];

  const currentScenario = scenarios.find(s => s.id === twinState.materialTest.scenario) || scenarios[0];

  return (
    <div className="h-full flex flex-col md:flex-row overflow-hidden">
      {/* 3D Visualizer Section */}
      <div className="flex-1 relative bg-gradient-to-br from-[#020617] to-[#0f172a] min-h-[400px]">
        <ThreeScene twinState={twinState} />

        {/* Scenario Overlay during Test */}
        {twinState.materialTest.isActive && (
          <div className="absolute top-24 left-6 z-20 animate-in fade-in slide-in-from-left duration-500">
             <div className="bg-indigo-600/20 backdrop-blur-xl border border-indigo-500/40 p-4 rounded-2xl flex items-center space-x-4 shadow-2xl">
               <div className="p-2 bg-indigo-500 rounded-xl">
                 <currentScenario.icon size={20} className="text-white animate-pulse" />
               </div>
               <div>
                 <p className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.2em]">Live Test Running</p>
                 <p className="text-sm font-black text-white uppercase tracking-tight">{currentScenario.label} Mode</p>
                 <p className="text-[9px] text-slate-400 font-bold mt-0.5">{currentScenario.desc}</p>
               </div>
             </div>
