            }`}>
              <span className="text-[10px] font-black uppercase tracking-widest flex items-center">
                <Activity size={12} className="mr-2" /> Asset Health Status
              </span>
              <span className="text-xs font-black">{twinState.health}</span>
            </div>
          </section>

          <section>
            <h2 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-4 flex items-center">
               <Layers size={14} className="mr-2 text-indigo-500" /> Process Setup
            </h2>
            <div className="space-y-6 bg-white/5 p-5 rounded-3xl border border-white/5">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-500 uppercase ml-1">Workpiece Material</label>
                  <select 
                    className="w-full bg-slate-900 border border-white/10 rounded-xl px-3 py-2 text-xs text-white outline-none"
                    value={twinState.config.material.id}
                    onChange={(e) => {
                      const mat = materials.find(m => m.id === e.target.value);
                      if (mat) onConfigChange({ material: mat });
                    }}
                  >
                    {materials.map(m => (
                      <option key={m.id} value={m.id}>{m.name}</option>
                    ))}
                  </select>
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-500 uppercase ml-1">Tool Specification</label>
                  <select 
                    className="w-full bg-slate-900 border border-white/10 rounded-xl px-3 py-2 text-xs text-white outline-none"
                    value={twinState.config.toolGrade.id}
                    onChange={(e) => {
                      const tool = toolGrades.find(t => t.id === e.target.value);
                      if (tool) onConfigChange({ toolGrade: tool });
                    }}
                  >
                    {toolGrades.map(t => (
                      <option key={t.id} value={t.id}>{t.name}</option>
                    ))}
                  </select>
                </div>
              </div>
              <div className="mt-2 flex items-start space-x-2 bg-indigo-500/5 p-3 rounded-xl border border-indigo-500/10">
                <Info size={14} className="text-indigo-400 mt-0.5" />
                <p className="text-[9px] text-slate-400 font-medium">Wear monitoring is active. Alarm triggers automatically at <span className="text-red-400 font-bold">60%</span> degradation threshold.</p>
              </div>
            </div>
          </section>

          {/* Connectivity & Hardware Configuration */}
          <section>
            <h2 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-4 flex items-center">
               <Network size={14} className="mr-2 text-indigo-500" /> Connectivity & Hardware
            </h2>
            <div className="bg-white/5 p-5 rounded-3xl border border-white/5 space-y-4">
              <div className="space-y-3">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-500 uppercase ml-1 flex items-center"><Key size={10} className="mr-1" /> ThingSpeak Write API Key</label>
                  <input 
                    type="password"
                    value={twinState.config.thingSpeakKey}
                    onChange={(e) => onConfigChange({ thingSpeakKey: e.target.value })}
                    className="w-full bg-slate-900 border border-white/10 rounded-xl px-3 py-2 text-xs text-white outline-none focus:border-indigo-500/50"
                    placeholder="Enter Key for Cloud Sync"
                  />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-500 uppercase ml-1">MQTT Command Topic</label>
                  <input 
                    type="text"
                    value={twinState.config.commandTopic}
                    onChange={(e) => onConfigChange({ commandTopic: e.target.value })}
                    className="w-full bg-slate-900 border border-white/10 rounded-xl px-3 py-2 text-xs text-white outline-none focus:border-indigo-500/50"
                    placeholder="e.g. machine/commands"
                  />
                </div>
                <div className="grid grid-cols-3 gap-3">
                  <div className="col-span-2 space-y-1">
                    <label className="text-[10px] font-black text-slate-500 uppercase ml-1">ESP32 IP Address</label>
                    <input 
                      type="text"
                      value={twinState.config.espIp}
                      onChange={(e) => onConfigChange({ espIp: e.target.value })}
                      className="w-full bg-slate-900 border border-white/10 rounded-xl px-3 py-2 text-xs text-white outline-none focus:border-indigo-500/50"
                      placeholder="192.168.1.100"
                    />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-500 uppercase ml-1">Port</label>
                    <input 
                      type="text"
                      value={twinState.config.espPort}
                      onChange={(e) => onConfigChange({ espPort: e.target.value })}
                      className="w-full bg-slate-900 border border-white/10 rounded-xl px-3 py-2 text-xs text-white outline-none focus:border-indigo-500/50"
                      placeholder="80"
                    />
                  </div>
                </div>
              </div>
            </div>
          </section>

          {/* Validation Reporting & Data Upload */}
          <section>
            <h2 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-4 flex items-center">
               <FileText size={14} className="mr-2 text-indigo-500" /> Technical Validation & Reporting
            </h2>
            <div className="bg-white/5 p-5 rounded-3xl border border-white/5 space-y-4 shadow-inner">
               <div className="space-y-2">
                 <label className="text-[10px] font-black text-slate-500 uppercase ml-1">Test Observations</label>
                 <textarea 
                   className="w-full bg-slate-900 border border-white/10 rounded-xl px-3 py-2 text-xs text-white outline-none h-24 focus:border-indigo-500/50 resize-none transition-colors"
                   placeholder="Input test results, microscopic analysis, or surface finish notes..."
                   value={reportText}
                   onChange={(e) => setReportText(e.target.value)}
                 />
               </div>

               {uploadedFile && (
                 <div className="flex items-center space-x-2 bg-indigo-500/10 p-2 rounded-lg border border-indigo-500/20">
                   <Paperclip size={12} className="text-indigo-400" />
                   <span className="text-[10px] font-mono text-slate-300 truncate">{uploadedFile}</span>
                   <button onClick={() => setUploadedFile(null)} className="text-[10px] text-red-400 font-black ml-auto hover:text-red-300">REMOVE</button>
                 </div>
               )}

               <div className="flex space-x-2">
                 <input 
                   type="file" 
                   ref={fileInputRef} 
                   className="hidden" 
                   onChange={handleFileUpload}
                 />
                 <button 
                   onClick={() => fileInputRef.current?.click()}
                   className="flex-1 py-2.5 bg-slate-800 hover:bg-slate-700 rounded-xl text-[10px] font-black uppercase tracking-widest text-slate-300 border border-white/5 flex items-center justify-center transition-all"
                 >
                    <Upload size={14} className="mr-2" /> Upload Info
                 </button>
                 <button 
                   onClick={handleFinalizeConclusion}
                   className="flex-1 py-2.5 bg-indigo-600 hover:bg-indigo-500 rounded-xl text-[10px] font-black uppercase tracking-widest text-white flex items-center justify-center shadow-lg transition-all"
                 >
                    <CheckCircle size={14} className="mr-2" /> Conclusion
                 </button>
               </div>

               {conclusion && (
                 <div className="mt-4 p-4 bg-emerald-500/10 border border-emerald-500/20 rounded-xl animate-in fade-in slide-in-from-top-2 duration-300">
                    <div className="flex items-center space-x-2 mb-2">
                      <ClipboardCheck size={14} className="text-emerald-400" />
                      <span className="text-[10px] font-black text-emerald-400 uppercase tracking-widest">Formal Assessment</span>
                    </div>
                    <p className="text-[10px] text-slate-300 leading-relaxed font-medium font-mono">
                      {conclusion}
                    </p>
                 </div>
               )}
            </div>
          </section>

          <section>
            <h2 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-4 flex items-center">
               <Box size={14} className="mr-2 text-indigo-500" /> Live Indicators
            </h2>
            <div className="grid grid-cols-2 gap-4">
              {stats.map((stat, i) => (
                <div key={i} className="bg-white/5 p-4 rounded-2xl border border-white/5">
                  <div className="flex items-center space-x-2 mb-2">
                    <stat.icon size={14} className={stat.color} />
                    <span className="text-[9px] text-slate-500 font-black uppercase tracking-widest">{stat.label}</span>
                  </div>
                  <div className="text-lg font-black text-white font-mono">{stat.value}</div>
                </div>
              ))}
            </div>
          </section>

          <section className="flex-1">
             <h2 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-4 flex items-center">
               <Globe size={14} className="mr-2 text-indigo-500" /> Sensor Streams
             </h2>
             <TelemetryCharts history={history} />
          </section>

          <section>
             <AIInsights twinState={twinState} />
          </section>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Dashboard } from './components/Dashboard';
import { TelemetryData, TwinState, MachineHealth, Material, ToolGrade } from './types';
import { MACHINE_CONFIG } from './constants';
import mqtt from 'mqtt';
import { Wifi, Shield, Globe, Cpu, ChevronUp, Link, Settings, AlertCircle, Bell, X } from 'lucide-react';

const MATERIALS: Material[] = [
  { id: 'al6061', name: 'Aluminum 6061', hardnessFactor: 0.7, thermalFactor: 1.5 },
  { id: 'st1045', name: 'Steel AISI 1045', hardnessFactor: 1.2, thermalFactor: 0.9 },
  { id: 'ti64', name: 'Titanium Ti-6Al-4V', hardnessFactor: 2.2, thermalFactor: 0.4 },
  { id: 'in718', name: 'Inconel 718', hardnessFactor: 3.5, thermalFactor: 0.2 },
];

const TOOL_GRADES: ToolGrade[] = [
  { id: 'hss', name: 'HSS (Standard)', durabilityFactor: 0.5, heatResistance: 0.6 },
  { id: 'carbide', name: 'Carbide (Micrograin)', durabilityFactor: 2.5, heatResistance: 2.0 },
  { id: 'cobalt', name: 'Cobalt (M42)', durabilityFactor: 1.5, heatResistance: 1.5 },
  { id: 'pcd', name: 'PCD Diamond', durabilityFactor: 5.0, heatResistance: 3.0 },
];

const INITIAL_TELEMETRY: TelemetryData = {
  timestamp: Date.now(),
  rpm: 0,
  feedRate: 0,
  spindleLoad: 0,
  vibration: 0.1,
  temperature: 24,
  toolWear: 5,
  powerConsumption: 0.5,
  forces: { fx: 0, fy: 0, fz: 0 }
};

const INITIAL_STATE: TwinState = {
  id: 'CNC-PRO-G3-001',
  name: 'Smart Factory Alpha - Unit 01',
  model: 'Acu-Drill Pro 5000 Edge',
  health: MachineHealth.HEALTHY,
  status: 'IDLE',
  mode: 'SIMULATED',
  mqttStatus: 'DISCONNECTED',
  cloudSync: 'OFFLINE',
  lastCommandSent: null,
  telemetry: INITIAL_TELEMETRY,
  materialTest: {
    isActive: false,
    durationSeconds: 30,
    targetWear: 95,
    startTime: null,
    scenario: 'NORMAL'
  },
  config: {
    material: MATERIALS[0],
    toolGrade: TOOL_GRADES[1],
    thingSpeakKey: '',
    mqttBroker: 'wss://broker.emqx.io:8084/mqtt',
    telemetryTopic: 'cnc/telemetry',
    commandTopic: 'cnc/control',
    wifiSsid: '',
    wifiPassword: '',
    espIp: '192.168.1.100',
    espPort: '80'
  },
  predictions: {
    rul: 425.5,
    failureProbability: 0.02,
    nextMaintenanceDate: '2025-01-20',
    anomalyDetected: false
  }
};

const App: React.FC = () => {
  const [twinState, setTwinState] = useState<TwinState>(INITIAL_STATE);
  const [history, setHistory] = useState<TelemetryData[]>([]);
  const [activeAlarm, setActiveAlarm] = useState<{ type: string; message: string } | null>(null);
  const stateRef = useRef<TwinState>(INITIAL_STATE);
  const mqttClientRef = useRef<any>(null);
  const lastCloudSyncRef = useRef<number>(0);

  // Request notification permissions on mount
  useEffect(() => {
    if ("Notification" in window) {
      Notification.requestPermission();
    }
  }, []);

  const handleConfigChange = useCallback((cfg: any) => {
    setTwinState(s => {
      const newState = { ...s };

      // Correctly route materialTest updates at the top level
      if (cfg.materialTest) {
        newState.materialTest = { ...s.materialTest, ...cfg.materialTest };
      }

      // Update nested configuration properties
      if (cfg.material || cfg.toolGrade || cfg.hasOwnProperty('thingSpeakKey') || cfg.mqttBroker || 
          cfg.telemetryTopic || cfg.commandTopic || cfg.wifiSsid || cfg.wifiPassword || 
          cfg.espIp || cfg.espPort) {
        newState.config = { ...s.config, ...cfg };
      }

      stateRef.current = newState;
      return newState;
    });
  }, []);

  const syncToThingSpeak = useCallback(async (telemetry: TelemetryData, key: string) => {
    if (!key || key.trim() === '' || key === 'YOUR_KEY_HERE') {
      if (twinState.cloudSync !== 'OFFLINE') {
        setTwinState(s => ({ ...s, cloudSync: 'OFFLINE' }));
      }
      return;
    }

    const now = Date.now();
    // ThingSpeak free tier limit is 15 seconds
    if (now - lastCloudSyncRef.current < 15500) return;

    lastCloudSyncRef.current = now;
    setTwinState(s => ({ ...s, cloudSync: 'SYNCING' }));

    try {
      // User mapping request: RPM(F1), Temp(F2), Wear(F3), Vibration(F4), Z-Force(F5)
      const baseUrl = 'https://api.thingspeak.com/update';
      const params = new URLSearchParams({
        api_key: key,
        field1: telemetry.rpm.toString(),
        field2: telemetry.temperature.toString(),
        field3: telemetry.toolWear.toString(),
        field4: telemetry.vibration.toString(),
        field5: telemetry.forces.fz.toString()
      });

      const response = await fetch(`${baseUrl}?${params.toString()}`);
      if (response.ok) {
        setTwinState(s => ({ ...s, cloudSync: 'SYNCED' }));
      } else {
        setTwinState(s => ({ ...s, cloudSync: 'ERROR' }));
      }
    } catch (e) {
      console.error("ThingSpeak Cloud Error:", e);
      setTwinState(s => ({ ...s, cloudSync: 'ERROR' }));
    }
  }, [twinState.cloudSync]);

  const runAIInference = (currentHistory: TelemetryData[]) => {
    if (currentHistory.length < 5) return stateRef.current.predictions;
    const recentWear = currentHistory.slice(-10).map(h => h.toolWear || 0);
    const recentTemp = currentHistory.slice(-10).map(h => h.temperature || 24);
    const wearTrend = (recentWear[recentWear.length - 1] - (recentWear[0] || 0)) / 10;
    const avgTemp = recentTemp.reduce((a, b) => a + b, 0) / recentTemp.length;
    const estimatedLife = 500 / (wearTrend > 0 ? wearTrend * 1000 : 0.001);
    const adjustedRul = Math.max(0, estimatedLife * (1 - (avgTemp / 200)));
    return {
      rul: adjustedRul,
      failureProbability: avgTemp > 95 ? 0.95 : avgTemp > 80 ? 0.45 : 0.02,
      nextMaintenanceDate: adjustedRul < 50 ? 'IMMEDIATE' : '2025-02-15',
      anomalyDetected: avgTemp > 110 || wearTrend > 0.5
    };
  };

  const sendHardwareCommand = useCallback(async (action: string, value?: string) => {
    const { espIp, espPort } = stateRef.current.config;
    if (!espIp) return;

    const url = `http://${espIp}:${espPort}/control?action=${action}${value ? `&value=${value}` : ''}`;
    try {
      setTwinState(s => ({ ...s, lastCommandSent: `UPLINK [FETCH]: ${action}${value ? `=${value}` : ''}` }));
      await fetch(url, { mode: 'no-cors' }); 
    } catch (error) {
      setTwinState(s => ({ ...s, lastCommandSent: 'UPLINK ERROR: TARGET UNREACHABLE' }));
    }
  }, []);

  useEffect(() => {
    if (twinState.mode === 'MQTT_LIVE') {
      try {
        const client = mqtt.connect(twinState.config.mqttBroker);
        mqttClientRef.current = client;
        client.on('connect', () => {
          setTwinState(s => ({ ...s, mqttStatus: 'CONNECTED' }));
          client.subscribe(stateRef.current.config.telemetryTopic);
        });
        client.on('message', (topic, message) => {
          if (topic === stateRef.current.config.telemetryTopic) {
            try {
              const payload = JSON.parse(message.toString());
              setTwinState(s => {
                const updatedTelemetry = { ...s.telemetry, ...payload, timestamp: Date.now() };
                // Using ref for sync call to avoid dependency loop if possible, 
                // but since it's an external trigger it's fine
                syncToThingSpeak(updatedTelemetry, s.config.thingSpeakKey);
                return {
                  ...s,
                  status: payload.status || s.status,
                  telemetry: updatedTelemetry
                };
              });
            } catch (e) {}
          }
        });
        client.on('error', () => setTwinState(s => ({ ...s, mqttStatus: 'DISCONNECTED' })));
        client.on('close', () => setTwinState(s => ({ ...s, mqttStatus: 'DISCONNECTED' })));
      } catch (e) {}
    } else {
      if (mqttClientRef.current) {
        mqttClientRef.current.end();
        mqttClientRef.current = null;
      }
      setTwinState(s => ({ ...s, mqttStatus: 'DISCONNECTED' }));
    }
    return () => { if (mqttClientRef.current) mqttClientRef.current.end(); };
  }, [twinState.mode, twinState.config.mqttBroker, syncToThingSpeak, twinState.config.telemetryTopic]);

  useEffect(() => {
    const interval = setInterval(() => {
      let nextTele: TelemetryData | null = null;
      let currentKey: string = '';

      setTwinState(prev => {
        if (prev.mode !== 'SIMULATED') return prev; 

        let isRunning = prev.status === 'RUNNING';
        let currentStatus = prev.status;
        let testActive = prev.materialTest.isActive;
        const scenario = prev.materialTest.scenario || 'NORMAL';
        const targetWear = prev.materialTest.targetWear;
        currentKey = prev.config.thingSpeakKey;

        if (isRunning && prev.telemetry.toolWear >= targetWear) {
          isRunning = false;
          currentStatus = 'IDLE';
          testActive = false;

          if (!activeAlarm) {
            const scenarioInfo = testActive && scenario !== 'NORMAL' ? ` during ${scenario} scenario` : '';
            const alarmMsg = `SAFETY SHUTDOWN: Tool wear exceeded limit of ${targetWear}%${scenarioInfo}.`;
            setActiveAlarm({ type: 'CRITICAL', message: alarmMsg });
          }
        }

        const { material, toolGrade } = prev.config;
        const loadMod = material.hardnessFactor || 1;

        let wearMultiplier = testActive ? 8 : 1; 
        let heatMultiplier = 1;
        let forceMultiplier = 1;

        if (testActive) {
          switch(scenario) {
            case 'AGGRESSIVE': wearMultiplier *= 3.0; forceMultiplier = 2.2; break;
            case 'THERMAL': heatMultiplier = 3.5; wearMultiplier *= 1.5; break;
            case 'IMPACT': wearMultiplier *= 6.0; forceMultiplier = 3.5; break;
          }
        }

        const heatMod = ((loadMod / (material.thermalFactor || 1)) / (toolGrade.heatResistance || 1)) * heatMultiplier;
        const wearMod = (loadMod / (toolGrade.durabilityFactor || 1)) * (isRunning ? 0.0008 : 0) * wearMultiplier;
        const noise = (val: number, range: number) => val + (Math.random() - 0.5) * range;
        const cycleSec = (Date.now() / 1000) % 4;
        const isCutting = isRunning && cycleSec > 0.5 && cycleSec < 3.0;
        const baseForce = isCutting ? 180 * loadMod * forceMultiplier : 0;

        nextTele = {
          timestamp: Date.now(),
          rpm: isRunning ? noise(3200, 50) : 0,
          feedRate: isRunning ? noise(450, 20) : 0,
          spindleLoad: isRunning ? noise(42 * loadMod * forceMultiplier, 10) : 0,
          vibration: isRunning ? noise(1.4 * loadMod * forceMultiplier, 0.4) : noise(0.05, 0.02),
          temperature: isRunning 
            ? Math.min(125, prev.telemetry.temperature + (1.2 * heatMod)) 
            : Math.max(24, prev.telemetry.temperature - 0.5),
          toolWear: Math.min(100, prev.telemetry.toolWear + wearMod),
          powerConsumption: isRunning ? noise(4.8 * loadMod * forceMultiplier, 0.8) : 0.2,
          forces: {
            fx: isCutting ? noise(baseForce * 0.1, 10) : noise(0, 1),
            fy: isCutting ? noise(baseForce * 0.1, 10) : noise(0, 1),
            fz: isCutting ? noise(baseForce * 1.6, 40) : noise(0, 2)
          }
        };

        let health = MachineHealth.HEALTHY;
        if (nextTele.temperature > 85 || nextTele.toolWear > targetWear * 0.8) health = MachineHealth.WARNING;
        if (nextTele.temperature > 105 || nextTele.toolWear >= targetWear) health = MachineHealth.CRITICAL;

        const newState = {
          ...prev,
          status: currentStatus,
          health,
          telemetry: nextTele,
          predictions: runAIInference(history)
        };
        stateRef.current = newState;
        return newState;
      });

      // Execute side effects outside of the functional state update
      if (nextTele) {
        syncToThingSpeak(nextTele, currentKey);
        setHistory(prev => {
          const newHist = [...prev, nextTele as TelemetryData];
          return newHist.slice(-50);
        });
      }
    }, MACHINE_CONFIG.POLLING_INTERVAL_MS);
    return () => clearInterval(interval);
  }, [history, activeAlarm, syncToThingSpeak]);

  const toggleMachine = useCallback(() => {
    const nextStatus = twinState.status === 'RUNNING' ? 'IDLE' : 'RUNNING';
    if (twinState.mode === 'SIMULATED') {
      setTwinState(prev => ({ ...prev, status: nextStatus }));
    } else {
      sendHardwareCommand('SET_STATUS', nextStatus);
    }
  }, [twinState.status, twinState.mode, sendHardwareCommand]);

  const resetMachine = useCallback(() => {
    setActiveAlarm(null);
    if (twinState.mode === 'SIMULATED') {
      setTwinState(prev => ({ 
        ...prev, 
        status: 'IDLE', 
        telemetry: { ...prev.telemetry, temperature: 24, toolWear: 0 },
        materialTest: { ...prev.materialTest, isActive: false, startTime: null }
      }));
    } else {
      sendHardwareCommand('RESET_SYSTEM');
    }
  }, [twinState.mode, sendHardwareCommand]);

  return (
    <div className="w-full h-full bg-[#020617] flex flex-col overflow-hidden">
      <header className="px-6 py-4 bg-slate-900/50 backdrop-blur-xl border-b border-white/5 flex justify-between items-center z-50">
        <div className="flex items-center space-x-4">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <Wifi className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-xl font-black text-white tracking-tighter uppercase italic">Twin<span className="text-indigo-400">Core</span></h1>
            <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Digital Force Twin</span>
          </div>
        </div>
        <div className="flex items-center space-x-4">
          <div className="flex bg-black/40 p-1 rounded-lg border border-white/5">
            {['SIMULATED', 'MQTT_LIVE', 'WIFI_LIVE'].map(m => (
              <button 
                key={m}
                onClick={() => setTwinState(s => ({ ...s, mode: m as any }))}
                className={`px-4 py-1.5 rounded-md text-[10px] font-black tracking-widest uppercase transition-all ${twinState.mode === m ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-white'}`}
              >
                {m.split('_')[0]}
              </button>
            ))}
          </div>
          <div className="flex space-x-2">
             <button onClick={toggleMachine} className={`px-6 py-2 rounded-lg font-black text-[11px] uppercase tracking-wider transition-all shadow-lg ${twinState.status === 'RUNNING' ? 'bg-red-500 shadow-red-500/20' : 'bg-emerald-500 shadow-emerald-500/20'} text-white`}>{twinState.status === 'RUNNING' ? 'STOP' : 'START'}</button>
             <button onClick={resetMachine} className="px-6 py-2 bg-slate-800 hover:bg-slate-700 rounded-lg font-black text-[11px] uppercase tracking-wider text-white border border-white/5">RESET</button>
          </div>
        </div>
      </header>

      {activeAlarm && (
