           <div className="bg-red-600 border border-red-400 p-4 rounded-2xl shadow-2xl shadow-red-500/30 flex items-start space-x-4 max-w-md">
              <div className="p-2 bg-white/20 rounded-full">
                <Bell size={20} className="text-white animate-bounce" />
              </div>
              <div className="flex-1">
                <h4 className="text-sm font-black text-white uppercase tracking-tight">Industrial Alarm Triggered</h4>
                <p className="text-xs text-red-50 font-medium mt-1 leading-relaxed">
                  {activeAlarm.message}
                </p>
                <div className="mt-3 flex space-x-2">
                  <button onClick={resetMachine} className="px-3 py-1 bg-white text-red-600 text-[10px] font-black rounded-lg uppercase tracking-widest hover:bg-red-50 transition-colors">Halt System</button>
                  <button onClick={() => setActiveAlarm(null)} className="p-1 text-white hover:bg-white/10 rounded-lg"><X size={16} /></button>
                </div>
              </div>
           </div>
        </div>
      )}

      <main className="flex-1 relative overflow-hidden">
        <Dashboard 
          twinState={twinState} 
          history={history} 
          materials={MATERIALS} 
          toolGrades={TOOL_GRADES} 
          onConfigChange={handleConfigChange}
        />
      </main>
    </div>
  );
};

