import React, { useMemo } from 'react';
import { TelemetryData } from '../types';
import { Binary, TrendingDown, Target, Zap } from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

interface LSTMForecasterProps {
  history: TelemetryData[];
}

export const LSTMForecaster: React.FC<LSTMForecasterProps> = ({ history }) => {
  // Simple "LSTM-like" trend analysis projection
  const predictionData = useMemo(() => {
    if (history.length < 10) return [];

    const lastWear = history[history.length - 1].toolWear;
    const firstWear = history[Math.max(0, history.length - 20)].toolWear;
    const slope = (lastWear - firstWear) / 20;

    // Project next 20 points
    const projection = [];
    for (let i = 0; i < 20; i++) {
      projection.push({
        index: i,
        actual: i === 0 ? lastWear : null,
        projected: lastWear + (slope * i) + (Math.random() - 0.5) * 0.2,
        upperBound: lastWear + (slope * i) + (i * 0.1),
        lowerBound: lastWear + (slope * i) - (i * 0.1),
      });
    }
    return projection;
  }, [history]);

  const rul = useMemo(() => {
    if (history.length < 5) return 'CALIBRATING';
    const last = history[history.length - 1].toolWear;
    const delta = (last - history[0].toolWear) / history.length;
    if (delta <= 0) return 'NOMINAL';
    const remaining = (100 - last) / (delta * 60); // Hours approx
    return `${remaining.toFixed(1)}h`;
  }, [history]);

  return (
    <section className="bg-white/5 p-6 rounded-3xl border border-white/5 flex flex-col h-[350px]">
      <div className="flex items-center justify-between mb-6">
        <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center">
          <Binary size={16} className="mr-2 text-blue-500" /> AI LSTM Forecasting (Edge-Inference)
        </h3>
        <div className="flex space-x-3">
          <div className="flex flex-col items-end">
            <span className="text-[8px] font-black text-slate-500 uppercase">Model Reliability</span>
            <span className="text-[10px] font-black text-emerald-400 font-mono">94.2%</span>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-3 gap-4 mb-6">
        <div className="bg-black/20 p-3 rounded-2xl border border-white/5">
          <div className="flex items-center text-[8px] text-slate-500 uppercase font-black mb-1">
             <Target size={10} className="mr-1 text-blue-400" /> Predicted RUL
          </div>
          <div className="text-xl font-black text-white font-mono">{rul}</div>
        </div>
        <div className="bg-black/20 p-3 rounded-2xl border border-white/5">
          <div className="flex items-center text-[8px] text-slate-500 uppercase font-black mb-1">
             <TrendingDown size={10} className="mr-1 text-amber-400" /> Deg. Rate
          </div>
          <div className="text-xl font-black text-white font-mono">2.4%/hr</div>
        </div>
        <div className="bg-black/20 p-3 rounded-2xl border border-white/5">
          <div className="flex items-center text-[8px] text-slate-500 uppercase font-black mb-1">
             <Zap size={10} className="mr-1 text-purple-400" /> Model Latency
          </div>
          <div className="text-xl font-black text-white font-mono">12ms</div>
        </div>
      </div>

      <div className="flex-1 min-h-0">
        <ResponsiveContainer width="100%" height="100%">
          <AreaChart data={predictionData}>
            <defs>
              <linearGradient id="forecastColor" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor="#3b82f6" stopOpacity={0.3}/>
                <stop offset="95%" stopColor="#3b82f6" stopOpacity={0}/>
              </linearGradient>
            </defs>
            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#1e293b" />
            <XAxis dataKey="index" hide />
            <YAxis domain={['auto', 'auto']} hide />
            <Tooltip 
              contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #1e293b', fontSize: '10px' }}
            />
            <Area 
              type="monotone" 
              dataKey="projected" 
              stroke="#3b82f6" 
              fillOpacity={1} 
              fill="url(#forecastColor)" 
              strokeWidth={2}
              isAnimationActive={false}
              name="LSTM Projected Wear"
            />
          </AreaChart>
        </ResponsiveContainer>
      </div>
    </section>
  );
};

import React, { useMemo } from 'react';
import { TelemetryData, MachineHealth } from '../types';
import { History, ShieldCheck, AlertTriangle, PlayCircle, Clock } from 'lucide-react';

interface ProcessHistoryProps {
  history: TelemetryData[];
  health: MachineHealth;
  status: string;
}

export const ProcessHistory: React.FC<ProcessHistoryProps> = ({ history, health, status }) => {
  const events = useMemo(() => {
    // Generate some interesting log entries from history data
    return history.slice(-20).reverse().map((h, i) => {
      let type: 'INFO' | 'WARNING' | 'CRITICAL' = 'INFO';
      let message = `System telemetry recorded at ${Math.round(h.rpm)} RPM`;

      if (h.temperature > 80) {
        type = 'WARNING';
        message = `High thermal threshold detected: ${h.temperature.toFixed(1)}°C`;
      }
      if (h.toolWear > 60) {
        type = 'CRITICAL';
        message = `Critical Tool Wear Alert: ${h.toolWear.toFixed(1)}% reached`;
      }

      return {
        id: i,
        time: new Date(h.timestamp).toLocaleTimeString(),
        type,
        message,
        icon: type === 'CRITICAL' ? AlertTriangle : type === 'WARNING' ? AlertTriangle : ShieldCheck
      };
    });
  }, [history]);

  return (
    <div className="p-6 h-full flex flex-col space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <div className="bg-white/5 p-4 rounded-2xl border border-white/5 flex items-center space-x-4">
          <div className="p-2 bg-indigo-500/10 rounded-xl"><Clock className="text-indigo-400" size={18} /></div>
          <div>
            <div className="text-[8px] text-slate-500 font-black uppercase tracking-widest">Active Runtime</div>
            <div className="text-sm font-black text-white font-mono">124:42:10</div>
          </div>
        </div>
        <div className="bg-white/5 p-4 rounded-2xl border border-white/5 flex items-center space-x-4">
          <div className="p-2 bg-emerald-500/10 rounded-xl"><ShieldCheck className="text-emerald-400" size={18} /></div>
          <div>
            <div className="text-[8px] text-slate-500 font-black uppercase tracking-widest">MTBF Prediction</div>
            <div className="text-sm font-black text-white font-mono">1,240 hrs</div>
          </div>
        </div>
        <div className="bg-white/5 p-4 rounded-2xl border border-white/5 flex items-center space-x-4">
          <div className="p-2 bg-amber-500/10 rounded-xl"><PlayCircle className="text-amber-400" size={18} /></div>
          <div>
            <div className="text-[8px] text-slate-500 font-black uppercase tracking-widest">Cycle Status</div>
            <div className="text-sm font-black text-white font-mono uppercase tracking-tighter">{status}</div>
          </div>
        </div>
        <div className="bg-white/5 p-4 rounded-2xl border border-white/5 flex items-center space-x-4">
          <div className="p-2 bg-red-500/10 rounded-xl"><AlertTriangle className="text-red-400" size={18} /></div>
          <div>
            <div className="text-[8px] text-slate-500 font-black uppercase tracking-widest">Active Alerts</div>
            <div className="text-sm font-black text-white font-mono">{health === MachineHealth.HEALTHY ? '0' : '1'}</div>
          </div>
        </div>
      </div>

      <div className="flex-1 bg-white/5 rounded-3xl border border-white/5 overflow-hidden flex flex-col shadow-inner">
        <div className="px-6 py-4 bg-white/5 border-b border-white/5 flex items-center justify-between">
          <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center">
            <History size={16} className="mr-2 text-indigo-500" /> Production Log & Audit Trail
          </h3>
          <button className="text-[10px] font-black text-indigo-400 uppercase hover:text-indigo-300 transition-colors">Export CSV</button>
        </div>
        <div className="flex-1 overflow-y-auto p-4 space-y-2 scrollbar-hide">
          {events.map((event) => (
            <div key={event.id} className="group flex items-center justify-between p-3 bg-black/20 hover:bg-white/5 rounded-xl border border-white/5 transition-all">
              <div className="flex items-center space-x-4">
                <div className={`p-1.5 rounded-lg ${
                  event.type === 'CRITICAL' ? 'bg-red-500/10 text-red-400' :
                  event.type === 'WARNING' ? 'bg-amber-500/10 text-amber-400' :
                  'bg-indigo-500/10 text-indigo-400'
                }`}>
                  <event.icon size={14} />
                </div>
                <div>
                  <div className={`text-[10px] font-black tracking-tight ${
                    event.type === 'CRITICAL' ? 'text-red-400' :
                    event.type === 'WARNING' ? 'text-amber-400' :
                    'text-white'
                  }`}>
                    {event.message}
                  </div>
                  <div className="text-[8px] text-slate-500 font-bold uppercase">{event.time} • SYSLOG_ENTRY_{event.id}</div>
                </div>
              </div>
              <div className="text-[8px] text-slate-600 font-mono hidden group-hover:block transition-all">
                CRC_VALID: 0x4F2A
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

