import { GoogleGenAI, Type } from "@google/genai";
import { AIDiagnosticResponse } from "../types";

const wait = (ms: number) => new Promise(res => setTimeout(res, ms));

export async function getIndustrialInsights(machineState: any, retryCount = 0): Promise<AIDiagnosticResponse | null> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const systemInstruction = `
      Act as a Digital Twin AI model for a tool health monitoring system. 
      Your job is to analyze real-time sensor data coming from an IoT device and provide structured insights.

      🔧 Sensor Inputs Evaluation:
      - temperature (°C)
      - vibration (g)
      - rpm (rotations per minute)
      - forces (fx, fy, fz in Newtons)
      - toolWear (%)

      🧠 Your Task:
      1. Evaluate Health Status: "Healthy", "Warning", or "Critical".
      2. Detect Anomalies: overheating, abnormal vibration, unexpected rpm drop, force spikes, mechanical wear.
      3. Predict Future Behavior: Short forecast on failure risks or stress.
      4. Provide Recommendations: actions like reduce load, schedule maintenance, lubricate, or shut down.

      Context:
      - Workpiece: ${machineState.config.material.name} (Hardness factor: ${machineState.config.material.hardnessFactor})
      - Tool: ${machineState.config.toolGrade.name} (Durability: ${machineState.config.toolGrade.durabilityFactor})
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `Current Telemetry Data: ${JSON.stringify(machineState.telemetry)}`,
      config: {
        temperature: 0.2,
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            healthStatus: { type: Type.STRING, description: 'Healthy, Warning, or Critical' },
            anomaliesDetected: { type: Type.ARRAY, items: { type: Type.STRING } },
            prediction: { type: Type.STRING },
            recommendedActions: { type: Type.ARRAY, items: { type: Type.STRING } },
            summary: { type: Type.STRING }
          },
          required: ["healthStatus", "anomaliesDetected", "prediction", "recommendedActions", "summary"]
        }
      }
    });

    const result = JSON.parse(response.text || '{}');
    return result as AIDiagnosticResponse;
  } catch (error: any) {
    console.error("Gemini Insight Error:", error);

    const isRateLimited = error?.message?.includes('429') || error?.status === 429 || error?.message?.includes('RESOURCE_EXHAUSTED');
    if (isRateLimited && retryCount < 2) {
      await wait(Math.pow(2, retryCount) * 2000);
      return getIndustrialInsights(machineState, retryCount + 1);
    }
    return null;
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { TwinState, MachineHealth, AIDiagnosticResponse } from '../types';
import { getIndustrialInsights } from '../services/geminiService';
import { BrainCircuit, Loader2, RefreshCw, ShieldCheck, AlertTriangle, ListChecks, History } from 'lucide-react';

interface AIInsightsProps {
  twinState: TwinState;
}

export const AIInsights: React.FC<AIInsightsProps> = ({ twinState }) => {
  const [insight, setInsight] = useState<AIDiagnosticResponse | null>(null);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const lastRequestTime = useRef<number>(0);

  const fetchInsight = async (force = false) => {
    const now = Date.now();
    if (!force && now - lastRequestTime.current < 15000) return;

    if (twinState.status !== 'RUNNING' && twinState.health === MachineHealth.HEALTHY && !force) {
      setLoading(false);
      return;
    }

    setLoading(true);
    setError(null);
    lastRequestTime.current = now;

    try {
      const data = await getIndustrialInsights(twinState);
      if (data) {
        setInsight(data);
      } else {
        setError("Edge diagnostic mode active. LLM link deferred.");
      }
    } catch (e) {
      setError("Analysis unavailable.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchInsight();
    const interval = setInterval(() => fetchInsight(), 90000);
    return () => clearInterval(interval);
  }, [twinState.status, twinState.health]);

  return (
    <div className="bg-slate-900/50 border border-indigo-500/20 rounded-3xl p-6 relative overflow-hidden backdrop-blur-xl">
      <div className="absolute top-0 right-0 p-4 opacity-5 pointer-events-none">
        <BrainCircuit size={120} className="text-indigo-400" />
      </div>

      <div className="flex items-center justify-between mb-6">
        <div className="flex items-center space-x-3">
          <div className="p-2 bg-indigo-500/10 rounded-xl">
            <BrainCircuit size={20} className="text-indigo-400" />
          </div>
          <div>
            <h3 className="text-xs font-black text-white uppercase tracking-[0.2em]">Digital Twin AI Diagnostics</h3>
            <p className="text-[8px] text-slate-500 font-bold uppercase tracking-widest">GEMINI 3 PRO EDGE-LINK</p>
          </div>
        </div>
        <button 
          onClick={() => fetchInsight(true)}
          disabled={loading}
          className="p-2 hover:bg-white/5 rounded-xl transition-all text-slate-400 group"
          title="Manual Refresh"
        >
          <RefreshCw size={16} className={`${loading ? 'animate-spin' : 'group-hover:rotate-180 transition-transform duration-500'}`} />
        </button>
      </div>

      {loading ? (
        <div className="flex flex-col items-center justify-center py-10 space-y-4">
          <Loader2 size={32} className="animate-spin text-indigo-500/50" />
          <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest animate-pulse">Processing Multi-Vector Telemetry...</span>
        </div>
      ) : error ? (
        <div className="text-center py-10 text-[10px] font-bold text-slate-500 uppercase tracking-widest">
          {error}
        </div>
      ) : insight ? (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2 duration-500">
          <div className="grid grid-cols-2 gap-4">
            <div className="bg-black/20 p-3 rounded-2xl border border-white/5">
              <div className="flex items-center text-[8px] text-slate-500 uppercase font-black mb-1">
                <ShieldCheck size={10} className="mr-1 text-emerald-400" /> AI Health Status
              </div>
              <div className={`text-sm font-black uppercase font-mono ${
                insight.healthStatus === 'Critical' ? 'text-red-400' :
                insight.healthStatus === 'Warning' ? 'text-amber-400' : 'text-emerald-400'
              }`}>{insight.healthStatus}</div>
            </div>
            <div className="bg-black/20 p-3 rounded-2xl border border-white/5">
              <div className="flex items-center text-[8px] text-slate-500 uppercase font-black mb-1">
                <AlertTriangle size={10} className="mr-1 text-amber-400" /> Anomalies
              </div>
              <div className="text-sm font-black text-white font-mono">{insight.anomaliesDetected.length} Detected</div>
            </div>
          </div>

          <div className="space-y-4">
            <div>
              <h4 className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-2 flex items-center">
                <History size={12} className="mr-2 text-indigo-400" /> Behavioral Forecast
              </h4>
              <p className="text-[11px] text-slate-300 font-medium leading-relaxed bg-indigo-500/5 p-3 rounded-xl border border-indigo-500/10 italic">
                "{insight.prediction}"
              </p>
            </div>

            <div>
              <h4 className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-2 flex items-center">
                <ListChecks size={12} className="mr-2 text-indigo-400" /> Recommended Interventions
              </h4>
              <div className="grid grid-cols-1 gap-2">
                {insight.recommendedActions.map((action, i) => (
                  <div key={i} className="flex items-center space-x-2 text-[10px] text-slate-400 font-bold uppercase bg-white/5 p-2 rounded-lg border border-white/5">
                    <div className="w-1.5 h-1.5 rounded-full bg-indigo-500"></div>
                    <span>{action}</span>
