  model: 'Acu-Drill Pro 5000 Edge',
  health: MachineHealth.HEALTHY,
  status: 'IDLE',
  mode: 'SIMULATED',
  mqttStatus: 'DISCONNECTED',
  cloudSync: 'OFFLINE',
  lastCommandSent: null,
  telemetry: INITIAL_TELEMETRY,
  materialTest: {
    isActive: false,
    durationSeconds: 30,
    targetWear: 95,
    startTime: null,
    scenario: 'NORMAL'
  },
  config: {
    material: MATERIALS[0],
    toolGrade: TOOL_GRADES[1],
    thingSpeakKey: '',
    mqttBroker: 'wss://broker.emqx.io:8084/mqtt',
    telemetryTopic: 'cnc/telemetry',
    commandTopic: 'cnc/control',
    wifiSsid: '',
    wifiPassword: '',
    espIp: '192.168.1.100',
    espPort: '80'
  },
  predictions: {
    rul: 425.5,
    failureProbability: 0.02,
    nextMaintenanceDate: '2025-01-20',
    anomalyDetected: false
  }
};

interface Alarm {
  type: 'CRITICAL' | 'WARNING';
  category: 'THERMAL' | 'VIBRATION' | 'WEAR' | 'SYSTEM';
  message: string;
  recommendations: string[];
}

const App: React.FC = () => {
  const [twinState, setTwinState] = useState<TwinState>(INITIAL_STATE);
  const [history, setHistory] = useState<TelemetryData[]>([]);
  const [activeAlarm, setActiveAlarm] = useState<Alarm | null>(null);
  const stateRef = useRef<TwinState>(INITIAL_STATE);
  const mqttClientRef = useRef<any>(null);
  const lastCloudSyncRef = useRef<number>(0);

  // Request notification permissions on mount
  useEffect(() => {
    if ("Notification" in window) {
      Notification.requestPermission();
    }
  }, []);

  const handleConfigChange = useCallback((cfg: any) => {
    setTwinState(s => {
      const newState = { ...s };

      if (cfg.materialTest) {
        newState.materialTest = { ...s.materialTest, ...cfg.materialTest };
      }

      if (cfg.material || cfg.toolGrade || cfg.hasOwnProperty('thingSpeakKey') || cfg.mqttBroker || 
          cfg.telemetryTopic || cfg.commandTopic || cfg.wifiSsid || cfg.wifiPassword || 
          cfg.espIp || cfg.espPort) {
        newState.config = { ...s.config, ...cfg };
      }

      stateRef.current = newState;
      return newState;
    });
  }, []);

  const syncToThingSpeak = useCallback(async (telemetry: TelemetryData, key: string) => {
    if (!key || key.trim() === '' || key === 'YOUR_KEY_HERE') {
      if (twinState.cloudSync !== 'OFFLINE') {
        setTwinState(s => ({ ...s, cloudSync: 'OFFLINE' }));
      }
      return;
    }

    const now = Date.now();
    if (now - lastCloudSyncRef.current < 15500) return;

    lastCloudSyncRef.current = now;
    setTwinState(s => ({ ...s, cloudSync: 'SYNCING' }));

    try {
      const baseUrl = 'https://api.thingspeak.com/update';
      const params = new URLSearchParams({
        api_key: key,
        field1: telemetry.rpm.toString(),
        field2: telemetry.temperature.toString(),
        field3: telemetry.toolWear.toString(),
        field4: telemetry.vibration.toString(),
        field5: telemetry.forces.fz.toString()
      });

      const response = await fetch(`${baseUrl}?${params.toString()}`);
      if (response.ok) {
        setTwinState(s => ({ ...s, cloudSync: 'SYNCED' }));
      } else {
        setTwinState(s => ({ ...s, cloudSync: 'ERROR' }));
      }
    } catch (e) {
      console.error("ThingSpeak Cloud Error:", e);
      setTwinState(s => ({ ...s, cloudSync: 'ERROR' }));
    }
  }, [twinState.cloudSync]);

  const runAIInference = (currentHistory: TelemetryData[]) => {
    if (currentHistory.length < 5) return stateRef.current.predictions;
    const recentWear = currentHistory.slice(-10).map(h => h.toolWear || 0);
    const recentTemp = currentHistory.slice(-10).map(h => h.temperature || 24);
    const wearTrend = (recentWear[recentWear.length - 1] - (recentWear[0] || 0)) / 10;
    const avgTemp = recentTemp.reduce((a, b) => a + b, 0) / recentTemp.length;
    const estimatedLife = 500 / (wearTrend > 0 ? wearTrend * 1000 : 0.001);
    const adjustedRul = Math.max(0, estimatedLife * (1 - (avgTemp / 200)));
    return {
      rul: adjustedRul,
      failureProbability: avgTemp > 95 ? 0.95 : avgTemp > 80 ? 0.45 : 0.02,
      nextMaintenanceDate: adjustedRul < 50 ? 'IMMEDIATE' : '2025-02-15',
      anomalyDetected: avgTemp > 110 || wearTrend > 0.5
    };
  };

  const sendHardwareCommand = useCallback(async (action: string, value?: string) => {
    const { espIp, espPort } = stateRef.current.config;
    if (!espIp) return;

    const url = `http://${espIp}:${espPort}/control?action=${action}${value ? `&value=${value}` : ''}`;
    try {
      setTwinState(s => ({ ...s, lastCommandSent: `UPLINK [FETCH]: ${action}${value ? `=${value}` : ''}` }));
      await fetch(url, { mode: 'no-cors' }); 
    } catch (error) {
      setTwinState(s => ({ ...s, lastCommandSent: 'UPLINK ERROR: TARGET UNREACHABLE' }));
    }
  }, []);

  const resetMachine = useCallback(() => {
    setActiveAlarm(null);
    if (stateRef.current.mode === 'SIMULATED') {
      setTwinState(prev => ({ 
        ...prev, 
        status: 'IDLE', 
        health: MachineHealth.HEALTHY,
        telemetry: { ...prev.telemetry, temperature: 24, toolWear: 0, rpm: 0, vibration: 0.1 },
        materialTest: { ...prev.materialTest, isActive: false, startTime: null }
      }));
    } else {
      sendHardwareCommand('RESET_SYSTEM');
    }
  }, [sendHardwareCommand]);

  useEffect(() => {
    if (twinState.mode === 'MQTT_LIVE') {
      try {
        const client = mqtt.connect(twinState.config.mqttBroker);
        mqttClientRef.current = client;
        client.on('connect', () => {
          setTwinState(s => ({ ...s, mqttStatus: 'CONNECTED' }));
          client.subscribe(stateRef.current.config.telemetryTopic);
        });
        client.on('message', (topic, message) => {
          if (topic === stateRef.current.config.telemetryTopic) {
            try {
              const payload = JSON.parse(message.toString());
              setTwinState(s => {
                const updatedTelemetry = { ...s.telemetry, ...payload, timestamp: Date.now() };
                syncToThingSpeak(updatedTelemetry, s.config.thingSpeakKey);
                return {
                  ...s,
                  status: payload.status || s.status,
                  telemetry: updatedTelemetry
                };
              });
            } catch (e) {}
          }
        });
        client.on('error', () => setTwinState(s => ({ ...s, mqttStatus: 'DISCONNECTED' })));
        client.on('close', () => setTwinState(s => ({ ...s, mqttStatus: 'DISCONNECTED' })));
      } catch (e) {}
    } else {
      if (mqttClientRef.current) {
        mqttClientRef.current.end();
        mqttClientRef.current = null;
      }
      setTwinState(s => ({ ...s, mqttStatus: 'DISCONNECTED' }));
    }
    return () => { if (mqttClientRef.current) mqttClientRef.current.end(); };
  }, [twinState.mode, twinState.config.mqttBroker, syncToThingSpeak, twinState.config.telemetryTopic]);

  useEffect(() => {
    const interval = setInterval(() => {
      let nextTele: TelemetryData | null = null;
      let currentKey: string = '';

      setTwinState(prev => {
        if (prev.mode !== 'SIMULATED') return prev; 

        let isRunning = prev.status === 'RUNNING';
        let currentStatus = prev.status;
        let testActive = prev.materialTest.isActive;
        const scenario = prev.materialTest.scenario || 'NORMAL';
        const targetWear = prev.materialTest.targetWear;
        currentKey = prev.config.thingSpeakKey;

        const { material, toolGrade } = prev.config;
        const loadMod = material.hardnessFactor || 1;

        let wearMultiplier = testActive ? 8 : 1; 
        let heatMultiplier = 1;
        let forceMultiplier = 1;

        if (testActive) {
          switch(scenario) {
            case 'AGGRESSIVE': wearMultiplier *= 3.0; forceMultiplier = 2.2; break;
            case 'THERMAL': heatMultiplier = 3.5; wearMultiplier *= 1.5; break;
            case 'IMPACT': wearMultiplier *= 6.0; forceMultiplier = 3.5; break;
          }
        }

        const heatMod = ((loadMod / (material.thermalFactor || 1)) / (toolGrade.heatResistance || 1)) * heatMultiplier;
        const wearMod = (loadMod / (toolGrade.durabilityFactor || 1)) * (isRunning ? 0.0008 : 0) * wearMultiplier;
        const noise = (val: number, range: number) => val + (Math.random() - 0.5) * range;
        const cycleSec = (Date.now() / 1000) % 4;
        const isCutting = isRunning && cycleSec > 0.5 && cycleSec < 3.0;
        const baseForce = isCutting ? 180 * loadMod * forceMultiplier : 0;
        const baseCurrent = isRunning ? (2.0 + (prev.telemetry.spindleLoad / 20)) : 0;

        nextTele = {
          timestamp: Date.now(),
          rpm: isRunning ? noise(3200, 50) : 0,
          feedRate: isRunning ? noise(450, 20) : 0,
          spindleLoad: isRunning ? noise(42 * loadMod * forceMultiplier, 10) : 0,
          vibration: isRunning ? noise(1.4 * loadMod * forceMultiplier, 0.4) : noise(0.05, 0.02),
          temperature: isRunning 
            ? Math.min(135, prev.telemetry.temperature + (1.2 * heatMod)) 
            : Math.max(24, prev.telemetry.temperature - 0.5),
          toolWear: Math.min(100, prev.telemetry.toolWear + wearMod),
          current: isRunning ? noise(baseCurrent, 0.2) : 0,
          noiseLevel: isRunning ? noise(75 + (wearMod * 1000), 5) : 35,
          powerConsumption: isRunning ? noise(4.8 * loadMod * forceMultiplier, 0.8) : 0.2,
          forces: {
            fx: isCutting ? noise(baseForce * 0.1, 10) : noise(0, 1),
            fy: isCutting ? noise(baseForce * 0.1, 10) : noise(0, 1),
            fz: isCutting ? noise(baseForce * 1.6, 40) : noise(0, 2)
          }
        };

        // Comprehensive failure detection
        if (isRunning && !activeAlarm) {
          let alarm: Alarm | null = null;

          if (nextTele.toolWear >= targetWear) {
            alarm = {
              type: 'CRITICAL',
              category: 'WEAR',
              message: `GEOMETRIC FAILURE DETECTED: Tool wear exceeded ${targetWear}% threshold.`,
              recommendations: ["Perform immediate tool change", "Verify workpiece surface integrity", "Check feedrate compensation logic"]
            };
          } else if (nextTele.temperature > 110) {
            alarm = {
              type: 'CRITICAL',
              category: 'THERMAL',
              message: `THERMAL RUNAWAY: Spindle temperature reached ${nextTele.temperature.toFixed(1)}°C.`,
              recommendations: ["Activate auxiliary cooling", "Reduce spindle load immediately", "Check coolant flow rate"]
            };
          } else if (nextTele.vibration > 6.0) {
            alarm = {
              type: 'CRITICAL',
              category: 'VIBRATION',
              message: `STRUCTURAL RESONANCE: Extreme vibration levels (${nextTele.vibration.toFixed(2)}g) detected.`,
              recommendations: ["Stop spindle to prevent bearing damage", "Inspect tool seating and alignment", "Verify fixture stability"]
            };
          }

          if (alarm) {
            setActiveAlarm(alarm);
            isRunning = false;
            currentStatus = 'IDLE';
            testActive = false;
          }
        }

        let health = MachineHealth.HEALTHY;
        if (nextTele.temperature > 85 || nextTele.toolWear > targetWear * 0.8 || nextTele.vibration > 3.0) health = MachineHealth.WARNING;
        if (nextTele.temperature > 105 || nextTele.toolWear >= targetWear || nextTele.vibration > 5.0) health = MachineHealth.CRITICAL;

        const newState = {
          ...prev,
          status: currentStatus,
          health,
          telemetry: nextTele,
          materialTest: { ...prev.materialTest, isActive: testActive },
          predictions: runAIInference(history)
        };
        stateRef.current = newState;
        return newState;
      });

      if (nextTele) {
        syncToThingSpeak(nextTele, currentKey);
        setHistory(prev => {
          const newHist = [...prev, nextTele as TelemetryData];
          return newHist.slice(-50);
        });
      }
    }, MACHINE_CONFIG.POLLING_INTERVAL_MS);
    return () => clearInterval(interval);
  }, [history, activeAlarm, syncToThingSpeak]);

  const toggleMachine = useCallback(() => {
    const nextStatus = twinState.status === 'RUNNING' ? 'IDLE' : 'RUNNING';
    if (twinState.mode === 'SIMULATED') {
      setTwinState(prev => ({ ...prev, status: nextStatus }));
    } else {
      sendHardwareCommand('SET_STATUS', nextStatus);
    }
  }, [twinState.status, twinState.mode, sendHardwareCommand]);

  return (
    <div className="w-full h-full bg-[#020617] flex flex-col overflow-hidden">
      <header className="px-6 py-4 bg-slate-900/50 backdrop-blur-xl border-b border-white/5 flex justify-between items-center z-50">
        <div className="flex items-center space-x-4">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <Wifi className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-xl font-black text-white tracking-tighter uppercase italic">Twin<span className="text-indigo-400">Core</span></h1>
            <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Digital Force Twin</span>
          </div>
        </div>
        <div className="flex items-center space-x-4">
          <div className="flex bg-black/40 p-1 rounded-lg border border-white/5">
            {['SIMULATED', 'MQTT_LIVE', 'WIFI_LIVE'].map(m => (
              <button 
                key={m}
                onClick={() => setTwinState(s => ({ ...s, mode: m as any }))}
                className={`px-4 py-1.5 rounded-md text-[10px] font-black tracking-widest uppercase transition-all ${twinState.mode === m ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-white'}`}
              >
                {m.split('_')[0]}
              </button>
            ))}
          </div>
          <div className="flex space-x-2">
             <button onClick={toggleMachine} className={`px-6 py-2 rounded-lg font-black text-[11px] uppercase tracking-wider transition-all shadow-lg ${twinState.status === 'RUNNING' ? 'bg-red-500 shadow-red-500/20' : 'bg-emerald-500 shadow-emerald-500/20'} text-white`}>{twinState.status === 'RUNNING' ? 'STOP' : 'START'}</button>
             <button onClick={resetMachine} className="px-6 py-2 bg-slate-800 hover:bg-slate-700 rounded-lg font-black text-[11px] uppercase tracking-wider text-white border border-white/5">RESET</button>
          </div>
        </div>
      </header>

      {/* SYSTEM-WIDE ALARM NOTIFICATION OVERLAY */}
      {activeAlarm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 pointer-events-none">
          <div className="w-full max-w-xl bg-[#0f172a] border-2 border-red-500/50 rounded-[2rem] shadow-[0_0_50px_rgba(239,68,68,0.3)] overflow-hidden animate-in zoom-in-95 duration-300 pointer-events-auto">
            <div className="bg-red-600 p-6 flex items-center justify-between">
              <div className="flex items-center space-x-4">
                <div className="bg-white/20 p-2 rounded-xl">
                  <ShieldAlert size={28} className="text-white animate-pulse" />
                </div>
                <div>
                  <h2 className="text-xl font-black text-white uppercase tracking-tight">Industrial Safety Halt</h2>
                  <p className="text-xs text-red-100 font-bold uppercase tracking-widest">Alarm ID: ERR_{activeAlarm.category}_{Date.now().toString().slice(-4)}</p>
                </div>
              </div>
              <button onClick={() => setActiveAlarm(null)} className="p-2 text-white/50 hover:text-white transition-colors">
                <X size={24} />
              </button>
            </div>

            <div className="p-8 space-y-8">
              <div className="flex items-start space-x-6">
                <div className="p-4 bg-red-500/10 rounded-2xl border border-red-500/20">
                   {activeAlarm.category === 'THERMAL' && <Thermometer size={32} className="text-red-500" />}
                   {activeAlarm.category === 'VIBRATION' && <Zap size={32} className="text-red-500" />}
                   {activeAlarm.category === 'WEAR' && <Wrench size={32} className="text-red-500" />}
                   {activeAlarm.category === 'SYSTEM' && <ShieldAlert size={32} className="text-red-500" />}
                </div>
                <div className="flex-1">
                  <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Failure Signature</div>
                  <p className="text-lg font-bold text-white leading-tight">{activeAlarm.message}</p>
                </div>
              </div>

              <div className="space-y-4">
                 <div className="text-[10px] font-black text-red-400 uppercase tracking-widest flex items-center">
                    <AlertCircle size={14} className="mr-2" /> Immediate Countermeasures Required
                 </div>
                 <div className="grid grid-cols-1 gap-3">
                   {activeAlarm.recommendations.map((rec, i) => (
                     <div key={i} className="flex items-center space-x-3 bg-red-500/5 border border-red-500/10 p-3 rounded-xl">
                        <div className="w-2 h-2 rounded-full bg-red-500"></div>
                        <span className="text-xs text-slate-300 font-medium">{rec}</span>
                     </div>
                   ))}
                 </div>
              </div>

              <div className="flex space-x-4 pt-4">
                <button 
                  onClick={resetMachine}
                  className="flex-1 bg-red-600 hover:bg-red-500 text-white font-black py-4 rounded-2xl uppercase tracking-[0.2em] text-sm transition-all shadow-lg shadow-red-900/20"
                >
                  Confirm Halt & Reset
                </button>
                <button 
                  onClick={() => setActiveAlarm(null)}
                  className="px-8 border border-white/10 hover:bg-white/5 text-slate-400 font-black rounded-2xl uppercase tracking-[0.2em] text-[10px] transition-all"
                >
                  Acknowledge
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      <main className="flex-1 relative overflow-hidden">
        <Dashboard 
          twinState={twinState} 
          history={history} 
          materials={MATERIALS} 
          toolGrades={TOOL_GRADES} 
          onConfigChange={handleConfigChange}
        />
      </main>
    </div>
  );
};

export default App;

export enum MachineHealth {
  HEALTHY = 'HEALTHY',
  WARNING = 'WARNING',
  CRITICAL = 'CRITICAL'
}

export interface Material {
  id: string;
  name: string;
  hardnessFactor: number;
  thermalFactor: number;
}

export interface ToolGrade {
  id: string;
  name: string;
  durabilityFactor: number;
  heatResistance: number;
}

export interface TelemetryData {
  timestamp: number;
  rpm: number;
  feedRate: number;
  spindleLoad: number;
  vibration: number;
  temperature: number;
  toolWear: number;
  current: number;
  noiseLevel: number;
  powerConsumption: number;
  forces: {
    fx: number;
    fy: number;
    fz: number;
  };
}

export interface AIDiagnosticResponse {
  healthStatus: string;
  anomaliesDetected: string[];
  prediction: string;
  recommendedActions: string[];
  summary: string;
}

export interface MaterialTest {
  isActive: boolean;
  durationSeconds: number;
  targetWear: number;
  startTime: number | null;
  scenario?: 'NORMAL' | 'AGGRESSIVE' | 'THERMAL' | 'IMPACT';
  testTitle?: string;
  researcherName?: string;
  batchId?: string;
  hypothesis?: string;
}

export interface TwinState {
  id: string;
  name: string;
  model: string;
  health: MachineHealth;
  status: 'IDLE' | 'RUNNING' | 'ERROR' | 'MAINTENANCE';
  mode: 'SIMULATED' | 'MQTT_LIVE' | 'WIFI_LIVE';
  mqttStatus: 'CONNECTED' | 'DISCONNECTED' | 'CONNECTING';
  cloudSync: 'SYNCED' | 'SYNCING' | 'ERROR' | 'OFFLINE';
  lastSyncTimestamp?: number;
  lastCommandSent: string | null;
  telemetry: TelemetryData;
  materialTest: MaterialTest;
  config: {
    material: Material;
    toolGrade: ToolGrade;
    thingSpeakKey: string;
    mqttBroker: string;
    telemetryTopic: string;
    commandTopic: string;
    wifiSsid: string;
    wifiPassword: string;
    espIp: string;
    espPort: string;
  };
  predictions: {
    rul: number;
    failureProbability: number;
    nextMaintenanceDate: string;
    anomalyDetected: boolean;
  };
}

export interface ChartDataPoint {
  time: string;
  value: number;
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Dashboard } from './components/Dashboard';
import { TelemetryData, TwinState, MachineHealth, Material, ToolGrade } from './types';
import { MACHINE_CONFIG } from './constants';
import mqtt from 'mqtt';
import { Wifi, Shield, Globe, Cpu, ChevronUp, Link, Settings, AlertCircle, Bell, X, ShieldAlert, Zap, Thermometer, Wrench } from 'lucide-react';

const MATERIALS: Material[] = [
  { id: 'al6061', name: 'Aluminum 6061', hardnessFactor: 0.7, thermalFactor: 1.5 },
  { id: 'st1045', name: 'Steel AISI 1045', hardnessFactor: 1.2, thermalFactor: 0.9 },
  { id: 'ti64', name: 'Titanium Ti-6Al-4V', hardnessFactor: 2.2, thermalFactor: 0.4 },
  { id: 'in718', name: 'Inconel 718', hardnessFactor: 3.5, thermalFactor: 0.2 },
];

const TOOL_GRADES: ToolGrade[] = [
  { id: 'hss', name: 'HSS (Standard)', durabilityFactor: 0.5, heatResistance: 0.6 },
  { id: 'carbide', name: 'Carbide (Micrograin)', durabilityFactor: 2.5, heatResistance: 2.0 },
  { id: 'cobalt', name: 'Cobalt (M42)', durabilityFactor: 1.5, heatResistance: 1.5 },
  { id: 'pcd', name: 'PCD Diamond', durabilityFactor: 5.0, heatResistance: 3.0 },
];

const INITIAL_TELEMETRY: TelemetryData = {
  timestamp: Date.now(),
  rpm: 0,
  feedRate: 0,
  spindleLoad: 0,
  vibration: 0.1,
  temperature: 24,
  toolWear: 5,
  current: 0,
  noiseLevel: 30,
  powerConsumption: 0.5,
  forces: { fx: 0, fy: 0, fz: 0 }
};

const INITIAL_STATE: TwinState = {
  id: 'CNC-PRO-G3-001',
  name: 'Smart Factory Alpha - Unit 01',
  model: 'Acu-Drill Pro 5000 Edge',
  health: MachineHealth.HEALTHY,
  status: 'IDLE',
  mode: 'SIMULATED',
  mqttStatus: 'DISCONNECTED',
  cloudSync: 'OFFLINE',
  lastCommandSent: null,
  telemetry: INITIAL_TELEMETRY,
  materialTest: {
    isActive: false,
    durationSeconds: 30,
    targetWear: 95,
    startTime: null,
    scenario: 'NORMAL'
  },
  config: {
    material: MATERIALS[0],
    toolGrade: TOOL_GRADES[1],
    thingSpeakKey: '',
    mqttBroker: 'wss://broker.emqx.io:8084/mqtt',
    telemetryTopic: 'cnc/telemetry',
    commandTopic: 'cnc/control',
    wifiSsid: '',
    wifiPassword: '',
    espIp: '192.168.1.100',
    espPort: '80'
  },
  predictions: {
    rul: 425.5,
    failureProbability: 0.02,
    nextMaintenanceDate: '2025-01-20',
    anomalyDetected: false
  }
};

interface Alarm {
  type: 'CRITICAL' | 'WARNING';
  category: 'THERMAL' | 'VIBRATION' | 'WEAR' | 'SYSTEM';
  message: string;
  recommendations: string[];
}

const App: React.FC = () => {
  const [twinState, setTwinState] = useState<TwinState>(INITIAL_STATE);
  const [history, setHistory] = useState<TelemetryData[]>([]);
  const [activeAlarm, setActiveAlarm] = useState<Alarm | null>(null);
  const stateRef = useRef<TwinState>(INITIAL_STATE);
  const mqttClientRef = useRef<any>(null);
  const lastCloudSyncRef = useRef<number>(0);

  // Request notification permissions on mount
  useEffect(() => {
    if ("Notification" in window) {
      Notification.requestPermission();
    }
  }, []);

  const handleConfigChange = useCallback((cfg: any) => {
    setTwinState(s => {
      const newState = { ...s };
      if (cfg.materialTest) {
        newState.materialTest = { ...s.materialTest, ...cfg.materialTest };
      }
      if (cfg.material || cfg.toolGrade || cfg.hasOwnProperty('thingSpeakKey') || cfg.mqttBroker || 
          cfg.telemetryTopic || cfg.commandTopic || cfg.wifiSsid || cfg.wifiPassword || 
          cfg.espIp || cfg.espPort) {
        newState.config = { ...s.config, ...cfg };
      }
      stateRef.current = newState;
      return newState;
    });
  }, []);

  const syncToThingSpeak = useCallback(async (telemetry: TelemetryData, key: string) => {
    if (!key || key.trim() === '') {
      return;
    }

    const now = Date.now();
    // ThingSpeak free tier limit is 15 seconds
    if (now - lastCloudSyncRef.current < 16000) return;

    lastCloudSyncRef.current = now;
    setTwinState(s => ({ ...s, cloudSync: 'SYNCING' }));

    try {
      const baseUrl = 'https://api.thingspeak.com/update';
      const params = new URLSearchParams({
        api_key: key,
        field1: Math.round(telemetry.rpm).toString(),
        field2: telemetry.temperature.toFixed(2),
        field3: telemetry.toolWear.toFixed(2),
        field4: telemetry.vibration.toFixed(3),
        field5: Math.round(telemetry.forces.fz).toString()
      });

      const response = await fetch(`${baseUrl}?${params.toString()}`);
      if (response.ok) {
        setTwinState(s => ({ ...s, cloudSync: 'SYNCED', lastSyncTimestamp: now }));
      } else {
        setTwinState(s => ({ ...s, cloudSync: 'ERROR' }));
      }
    } catch (e) {
      console.error("ThingSpeak Cloud Error:", e);
      setTwinState(s => ({ ...s, cloudSync: 'ERROR' }));
    }
  }, []);

  // Dedicated Observer for Cloud Syncing
  useEffect(() => {
    const { telemetry, config, status } = twinState;
    if (status === 'RUNNING' || twinState.mode !== 'SIMULATED') {
      syncToThingSpeak(telemetry, config.thingSpeakKey);
    }
  }, [twinState.telemetry, twinState.config.thingSpeakKey, syncToThingSpeak]);

  const sendHardwareCommand = useCallback(async (action: string, value?: string) => {
    const { espIp, espPort } = stateRef.current.config;
    if (!espIp) return;
    const url = `http://${espIp}:${espPort}/control?action=${action}${value ? `&value=${value}` : ''}`;
    try {
      setTwinState(s => ({ ...s, lastCommandSent: `UPLINK [FETCH]: ${action}${value ? `=${value}` : ''}` }));
      await fetch(url, { mode: 'no-cors' }); 
    } catch (error) {
      setTwinState(s => ({ ...s, lastCommandSent: 'UPLINK ERROR: TARGET UNREACHABLE' }));
    }
  }, []);

  const resetMachine = useCallback(() => {
    setActiveAlarm(null);
    if (stateRef.current.mode === 'SIMULATED') {
      setTwinState(prev => ({ 
        ...prev, 
        status: 'IDLE', 
        health: MachineHealth.HEALTHY,
        telemetry: { ...prev.telemetry, temperature: 24, toolWear: 0, rpm: 0, vibration: 0.1 },
        materialTest: { ...prev.materialTest, isActive: false, startTime: null }
      }));
    } else {
      sendHardwareCommand('RESET_SYSTEM');
    }
  }, [sendHardwareCommand]);

  useEffect(() => {
    if (twinState.mode === 'MQTT_LIVE') {
      try {
        const client = mqtt.connect(twinState.config.mqttBroker);
        mqttClientRef.current = client;
        client.on('connect', () => {
          setTwinState(s => ({ ...s, mqttStatus: 'CONNECTED' }));
          client.subscribe(stateRef.current.config.telemetryTopic);
        });
        client.on('message', (topic, message) => {
          if (topic === stateRef.current.config.telemetryTopic) {
            try {
              const payload = JSON.parse(message.toString());
              setTwinState(s => ({
                ...s,
                status: payload.status || s.status,
                telemetry: { ...s.telemetry, ...payload, timestamp: Date.now() }
              }));
            } catch (e) {}
          }
        });
        client.on('error', () => setTwinState(s => ({ ...s, mqttStatus: 'DISCONNECTED' })));
        client.on('close', () => setTwinState(s => ({ ...s, mqttStatus: 'DISCONNECTED' })));
      } catch (e) {}
    } else {
      if (mqttClientRef.current) mqttClientRef.current.end();
      setTwinState(s => ({ ...s, mqttStatus: 'DISCONNECTED' }));
    }
    return () => { if (mqttClientRef.current) mqttClientRef.current.end(); };
  }, [twinState.mode, twinState.config.mqttBroker, twinState.config.telemetryTopic]);

  useEffect(() => {
    const interval = setInterval(() => {
      let nextTele: TelemetryData | null = null;
      setTwinState(prev => {
        if (prev.mode !== 'SIMULATED') return prev; 
        let isRunning = prev.status === 'RUNNING';
        let currentStatus = prev.status;
        let testActive = prev.materialTest.isActive;
        const scenario = prev.materialTest.scenario || 'NORMAL';
        const targetWear = prev.materialTest.targetWear;
        const { material, toolGrade } = prev.config;
        const loadMod = material.hardnessFactor || 1;
        let wearMultiplier = testActive ? 8 : 1; 
        let heatMultiplier = 1;
        let forceMultiplier = 1;
        if (testActive) {
          switch(scenario) {
            case 'AGGRESSIVE': wearMultiplier *= 3.0; forceMultiplier = 2.2; break;
            case 'THERMAL': heatMultiplier = 3.5; wearMultiplier *= 1.5; break;
            case 'IMPACT': wearMultiplier *= 6.0; forceMultiplier = 3.5; break;
          }
        }
        const heatMod = ((loadMod / (material.thermalFactor || 1)) / (toolGrade.heatResistance || 1)) * heatMultiplier;
        const wearMod = (loadMod / (toolGrade.durabilityFactor || 1)) * (isRunning ? 0.0008 : 0) * wearMultiplier;
        const noise = (val: number, range: number) => val + (Math.random() - 0.5) * range;
        const cycleSec = (Date.now() / 1000) % 4;
        const isCutting = isRunning && cycleSec > 0.5 && cycleSec < 3.0;
        const baseForce = isCutting ? 180 * loadMod * forceMultiplier : 0;
        const baseCurrent = isRunning ? (2.0 + (prev.telemetry.spindleLoad / 20)) : 0;
        nextTele = {
          timestamp: Date.now(),
          rpm: isRunning ? noise(3200, 50) : 0,
          feedRate: isRunning ? noise(450, 20) : 0,
          spindleLoad: isRunning ? noise(42 * loadMod * forceMultiplier, 10) : 0,
          vibration: isRunning ? noise(1.4 * loadMod * forceMultiplier, 0.4) : noise(0.05, 0.02),
          temperature: isRunning ? Math.min(135, prev.telemetry.temperature + (1.2 * heatMod)) : Math.max(24, prev.telemetry.temperature - 0.5),
          toolWear: Math.min(100, prev.telemetry.toolWear + wearMod),
          current: isRunning ? noise(baseCurrent, 0.2) : 0,
          noiseLevel: isRunning ? noise(75 + (wearMod * 1000), 5) : 35,
          powerConsumption: isRunning ? noise(4.8 * loadMod * forceMultiplier, 0.8) : 0.2,
          forces: {
            fx: isCutting ? noise(baseForce * 0.1, 10) : noise(0, 1),
            fy: isCutting ? noise(baseForce * 0.1, 10) : noise(0, 1),
            fz: isCutting ? noise(baseForce * 1.6, 40) : noise(0, 2)
          }
        };
        if (isRunning && !activeAlarm) {
          let alarm: Alarm | null = null;
          if (nextTele.toolWear >= targetWear) {
            alarm = { type: 'CRITICAL', category: 'WEAR', message: `GEOMETRIC FAILURE: Wear > ${targetWear}%`, recommendations: ["Tool change required"] };
          } else if (nextTele.temperature > 110) {
            alarm = { type: 'CRITICAL', category: 'THERMAL', message: `THERMAL RUNAWAY: ${nextTele.temperature.toFixed(1)}°C`, recommendations: ["Activate cooling"] };
          } else if (nextTele.vibration > 6.0) {
            alarm = { type: 'CRITICAL', category: 'VIBRATION', message: `STRUCTURAL RESONANCE: ${nextTele.vibration.toFixed(2)}g`, recommendations: ["Check seating"] };
          }
          if (alarm) { setActiveAlarm(alarm); isRunning = false; currentStatus = 'IDLE'; testActive = false; }
        }
        let health = MachineHealth.HEALTHY;
        if (nextTele.temperature > 85 || nextTele.toolWear > targetWear * 0.8 || nextTele.vibration > 3.0) health = MachineHealth.WARNING;
        if (nextTele.temperature > 105 || nextTele.toolWear >= targetWear || nextTele.vibration > 5.0) health = MachineHealth.CRITICAL;
        const newState = { ...prev, status: currentStatus, health, telemetry: nextTele, materialTest: { ...prev.materialTest, isActive: testActive }};
        stateRef.current = newState;
        return newState;
      });
      if (nextTele) {
        setHistory(prev => {
          const newHist = [...prev, nextTele as TelemetryData];
          return newHist.slice(-50);
        });
      }
    }, MACHINE_CONFIG.POLLING_INTERVAL_MS);
    return () => clearInterval(interval);
  }, [history, activeAlarm]);

  const toggleMachine = useCallback(() => {
    const nextStatus = twinState.status === 'RUNNING' ? 'IDLE' : 'RUNNING';
    if (twinState.mode === 'SIMULATED') {
      setTwinState(prev => ({ ...prev, status: nextStatus }));
    } else {
      sendHardwareCommand('SET_STATUS', nextStatus);
    }
  }, [twinState.status, twinState.mode, sendHardwareCommand]);

  return (
    <div className="w-full h-full bg-[#020617] flex flex-col overflow-hidden">
      <header className="px-6 py-4 bg-slate-900/50 backdrop-blur-xl border-b border-white/5 flex justify-between items-center z-50">
        <div className="flex items-center space-x-4">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <Wifi className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-xl font-black text-white tracking-tighter uppercase italic">Twin<span className="text-indigo-400">Core</span></h1>
            <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Digital Force Twin</span>
          </div>
        </div>
        <div className="flex items-center space-x-4">
          <div className="flex bg-black/40 p-1 rounded-lg border border-white/5">
            {['SIMULATED', 'MQTT_LIVE', 'WIFI_LIVE'].map(m => (
              <button 
                key={m}
                onClick={() => setTwinState(s => ({ ...s, mode: m as any }))}
                className={`px-4 py-1.5 rounded-md text-[10px] font-black tracking-widest uppercase transition-all ${twinState.mode === m ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-white'}`}
              >
                {m.split('_')[0]}
              </button>
            ))}
          </div>
          <div className="flex space-x-2">
             <button onClick={toggleMachine} className={`px-6 py-2 rounded-lg font-black text-[11px] uppercase tracking-wider transition-all shadow-lg ${twinState.status === 'RUNNING' ? 'bg-red-500 shadow-red-500/20' : 'bg-emerald-500 shadow-emerald-500/20'} text-white`}>{twinState.status === 'RUNNING' ? 'STOP' : 'START'}</button>
             <button onClick={resetMachine} className="px-6 py-2 bg-slate-800 hover:bg-slate-700 rounded-lg font-black text-[11px] uppercase tracking-wider text-white border border-white/5">RESET</button>
          </div>
        </div>
      </header>

      {activeAlarm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 pointer-events-none">
          <div className="w-full max-w-xl bg-[#0f172a] border-2 border-red-500/50 rounded-[2rem] shadow-[0_0_50px_rgba(239,68,68,0.3)] overflow-hidden animate-in zoom-in-95 duration-300 pointer-events-auto">
            <div className="bg-red-600 p-6 flex items-center justify-between">
              <div className="flex items-center space-x-4">
                <ShieldAlert size={28} className="text-white animate-pulse" />
                <div>
                  <h2 className="text-xl font-black text-white uppercase tracking-tight">Industrial Safety Halt</h2>
                  <p className="text-xs text-red-100 font-bold uppercase tracking-widest">Alarm ID: ERR_{activeAlarm.category}</p>
                </div>
              </div>
              <button onClick={() => setActiveAlarm(null)} className="p-2 text-white/50 hover:text-white transition-colors"><X size={24} /></button>
            </div>
            <div className="p-8 space-y-8">
              <div className="flex items-start space-x-6">
                <div className="p-4 bg-red-500/10 rounded-2xl border border-red-500/20">
                   {activeAlarm.category === 'THERMAL' && <Thermometer size={32} className="text-red-500" />}
                   {activeAlarm.category === 'VIBRATION' && <Zap size={32} className="text-red-500" />}
                   {activeAlarm.category === 'WEAR' && <Wrench size={32} className="text-red-500" />}
                </div>
                <div className="flex-1">
                  <p className="text-lg font-bold text-white leading-tight">{activeAlarm.message}</p>
                </div>
              </div>
              <div className="space-y-4">
                 <div className="text-[10px] font-black text-red-400 uppercase tracking-widest flex items-center"><AlertCircle size={14} className="mr-2" /> Immediate Countermeasures</div>
                 {activeAlarm.recommendations.map((rec, i) => (
                   <div key={i} className="flex items-center space-x-3 bg-red-500/5 border border-red-500/10 p-3 rounded-xl">
                      <div className="w-2 h-2 rounded-full bg-red-500"></div>
                      <span className="text-xs text-slate-300 font-medium">{rec}</span>
                   </div>
                 ))}
              </div>
              <button onClick={resetMachine} className="w-full bg-red-600 hover:bg-red-500 text-white font-black py-4 rounded-2xl uppercase tracking-[0.2em] text-sm shadow-lg shadow-red-900/20">Confirm Halt & Reset</button>
            </div>
          </div>
        </div>
      )}

      <main className="flex-1 relative overflow-hidden">
        <Dashboard 
          twinState={twinState} 
          history={history} 
          materials={MATERIALS} 
          toolGrades={TOOL_GRADES} 
          onConfigChange={handleConfigChange}
        />
      </main>
    </div>
  );
};

export default App;

export enum MachineHealth {
  HEALTHY = 'HEALTHY',
  WARNING = 'WARNING',
  CRITICAL = 'CRITICAL'
}

export interface Material {
  id: string;
  name: string;
  hardnessFactor: number;
  thermalFactor: number;
}

export interface ToolGrade {
  id: string;
  name: string;
  durabilityFactor: number;
  heatResistance: number;
}

export interface TelemetryData {
  timestamp: number;
  rpm: number;
  feedRate: number;
  spindleLoad: number;
  vibration: number;
  temperature: number;
  toolWear: number;
  current: number;
  noiseLevel: number;
  powerConsumption: number;
  forces: {
    fx: number;
    fy: number;
    fz: number;
  };
}

export interface AIDiagnosticResponse {
  healthStatus: string;
  anomaliesDetected: string[];
  prediction: string;
  recommendedActions: string[];
  summary: string;
}

export interface MaterialTest {
  isActive: boolean;
  durationSeconds: number;
  targetWear: number;
  startTime: number | null;
  scenario?: 'NORMAL' | 'AGGRESSIVE' | 'THERMAL' | 'IMPACT';
  testTitle?: string;
  researcherName?: string;
  batchId?: string;
  hypothesis?: string;
}

export interface TwinState {
  id: string;
  name: string;
  model: string;
  health: MachineHealth;
  status: 'IDLE' | 'RUNNING' | 'ERROR' | 'MAINTENANCE';
  mode: 'SIMULATED' | 'MQTT_LIVE' | 'WIFI_LIVE';
  mqttStatus: 'CONNECTED' | 'DISCONNECTED' | 'CONNECTING';
  cloudSync: 'SYNCED' | 'SYNCING' | 'ERROR' | 'OFFLINE';
  lastSyncTimestamp?: number;
  lastCommandSent: string | null;
  telemetry: TelemetryData;
  materialTest: MaterialTest;
  config: {
    material: Material;
    toolGrade: ToolGrade;
    simulationSpeed: number;
    enabledSensors: {
      vibration: boolean;
      temperature: boolean;
      forces: boolean;
      spindleLoad: boolean;
    };
    thingSpeakKey: string;
    mqttBroker: string;
    telemetryTopic: string;
    commandTopic: string;
    wifiSsid: string;
    wifiPassword: string;
    espIp: string;
    espPort: string;
  };
  predictions: {
    rul: number;
    failureProbability: number;
    nextMaintenanceDate: string;
    anomalyDetected: boolean;
  };
}

export interface ChartDataPoint {
  time: string;
  value: number;
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { Dashboard } from './components/Dashboard';
import { TelemetryData, TwinState, MachineHealth, Material, ToolGrade } from './types';
import { MACHINE_CONFIG } from './constants';
import mqtt from 'mqtt';
import { Wifi, Shield, Globe, Cpu, ChevronUp, Link, Settings, AlertCircle, Bell, X, ShieldAlert, Zap, Thermometer, Wrench } from 'lucide-react';

