                    ? 'bg-red-500/10 text-red-500 border border-red-500/20 hover:bg-red-500/20' 
                    : 'bg-indigo-600 text-white shadow-indigo-500/20 hover:bg-indigo-500'
                  }`}
                >
                  {twinState.materialTest.isActive ? 'Stop Scenario Run' : 'Execute Test Protocol'}
                </button>
              </div>
            </section>
          </div>
        );
      case 'CONNECTIVITY':
        return (
          <div className="p-6 space-y-8 overflow-y-auto h-full scrollbar-hide">
            <section className="space-y-4">
              <h2 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] flex items-center">
                 <Network size={14} className="mr-2 text-indigo-500" /> Industrial IoT Cloud Integration
              </h2>
