                <div className="bg-white/5 p-6 rounded-3xl border border-white/5 space-y-4">
                  <div className="flex items-center justify-between">
                    <h3 className="text-[10px] font-black text-indigo-400 uppercase tracking-widest flex items-center">
                      <Cloud size={14} className="mr-2" /> ThingSpeak Analytical Platform
                    </h3>
                    <div className={`px-2 py-0.5 rounded-full text-[8px] font-black uppercase ${
                      twinState.cloudSync === 'SYNCED' ? 'bg-emerald-500/20 text-emerald-400' :
                      twinState.cloudSync === 'SYNCING' ? 'bg-amber-500/20 text-amber-400 animate-pulse' :
                      twinState.cloudSync === 'ERROR' ? 'bg-red-500/20 text-red-400' : 'bg-slate-500/20 text-slate-500'
                    }`}>
                      {twinState.cloudSync}
                    </div>
                  </div>
                  <div className="space-y-4">
                    <div className="space-y-1">
                      <label className="text-[10px] font-black text-slate-500 uppercase ml-1 flex items-center">
                        <Key size={10} className="mr-1" /> Channel Write API Key
                      </label>
                      <input 
                        type="password"
                        value={twinState.config.thingSpeakKey}
                        onChange={(e) => onConfigChange({ thingSpeakKey: e.target.value })}
                        className="w-full bg-slate-900 border border-white/10 rounded-xl px-3 py-3 text-xs text-white outline-none focus:border-indigo-500 font-mono"
                        placeholder="Paste Write API Key Here..."
                      />
                    </div>
                    <div className="p-4 bg-black/40 rounded-2xl border border-white/5 space-y-3">
                       <div className="flex justify-between items-center text-[9px] font-bold uppercase tracking-tight">
                          <span className="text-slate-500">Sync Frequency</span>
                          <span className="text-white">16 SEC (FREE TIER ADHERED)</span>
                       </div>
                       <div className="flex justify-between items-center text-[9px] font-bold uppercase tracking-tight">
                          <span className="text-slate-500">Last Successful Uplink</span>
                          <span className="text-indigo-400">{twinState.lastSyncTimestamp ? new Date(twinState.lastSyncTimestamp).toLocaleTimeString() : 'NEVER'}</span>
                       </div>
                       <div className="pt-2 flex flex-wrap gap-2">
                         {['RPM (F1)', 'TEMP (F2)', 'WEAR (F3)', 'VIBE (F4)', 'FORCE (F5)'].map(f => (
                           <div key={f} className="px-2 py-1 bg-white/5 border border-white/10 rounded-md text-[7px] font-black text-slate-500 uppercase">{f}</div>
                         ))}
                       </div>
                    </div>
                    <button 
                      onClick={() => window.open('https://thingspeak.com/', '_blank')}
                      className="w-full py-2 bg-indigo-500/10 hover:bg-indigo-500/20 border border-indigo-500/20 rounded-xl text-[9px] font-black text-indigo-400 uppercase flex items-center justify-center transition-all"
                    >
                      <ExternalLink size={10} className="mr-2" /> Open ThingSpeak Dashboard
                    </button>
                  </div>
                </div>
                <div className="bg-white/5 p-6 rounded-3xl border border-white/5 space-y-4">
                  <h3 className="text-[10px] font-black text-emerald-400 uppercase tracking-widest flex items-center">
                    <Cpu size={14} className="mr-2" /> ESP32 Edge Core Connectivity
                  </h3>
                  <div className="space-y-3">
                    <div className="space-y-1">
                      <label className="text-[10px] font-black text-slate-500 uppercase ml-1">MQTT Industrial Broker</label>
                      <input 
                        type="text"
                        value={twinState.config.mqttBroker}
                        onChange={(e) => onConfigChange({ mqttBroker: e.target.value })}
                        className="w-full bg-slate-900 border border-white/10 rounded-xl px-3 py-2 text-xs text-white outline-none focus:border-indigo-500/50"
                      />
                    </div>
                    <div className="grid grid-cols-2 gap-3">
                      <div className="space-y-1">
                        <label className="text-[10px] font-black text-slate-500 uppercase ml-1">Edge IP Address</label>
                        <input 
                          type="text"
                          value={twinState.config.espIp}
                          onChange={(e) => onConfigChange({ espIp: e.target.value })}
                          className="w-full bg-slate-900 border border-white/10 rounded-xl px-3 py-2 text-xs text-white outline-none focus:border-indigo-500/50"
                        />
                      </div>
                      <div className="space-y-1">
                        <label className="text-[10px] font-black text-slate-500 uppercase ml-1">Tele-Topic</label>
                        <input 
                          type="text"
                          value={twinState.config.telemetryTopic}
                          onChange={(e) => onConfigChange({ telemetryTopic: e.target.value })}
                          className="w-full bg-slate-900 border border-white/10 rounded-xl px-3 py-2 text-xs text-white outline-none focus:border-indigo-500/50"
                        />
                      </div>
                    </div>
                    <div className="p-3 bg-emerald-500/5 border border-emerald-500/10 rounded-xl flex items-center justify-between">
                       <div className="flex items-center space-x-2">
                         <HardDrive size={14} className="text-emerald-500" />
                         <span className="text-[9px] font-black text-slate-300 uppercase">MQTT Link Status</span>
                       </div>
                       <span className={`text-[10px] font-black uppercase ${twinState.mqttStatus === 'CONNECTED' ? 'text-emerald-400' : 'text-slate-500'}`}>{twinState.mqttStatus}</span>
                    </div>
                  </div>
                </div>
              </div>
            </section>
          </div>
        );
      case 'HISTORY':
        return <ProcessHistory history={history} health={twinState.health} status={twinState.status} />;
      default:
        return null;
    }
  };

  return (
    <div className="h-full flex flex-col bg-[#020617] overflow-hidden">
      <div className="flex items-center px-6 py-2 bg-slate-900/30 border-b border-white/5 justify-between">
        <div className="flex space-x-1">
          {(['TWIN', 'ANALYTICS', 'HISTORY', 'SETUP', 'CONNECTIVITY'] as TabType[]).map((tab) => (
            <button
              key={tab}
              onClick={() => setActiveTab(tab)}
              className={`flex items-center space-x-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${
                activeTab === tab 
                ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/20' 
                : 'text-slate-500 hover:text-slate-300 hover:bg-white/5'
              }`}
            >
              {tab === 'TWIN' && <LayoutDashboard size={14} />}
              {tab === 'ANALYTICS' && <Binary size={14} />}
              {tab === 'HISTORY' && <History size={14} />}
              {tab === 'SETUP' && <Settings size={14} />}
              {tab === 'CONNECTIVITY' && <Network size={14} />}
              <span>{tab === 'SETUP' ? 'PROCESS SETUP' : tab}</span>
            </button>
          ))}
        </div>
        <div className="flex items-center space-x-6">
          <div className="flex flex-col items-end">
            <span className="text-[8px] font-black text-slate-500 uppercase tracking-tighter">System Health</span>
            <span className={`text-[10px] font-black uppercase ${twinState.health === MachineHealth.HEALTHY ? 'text-emerald-400' : 'text-red-400'}`}>{twinState.health}</span>
          </div>
          <div className="h-8 w-px bg-white/10" />
          <div className="flex flex-col items-end">
            <span className="text-[8px] font-black text-slate-500 uppercase tracking-tighter">MQTT Uplink</span>
            <span className={`text-[10px] font-black uppercase ${twinState.mqttStatus === 'CONNECTED' ? 'text-indigo-400' : 'text-slate-500'}`}>{twinState.mqttStatus}</span>
          </div>
        </div>
      </div>
      <div className="flex-1 overflow-hidden">
        {renderTabContent()}
      </div>
    </div>
  );
};

export enum MachineHealth {
  HEALTHY = 'HEALTHY',
  WARNING = 'WARNING',
  CRITICAL = 'CRITICAL'
}

export interface Material {
  id: string;
  name: string;
  hardnessFactor: number;
  thermalFactor: number;
}

export interface ToolGrade {
  id: string;
  name: string;
  durabilityFactor: number;
  heatResistance: number;
}

export interface TelemetryData {
  timestamp: number;
  rpm: number;
  feedRate: number;
  spindleLoad: number;
  vibration: number;
  temperature: number;
  toolWear: number;
  current: number;
  noiseLevel: number;
  powerConsumption: number;
  forces: {
    fx: number;
    fy: number;
    fz: number;
  };
}

export interface AIDiagnosticResponse {
  healthStatus: string;
  anomaliesDetected: string[];
  prediction: string;
  recommendedActions: string[];
  summary: string;
}

export interface MaterialTest {
  isActive: boolean;
  durationSeconds: number;
  targetWear: number;
  startTime: number | null;
  scenario?: 'NORMAL' | 'AGGRESSIVE' | 'THERMAL' | 'IMPACT';
  testTitle?: string;
  researcherName?: string;
  batchId?: string;
  hypothesis?: string;
}

export interface TwinState {
  id: string;
  name: string;
  model: string;
  health: MachineHealth;
  status: 'IDLE' | 'RUNNING' | 'ERROR' | 'MAINTENANCE';
  mode: 'SIMULATED' | 'MQTT_LIVE' | 'WIFI_LIVE';
  mqttStatus: 'CONNECTED' | 'DISCONNECTED' | 'CONNECTING';
  cloudSync: 'SYNCED' | 'SYNCING' | 'ERROR' | 'OFFLINE';
  lastSyncTimestamp?: number;
  lastCommandSent: string | null;
  telemetry: TelemetryData;
  materialTest: MaterialTest;
  config: {
    material: Material;
    toolGrade: ToolGrade;
    simulationSpeed: number;
    enabledSensors: {
      vibration: boolean;
      temperature: boolean;
      forces: boolean;
      spindleLoad: boolean;
    };
    thresholds: {
      temperature: number;
      vibration: number;
      force: number;
      spindleLoad: number;
      toolWear: number;
    };
    thingSpeakKey: string;
    mqttBroker: string;
    telemetryTopic: string;
    commandTopic: string;
    wifiSsid: string;
    wifiPassword: string;
    espIp: string;
    espPort: string;
  };
  predictions: {
    rul: number;
    failureProbability: number;
    nextMaintenanceDate: string;
    anomalyDetected: boolean;
  };
}

export interface ChartDataPoint {
  time: string;
  value: number;
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
