            </div>

            <section className="bg-white/5 p-6 rounded-3xl border border-white/5">
              <h2 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] flex items-center mb-6">
                 <Zap size={14} className="mr-2 text-indigo-500" /> Active Hardware Feeds
              </h2>
              <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
                {(['temperature', 'vibration', 'forces', 'spindleLoad'] as const).map(sensor => (
                  <button
                    key={sensor}
                    onClick={() => handleSensorToggle(sensor)}
                    className={`flex flex-col items-center p-3 rounded-2xl border transition-all ${
                      twinState.config.enabledSensors[sensor] 
                      ? 'bg-indigo-600/10 border-indigo-500 text-indigo-400' 
                      : 'bg-black/20 border-white/5 text-slate-600'
