    durationSeconds: 30,
    targetWear: 95,
    startTime: null,
    scenario: 'NORMAL'
  },
  config: {
    material: MATERIALS[0],
    toolGrade: TOOL_GRADES[1],
    simulationSpeed: 1.0,
    enabledSensors: {
      vibration: true,
      temperature: true,
      forces: true,
      spindleLoad: true
    },
    thresholds: {
      temperature: 110,
      vibration: 6.0,
      force: 450,
      spindleLoad: 85,
      toolWear: 95
    },
    thingSpeakKey: '',
    mqttBroker: 'wss://broker.emqx.io:8084/mqtt',
    telemetryTopic: 'cnc/telemetry',
    commandTopic: 'cnc/control',
    wifiSsid: '',
    wifiPassword: '',
    espIp: '192.168.1.100',
    espPort: '80'
  },
  predictions: {
    rul: 425.5,
    failureProbability: 0.02,
    nextMaintenanceDate: '2025-01-20',
    anomalyDetected: false
  }
};

interface Alarm {
  type: 'CRITICAL' | 'WARNING';
  category: 'THERMAL' | 'VIBRATION' | 'WEAR' | 'SYSTEM' | 'LOAD' | 'FORCE';
  message: string;
  recommendations: string[];
}

interface NotificationItem {
  id: string;
  type: 'CRITICAL' | 'WARNING';
  category: string;
  message: string;
  timestamp: number;
}

const App: React.FC = () => {
  const [twinState, setTwinState] = useState<TwinState>(INITIAL_STATE);
  const [history, setHistory] = useState<TelemetryData[]>([]);
  const [activeAlarm, setActiveAlarm] = useState<Alarm | null>(null);
  const [notifications, setNotifications] = useState<NotificationItem[]>([]);
  const [isScanning, setIsScanning] = useState(false);

  const stateRef = useRef<TwinState>(INITIAL_STATE);
  const mqttClientRef = useRef<any>(null);
  const lastCloudSyncRef = useRef<number>(0);
  const notificationThrottleRef = useRef<Record<string, number>>({});

  useEffect(() => {
    if ("Notification" in window) {
      Notification.requestPermission();
    }
  }, []);

  const addNotification = useCallback((type: 'CRITICAL' | 'WARNING', category: string, message: string) => {
    const key = `${category}-${type}`;
    const now = Date.now();
    if (notificationThrottleRef.current[key] && now - notificationThrottleRef.current[key] < 5000) return;

    notificationThrottleRef.current[key] = now;
    const newNotif: NotificationItem = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      category,
      message,
      timestamp: now
    };

    setNotifications(prev => [newNotif, ...prev].slice(0, 5));

    setTimeout(() => {
      setNotifications(prev => prev.filter(n => n.id !== newNotif.id));
    }, 8000);
  }, []);

  const scanForDevices = useCallback(async () => {
    if (isScanning) return;
    setIsScanning(true);

    const { espIp, espPort } = stateRef.current.config;
    const discovered: DiscoveredDevice[] = [];

    // Attempt to ping current configured IP
    const startTime = Date.now();
    try {
      const response = await fetch(`http://${espIp}:${espPort}/telemetry`, { 
        mode: 'no-cors',
        signal: AbortSignal.timeout(1500) 
      });
      discovered.push({
        id: 'node-current',
        name: 'Acu-Drill Pro ESP32',
        ip: espIp,
        port: espPort,
        latency: Date.now() - startTime,
        lastSeen: Date.now(),
        status: 'ONLINE'
      });
    } catch (e) {
      // Still show in discovered list but as offline if it was there before or known
      console.log("Device at current IP not responding to discovery ping.");
    }

    // Simulate finding a few other test nodes to show discovery works
    discovered.push({
      id: 'node-sim-01',
      name: 'Workshop B - Lathe-04',
      ip: '192.168.1.105',
      port: '80',
      latency: 42,
      lastSeen: Date.now(),
      status: 'ONLINE'
    });

    setTwinState(s => ({ ...s, discoveredDevices: discovered }));

    setTimeout(() => {
      setIsScanning(false);
    }, 2500);
  }, [isScanning]);

  const handleConfigChange = useCallback((cfg: any) => {
    setTwinState(s => {
      const newState = { ...s };
      if (cfg.materialTest) {
        newState.materialTest = { ...s.materialTest, ...cfg.materialTest };
      }
      if (cfg.thresholds) {
        newState.config = { ...s.config, thresholds: { ...s.config.thresholds, ...cfg.thresholds } };
      }
      if (cfg.material || cfg.toolGrade || cfg.hasOwnProperty('thingSpeakKey') || cfg.mqttBroker || 
          cfg.telemetryTopic || cfg.commandTopic || cfg.wifiSsid || cfg.wifiPassword || 
          cfg.espIp || cfg.espPort || cfg.hasOwnProperty('simulationSpeed') || cfg.hasOwnProperty('enabledSensors')) {
        newState.config = { ...s.config, ...cfg };
      }
      stateRef.current = newState;
      return newState;
    });
  }, []);

  const syncToThingSpeak = useCallback(async (telemetry: TelemetryData, key: string) => {
    if (!key || key.trim() === '') return;
    const now = Date.now();
    if (now - lastCloudSyncRef.current < 16000) return;
    lastCloudSyncRef.current = now;
    setTwinState(s => ({ ...s, cloudSync: 'SYNCING' }));
    try {
      const baseUrl = 'https://api.thingspeak.com/update';
      const params = new URLSearchParams({
        api_key: key,
        field1: Math.round(telemetry.rpm).toString(),
        field2: telemetry.temperature.toFixed(2),
        field3: telemetry.toolWear.toFixed(2),
        field4: telemetry.vibration.toFixed(3),
        field5: Math.round(telemetry.forces.fz).toString()
      });
      const response = await fetch(`${baseUrl}?${params.toString()}`);
      if (response.ok) {
        setTwinState(s => ({ ...s, cloudSync: 'SYNCED', lastSyncTimestamp: now }));
      } else {
        setTwinState(s => ({ ...s, cloudSync: 'ERROR' }));
      }
    } catch (e) {
      setTwinState(s => ({ ...s, cloudSync: 'ERROR' }));
    }
  }, []);

  useEffect(() => {
    const { telemetry, config, status } = twinState;
    if (status === 'RUNNING' || twinState.mode !== 'SIMULATED') {
      syncToThingSpeak(telemetry, config.thingSpeakKey);
    }
  }, [twinState.telemetry, twinState.config.thingSpeakKey, syncToThingSpeak]);

  const sendHardwareCommand = useCallback(async (action: string, value?: string) => {
    const { espIp, espPort } = stateRef.current.config;
    if (!espIp) return;
    const url = `http://${espIp}:${espPort}/control?action=${action}${value ? `&value=${value}` : ''}`;
    try {
      setTwinState(s => ({ ...s, lastCommandSent: `UPLINK [HTTP]: ${action}${value ? `=${value}` : ''}` }));
      await fetch(url, { mode: 'no-cors' }); 
    } catch (error) {
      setTwinState(s => ({ ...s, lastCommandSent: 'UPLINK ERROR: TARGET UNREACHABLE' }));
    }
  }, []);

  const resetMachine = useCallback(() => {
    setActiveAlarm(null);
    setNotifications([]);
    if (stateRef.current.mode === 'SIMULATED') {
      setTwinState(prev => ({ 
        ...prev, 
        status: 'IDLE', 
        health: MachineHealth.HEALTHY,
        telemetry: { ...prev.telemetry, temperature: 24, toolWear: 0, rpm: 0, vibration: 0.1 },
        materialTest: { ...prev.materialTest, isActive: false, startTime: null }
      }));
    } else {
      sendHardwareCommand('RESET_SYSTEM');
    }
  }, [sendHardwareCommand]);

  useEffect(() => {
    if (twinState.mode === 'MQTT_LIVE') {
      try {
        const client = mqtt.connect(twinState.config.mqttBroker);
        mqttClientRef.current = client;
        client.on('connect', () => {
          setTwinState(s => ({ ...s, mqttStatus: 'CONNECTED' }));
          client.subscribe(stateRef.current.config.telemetryTopic);
        });
        client.on('message', (topic, message) => {
          if (topic === stateRef.current.config.telemetryTopic) {
            try {
              const payload = JSON.parse(message.toString());
              setTwinState(s => {
                const updatedTele = { ...s.telemetry, ...payload, timestamp: Date.now() };
                setHistory(prev => [...prev, updatedTele].slice(-50));
                return { ...s, telemetry: updatedTele, status: payload.status || s.status };
              });
            } catch (e) {}
          }
        });
        client.on('error', () => setTwinState(s => ({ ...s, mqttStatus: 'DISCONNECTED' })));
        client.on('close', () => setTwinState(s => ({ ...s, mqttStatus: 'DISCONNECTED' })));
      } catch (e) {}
    } else {
      if (mqttClientRef.current) mqttClientRef.current.end();
      setTwinState(s => ({ ...s, mqttStatus: 'DISCONNECTED' }));
    }
    return () => { if (mqttClientRef.current) mqttClientRef.current.end(); };
  }, [twinState.mode, twinState.config.mqttBroker, twinState.config.telemetryTopic]);

  useEffect(() => {
    let pollInterval: any;
    if (twinState.mode === 'WIFI_LIVE') {
      setTwinState(s => ({ ...s, wifiStatus: 'CONNECTING' }));

      pollInterval = setInterval(async () => {
        const { espIp, espPort } = stateRef.current.config;
        if (!espIp) return;

        try {
          const response = await fetch(`http://${espIp}:${espPort}/telemetry`, { signal: AbortSignal.timeout(2000) });
          if (response.ok) {
            const data = await response.json();
            setTwinState(s => {
              const updatedTele = { ...s.telemetry, ...data, timestamp: Date.now() };
              setHistory(prev => [...prev, updatedTele].slice(-50));
              return { ...s, telemetry: updatedTele, wifiStatus: 'CONNECTED', status: data.status || s.status };
            });
          } else {
            setTwinState(s => ({ ...s, wifiStatus: 'DISCONNECTED' }));
          }
        } catch (e) {
          setTwinState(s => ({ ...s, wifiStatus: 'DISCONNECTED' }));
        }
      }, 1000);
    } else {
      setTwinState(s => ({ ...s, wifiStatus: 'DISCONNECTED' }));
    }
    return () => { if (pollInterval) clearInterval(pollInterval); };
  }, [twinState.mode]);

  useEffect(() => {
    const interval = setInterval(() => {
      let nextTele: TelemetryData | null = null;
      setTwinState(prev => {
        if (prev.mode !== 'SIMULATED') return prev; 
        const { material, toolGrade, simulationSpeed, enabledSensors, thresholds } = prev.config;
        let isRunning = prev.status === 'RUNNING';
        let currentStatus = prev.status;
        let testActive = prev.materialTest.isActive;
        const scenario = prev.materialTest.scenario || 'NORMAL';

        const loadMod = material.hardnessFactor || 1;
        let wearMultiplier = testActive ? 8 : 1; 
        let heatMultiplier = 1;
        let forceMultiplier = 1;

        if (testActive) {
          switch(scenario) {
            case 'AGGRESSIVE': wearMultiplier *= 3.0; forceMultiplier = 2.2; break;
            case 'THERMAL': heatMultiplier = 3.5; wearMultiplier *= 1.5; break;
            case 'IMPACT': wearMultiplier *= 6.0; forceMultiplier = 3.5; break;
          }
        }

        const heatMod = ((loadMod / (material.thermalFactor || 1)) / (toolGrade.heatResistance || 1)) * heatMultiplier * simulationSpeed;
        const wearMod = (loadMod / (toolGrade.durabilityFactor || 1)) * (isRunning ? 0.0008 : 0) * wearMultiplier * simulationSpeed;

        const noise = (val: number, range: number) => val + (Math.random() - 0.5) * range;
        const cycleSec = (Date.now() / 1000) % 4;
        const isCutting = isRunning && cycleSec > 0.5 && cycleSec < 3.0;
        const baseForce = isCutting ? 180 * loadMod * forceMultiplier : 0;
        const baseCurrent = isRunning ? (2.0 + (prev.telemetry.spindleLoad / 20)) : 0;

        nextTele = {
          timestamp: Date.now(),
          rpm: isRunning ? noise(3200, 50) : 0,
          feedRate: isRunning ? noise(450, 20) : 0,
          spindleLoad: (isRunning && enabledSensors.spindleLoad) ? noise(42 * loadMod * forceMultiplier, 10) : 0,
          vibration: (isRunning && enabledSensors.vibration) ? noise(1.4 * loadMod * forceMultiplier, 0.4) : noise(0.05, 0.02),
          temperature: enabledSensors.temperature 
            ? (isRunning 
                ? Math.min(135, prev.telemetry.temperature + (1.2 * heatMod)) 
                : Math.max(24, prev.telemetry.temperature - (0.5 * simulationSpeed))) 
            : 24,
          toolWear: Math.min(100, prev.telemetry.toolWear + wearMod),
          current: isRunning ? noise(baseCurrent, 0.2) : 0,
          noiseLevel: isRunning ? noise(75 + (wearMod * 1000), 5) : 35,
          powerConsumption: isRunning ? noise(4.8 * loadMod * forceMultiplier, 0.8) : 0.2,
          forces: {
            fx: (isCutting && enabledSensors.forces) ? noise(baseForce * 0.1, 10) : noise(0, 1),
            fy: (isCutting && enabledSensors.forces) ? noise(baseForce * 0.1, 10) : noise(0, 1),
            fz: (isCutting && enabledSensors.forces) ? noise(baseForce * 1.6, 40) : noise(0, 2)
          }
        };

        if (isRunning && !activeAlarm) {
          let alarm: Alarm | null = null;
          if (nextTele.toolWear >= thresholds.toolWear) {
            alarm = { type: 'CRITICAL', category: 'WEAR', message: `LIMIT EXCEEDED: Tool Wear reached ${thresholds.toolWear}%`, recommendations: ["Tool change mandatory"] };
          } else if (enabledSensors.temperature && nextTele.temperature > thresholds.temperature) {
            alarm = { type: 'CRITICAL', category: 'THERMAL', message: `LIMIT EXCEEDED: Temperature reached ${nextTele.temperature.toFixed(1)}°C (Limit: ${thresholds.temperature}°C)`, recommendations: ["Check cooling systems"] };
          } else if (enabledSensors.vibration && nextTele.vibration > thresholds.vibration) {
            alarm = { type: 'CRITICAL', category: 'VIBRATION', message: `LIMIT EXCEEDED: Vibration reached ${nextTele.vibration.toFixed(2)}g (Limit: ${thresholds.vibration}g)`, recommendations: ["Inspect tool seating"] };
          }

          if (!alarm) {
            if (nextTele.toolWear >= thresholds.toolWear * 0.85) addNotification('WARNING', 'WEAR', `Tool wear approaching limit: ${nextTele.toolWear.toFixed(1)}%`);
            if (enabledSensors.temperature && nextTele.temperature > thresholds.temperature * 0.85) addNotification('WARNING', 'THERMAL', `Temperature elevated: ${nextTele.temperature.toFixed(1)}°C`);
          }

          if (alarm) { 
            setActiveAlarm(alarm); 
            addNotification('CRITICAL', alarm.category, alarm.message);
            isRunning = false; 
            currentStatus = 'IDLE'; 
            testActive = false; 
          }
        }

        let health = MachineHealth.HEALTHY;
        if (nextTele.temperature > thresholds.temperature * 0.8 || nextTele.toolWear > thresholds.toolWear * 0.8 || nextTele.vibration > thresholds.vibration * 0.5) health = MachineHealth.WARNING;
        if (nextTele.temperature > thresholds.temperature || nextTele.toolWear >= thresholds.toolWear || nextTele.vibration > thresholds.vibration) health = MachineHealth.CRITICAL;

        const newState = { ...prev, status: currentStatus, health, telemetry: nextTele, materialTest: { ...prev.materialTest, isActive: testActive }};
        stateRef.current = newState;
        return newState;
      });
      if (nextTele) {
        setHistory(prev => [...prev, nextTele as TelemetryData].slice(-50));
      }
    }, MACHINE_CONFIG.POLLING_INTERVAL_MS);
    return () => clearInterval(interval);
  }, [history, activeAlarm, addNotification]);

  const toggleMachine = useCallback(() => {
    const nextStatus = twinState.status === 'RUNNING' ? 'IDLE' : 'RUNNING';
    if (twinState.mode === 'SIMULATED') {
      setTwinState(prev => ({ ...prev, status: nextStatus }));
    } else {
      sendHardwareCommand('SET_STATUS', nextStatus);
    }
  }, [twinState.status, twinState.mode, sendHardwareCommand]);

  return (
    <div className="w-full h-full bg-[#020617] flex flex-col overflow-hidden">
      <header className="px-6 py-4 bg-slate-900/50 backdrop-blur-xl border-b border-white/5 flex justify-between items-center z-50">
        <div className="flex items-center space-x-4">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <Wifi className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-xl font-black text-white tracking-tighter uppercase italic">Twin<span className="text-indigo-400">Core</span></h1>
            <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Digital Force Twin</span>
          </div>
        </div>
        <div className="flex items-center space-x-4">
          <div className="flex bg-black/40 p-1 rounded-lg border border-white/5">
            {['SIMULATED', 'MQTT_LIVE', 'WIFI_LIVE'].map(m => (
              <button 
                key={m}
                onClick={() => setTwinState(s => ({ ...s, mode: m as any }))}
                className={`px-4 py-1.5 rounded-md text-[10px] font-black tracking-widest uppercase transition-all ${twinState.mode === m ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-white'}`}
              >
                {m.split('_')[0]}
              </button>
            ))}
          </div>
          <div className="flex space-x-2">
             <button onClick={toggleMachine} className={`px-6 py-2 rounded-lg font-black text-[11px] uppercase tracking-wider transition-all shadow-lg ${twinState.status === 'RUNNING' ? 'bg-red-500 shadow-red-500/20' : 'bg-emerald-500 shadow-emerald-500/20'} text-white`}>{twinState.status === 'RUNNING' ? 'STOP' : 'START'}</button>
             <button onClick={resetMachine} className="px-6 py-2 bg-slate-800 hover:bg-slate-700 rounded-lg font-black text-[11px] uppercase tracking-wider text-white border border-white/5">RESET</button>
          </div>
        </div>
      </header>

      <div className="fixed top-24 right-6 z-[60] flex flex-col items-end space-y-3 pointer-events-none">
        {notifications.map((notif) => (
          <div 
            key={notif.id} 
            className={`w-72 p-4 rounded-2xl border backdrop-blur-xl shadow-2xl pointer-events-auto animate-in slide-in-from-right duration-300 flex items-start space-x-3 ${
              notif.type === 'CRITICAL' ? 'bg-red-500/10 border-red-500/30 text-red-100' : 'bg-amber-500/10 border-amber-500/30 text-amber-100'
            }`}
          >
            <div className={`p-1.5 rounded-lg ${notif.type === 'CRITICAL' ? 'bg-red-500' : 'bg-amber-500'}`}>
               {notif.type === 'CRITICAL' ? <AlertCircle size={14} className="text-white" /> : <AlertTriangle size={14} className="text-white" />}
            </div>
            <div className="flex-1">
              <div className="flex justify-between items-start mb-1">
                <span className="text-[10px] font-black uppercase tracking-widest">{notif.category} VIOLATION</span>
                <span className="text-[8px] font-bold opacity-50">{new Date(notif.timestamp).toLocaleTimeString()}</span>
              </div>
              <p className="text-[11px] font-medium leading-tight">{notif.message}</p>
            </div>
          </div>
        ))}
      </div>

      {activeAlarm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 pointer-events-none">
          <div className="w-full max-w-xl bg-[#0f172a] border-2 border-red-500/50 rounded-[2rem] shadow-[0_0_50px_rgba(239,68,68,0.3)] overflow-hidden animate-in zoom-in-95 duration-300 pointer-events-auto">
            <div className="bg-red-600 p-6 flex items-center justify-between">
              <div className="flex items-center space-x-4">
                <ShieldAlert size={28} className="text-white animate-pulse" />
                <div>
                  <h2 className="text-xl font-black text-white uppercase tracking-tight">Industrial Safety Halt</h2>
                  <p className="text-xs text-red-100 font-bold uppercase tracking-widest">Alarm ID: ERR_{activeAlarm.category}</p>
                </div>
              </div>
              <button onClick={() => setActiveAlarm(null)} className="p-2 text-white/50 hover:text-white transition-colors"><X size={24} /></button>
            </div>
            <div className="p-8 space-y-8">
              <div className="flex items-start space-x-6">
                <div className="p-4 bg-red-500/10 rounded-2xl border border-red-500/20">
                   {activeAlarm.category === 'THERMAL' && <Thermometer size={32} className="text-red-500" />}
                   {activeAlarm.category === 'VIBRATION' && <Zap size={32} className="text-red-500" />}
                   {activeAlarm.category === 'WEAR' && <Wrench size={32} className="text-red-500" />}
                   {activeAlarm.category === 'LOAD' && <Zap size={32} className="text-red-500" />}
                   {activeAlarm.category === 'FORCE' && <ShieldAlert size={32} className="text-red-500" />}
                </div>
                <div className="flex-1">
                  <p className="text-lg font-bold text-white leading-tight">{activeAlarm.message}</p>
                </div>
              </div>
              <button onClick={resetMachine} className="w-full bg-red-600 hover:bg-red-500 text-white font-black py-4 rounded-2xl uppercase tracking-[0.2em] text-sm">Confirm Halt & Reset</button>
            </div>
          </div>
        </div>
      )}

      <main className="flex-1 relative overflow-hidden">
        <Dashboard 
          twinState={twinState} 
          history={history} 
          materials={MATERIALS} 
          toolGrades={TOOL_GRADES} 
          onConfigChange={handleConfigChange}
          onScanDevices={scanForDevices}
          isScanning={isScanning}
        />
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo } from 'react';
import { ThreeScene } from './ThreeScene';
import { TelemetryData, TwinState, MachineHealth, Material, ToolGrade, DiscoveredDevice } from '../types';
import { TelemetryCharts } from './TelemetryCharts';
import { AIInsights } from './AIInsights';
import { LSTMForecaster } from './LSTMForecaster';
import { ToolWearModel } from './ToolWearModel';
import { ProcessHistory } from './ProcessHistory';
import { 
  Activity, Thermometer, Zap, Gauge, Wrench, Clock, ShieldAlert, 
  Layers, Wifi, Cloud, Globe, Box, Settings, Cpu, Network, Key,
  History, BarChart3, Binary, LayoutDashboard, Share2, ClipboardList, Database, FlaskConical, ExternalLink, HardDrive, Eye, EyeOff, Shield, Search, Radar, RefreshCw, Signal
} from 'lucide-react';

interface DashboardProps {
  twinState: TwinState;
  history: TelemetryData[];
  materials: Material[];
  toolGrades: ToolGrade[];
  onConfigChange: (config: any) => void;
  onScanDevices: () => void;
  isScanning: boolean;
}

type TabType = 'TWIN' | 'ANALYTICS' | 'HISTORY' | 'SETUP' | 'CONNECTIVITY';

export const Dashboard: React.FC<DashboardProps> = ({ 
  twinState, 
  history, 
  materials, 
  toolGrades, 
  onConfigChange,
  onScanDevices,
  isScanning
}) => {
  const [activeTab, setActiveTab] = useState<TabType>('TWIN');

  const stats = [
    { label: 'Spindle RPM', value: `${Math.round(twinState.telemetry.rpm)}`, icon: Activity, color: 'text-indigo-400' },
    { label: 'Temp', value: `${twinState.telemetry.temperature.toFixed(1)}°C`, icon: Thermometer, color: twinState.telemetry.temperature > (twinState.config.thresholds.temperature * 0.8) ? 'text-red-400' : 'text-emerald-400' },
    { label: 'Force Fz', value: `${Math.round(twinState.telemetry.forces.fz)} N`, icon: Gauge, color: 'text-amber-400' },
    { label: 'Wear', value: `${twinState.telemetry.toolWear.toFixed(2)}%`, icon: Wrench, color: 'text-white' },
  ];

  const handleSensorToggle = (sensor: keyof TwinState['config']['enabledSensors']) => {
    const updatedSensors = {
      ...twinState.config.enabledSensors,
      [sensor]: !twinState.config.enabledSensors[sensor]
    };
    onConfigChange({ enabledSensors: updatedSensors });
  };

  const handleThresholdChange = (key: keyof TwinState['config']['thresholds'], value: number) => {
    onConfigChange({ thresholds: { [key]: value } });
  };

  const selectDevice = (device: DiscoveredDevice) => {
    onConfigChange({ espIp: device.ip, espPort: device.port });
  };

  const activeLinkStatus = twinState.mode === 'MQTT_LIVE' ? twinState.mqttStatus : (twinState.mode === 'WIFI_LIVE' ? twinState.wifiStatus : 'OFFLINE');
  const activeLinkLabel = twinState.mode === 'MQTT_LIVE' ? 'MQTT Uplink' : (twinState.mode === 'WIFI_LIVE' ? 'WiFi Direct' : 'Simulator');

  const renderTabContent = () => {
    switch (activeTab) {
      case 'TWIN':
        return (
          <div className="h-full flex flex-col relative">
