                    {sensor === 'temperature' && <Thermometer size={18} className="mb-2" />}
                    {sensor === 'vibration' && <Activity size={18} className="mb-2" />}
                    {sensor === 'forces' && <Gauge size={18} className="mb-2" />}
                    {sensor === 'spindleLoad' && <Zap size={18} className="mb-2" />}
