        </div>
        <div className="flex items-center space-x-6">
          <div className="flex flex-col items-end">
            <span className="text-[8px] font-black text-slate-500 uppercase tracking-tighter">System Health</span>
            <span className={`text-[10px] font-black uppercase ${twinState.health === MachineHealth.HEALTHY ? 'text-emerald-400' : 'text-red-400'}`}>{twinState.health}</span>
