          <div className="h-8 w-px bg-white/10" />
          <div className="flex flex-col items-end">
            <span className="text-[8px] font-black text-slate-500 uppercase tracking-tighter">{activeLinkLabel}</span>
            <span className={`text-[10px] font-black uppercase ${activeLinkStatus === 'CONNECTED' ? 'text-indigo-400' : (activeLinkStatus === 'CONNECTING' ? 'text-amber-400' : 'text-slate-500')}`}>{activeLinkStatus}</span>
          </div>
        </div>
      </div>
      <div className="flex-1 overflow-hidden">
        {renderTabContent()}
      </div>
    </div>
  );
};

export enum MachineHealth {
  HEALTHY = 'HEALTHY',
  WARNING = 'WARNING',
  CRITICAL = 'CRITICAL'
}

export interface Material {
  id: string;
  name: string;
  hardnessFactor: number;
  thermalFactor: number;
}

export interface ToolGrade {
  id: string;
  name: string;
  durabilityFactor: number;
  heatResistance: number;
}

export interface TelemetryData {
  timestamp: number;
  rpm: number;
  feedRate: number;
  spindleLoad: number;
  vibration: number;
  temperature: number;
  toolWear: number;
  current: number;
  noiseLevel: number;
  powerConsumption: number;
  forces: {
    fx: number;
    fy: number;
    fz: number;
  };
}

export interface AIDiagnosticResponse {
  healthStatus: string;
  anomaliesDetected: string[];
  prediction: string;
  recommendedActions: string[];
  summary: string;
}

export interface MaterialTest {
  isActive: boolean;
  durationSeconds: number;
  targetWear: number;
  startTime: number | null;
  scenario?: 'NORMAL' | 'AGGRESSIVE' | 'THERMAL' | 'IMPACT';
  testTitle?: string;
  researcherName?: string;
  batchId?: string;
  hypothesis?: string;
}

export interface DiscoveredDevice {
  id: string;
  name: string;
  ip: string;
  port: string;
  latency: number;
  lastSeen: number;
  status: 'ONLINE' | 'OFFLINE';
}

export interface TwinState {
  id: string;
  name: string;
  model: string;
  health: MachineHealth;
  status: 'IDLE' | 'RUNNING' | 'ERROR' | 'MAINTENANCE';
  mode: 'SIMULATED' | 'MQTT_LIVE' | 'WIFI_LIVE';
  mqttStatus: 'CONNECTED' | 'DISCONNECTED' | 'CONNECTING';
  wifiStatus: 'CONNECTED' | 'DISCONNECTED' | 'CONNECTING';
  discoveredDevices: DiscoveredDevice[];
  cloudSync: 'SYNCED' | 'SYNCING' | 'ERROR' | 'OFFLINE';
  lastSyncTimestamp?: number;
  lastCommandSent: string | null;
  telemetry: TelemetryData;
  materialTest: MaterialTest;
  config: {
    material: Material;
    toolGrade: ToolGrade;
    simulationSpeed: number;
    enabledSensors: {
      vibration: boolean;
      temperature: boolean;
      forces: boolean;
      spindleLoad: boolean;
    };
    thresholds: {
      temperature: number;
      vibration: number;
      force: number;
      forceX: number;
      forceY: number;
      forceZ: number;
      spindleLoad: number;
      toolWear: number;
    };
    thingSpeakKey: string;
    mqttBroker: string;
    telemetryTopic: string;
    commandTopic: string;
    wifiEnabled: boolean;
    wifiSsid: string;
    wifiPassword: string;
    espIp: string;
    espPort: string;
  };
  predictions: {
    rul: number;
    failureProbability: number;
    nextMaintenanceDate: string;
    anomalyDetected: boolean;
  };
}

export interface ChartDataPoint {
  time: string;
  value: number;
}

