                      onChange={(e) => handleThresholdChange('vibration', parseFloat(e.target.value))}
                    />
                  </div>
                  <div className="space-y-2">
                    <div className="flex justify-between items-center text-[9px] font-black uppercase text-slate-500">
                      <span>Tool Wear Limit</span>
                      <span className="text-white font-mono">{twinState.config.thresholds.toolWear}%</span>
                    </div>
                    <input 
                      type="range" min="5" max="100" step="5"
                      className="w-full accent-slate-400 bg-slate-900 rounded-lg h-1.5"
