                      onChange={(e) => handleThresholdChange('toolWear', parseInt(e.target.value))}
                    />
                  </div>
                </div>

                <div className="mt-8 pt-6 border-t border-white/5">
                   <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-6 flex items-center">
                     <Gauge size={14} className="mr-2 text-indigo-400" /> Milling Dynamometer Force Limits
                   </h3>
                   <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
                      <div className="space-y-2">
                        <div className="flex justify-between items-center text-[9px] font-black uppercase text-slate-500">
                          <span>Fx Limit (N)</span>
                          <span className="text-white font-mono">{twinState.config.thresholds.forceX}N</span>
                        </div>
                        <input 
                          type="range" min="10" max="1000" step="10"
                          className="w-full accent-indigo-500 bg-slate-900 rounded-lg h-1.5"
                          value={twinState.config.thresholds.forceX}
                          onChange={(e) => handleThresholdChange('forceX', parseInt(e.target.value))}
                        />
                      </div>
                      <div className="space-y-2">
                        <div className="flex justify-between items-center text-[9px] font-black uppercase text-slate-500">
                          <span>Fy Limit (N)</span>
                          <span className="text-white font-mono">{twinState.config.thresholds.forceY}N</span>
                        </div>
                        <input 
                          type="range" min="10" max="1000" step="10"
                          className="w-full accent-indigo-500 bg-slate-900 rounded-lg h-1.5"
                          value={twinState.config.thresholds.forceY}
                          onChange={(e) => handleThresholdChange('forceY', parseInt(e.target.value))}
                        />
                      </div>
                      <div className="space-y-2">
                        <div className="flex justify-between items-center text-[9px] font-black uppercase text-slate-500">
                          <span>Fz Limit (N)</span>
                          <span className="text-white font-mono">{twinState.config.thresholds.forceZ}N</span>
                        </div>
                        <input 
                          type="range" min="10" max="1000" step="10"
                          className="w-full accent-red-500 bg-slate-900 rounded-lg h-1.5"
                          value={twinState.config.thresholds.forceZ}
                          onChange={(e) => handleThresholdChange('forceZ', parseInt(e.target.value))}
                        />
                      </div>
                   </div>
                </div>
              </section>
            </div>

            <section className="bg-white/5 p-6 rounded-3xl border border-white/5">
              <h2 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] flex items-center mb-6">
                 <Zap size={14} className="mr-2 text-indigo-500" /> Active Hardware Feeds
              </h2>
              <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
                {(['temperature', 'vibration', 'forces', 'spindleLoad'] as const).map(sensor => (
                  <button
                    key={sensor}
                    onClick={() => handleSensorToggle(sensor)}
                    className={`flex flex-col items-center p-3 rounded-2xl border transition-all ${
