               >
                  <div className={`w-6 h-6 rounded-full bg-white shadow-lg transition-all transform ${twinState.config.wifiEnabled ? 'translate-x-8' : 'translate-x-0'} flex items-center justify-center`}>
                    <Power size={12} className={twinState.config.wifiEnabled ? 'text-indigo-600' : 'text-slate-400'} />
                  </div>
               </button>
