                     <div className="absolute inset-12 rounded-full border border-indigo-500/5"></div>
                     <div className="relative z-10 w-20 h-20 bg-indigo-600/10 rounded-full flex items-center justify-center border border-indigo-500/30">
                        <Wifi size={32} className={`text-indigo-400 ${isScanning ? 'animate-pulse' : ''}`} />
                     </div>
                     {twinState.discoveredDevices.map((dev, i) => {
                        const angle = (i * 137.5) % 360;
                        const dist = 60 + (i * 20);
                        return (
                          <div 
                            key={dev.id}
                            className="absolute transition-all duration-1000"
                            style={{ 
                              transform: `rotate(${angle}deg) translateY(-${dist}px) rotate(-${angle}deg)`,
                              opacity: isScanning ? 0.3 : 1
                            }}
                          >
                             <div className="w-4 h-4 bg-emerald-500 rounded-full shadow-[0_0_15px_#10b981] animate-pulse"></div>
                          </div>
                        );
                     })}
                  </div>

                  <div className="space-y-3">
                    <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center px-1">
