                    ) : (
                      <div className="space-y-2">
                        {twinState.discoveredDevices.map(device => {
                          const isCurrent = twinState.config.espIp === device.ip;
                          const isConnecting = isCurrent && twinState.wifiStatus === 'CONNECTING';
