                                     <Activity size={8} className="mr-1" /> {device.latency}ms
                                   </span>
                                   <span className="text-[9px] font-black text-slate-500 uppercase">{device.status}</span>
                                </div>
                                <button 
                                  onClick={() => selectAndConnectDevice(device)}
                                  className={`px-3 py-1.5 rounded-lg text-[9px] font-black uppercase tracking-widest transition-all ${
                                    isConnected 
