                                    : isConnecting 
                                    ? 'bg-amber-500/20 text-amber-400 border border-amber-500/30 animate-pulse'
                                    : 'bg-indigo-600 text-white hover:bg-indigo-500'
                                  }`}
                                >
                                  {isConnected ? 'CONNECTED' : isConnecting ? 'CONNECTING...' : 'CONNECT'}
                                </button>
                              </div>
                            </div>
                          );
                        })}
                      </div>
                    )}
                  </div>
                </div>
              </section>
            )}

            <section className={`space-y-4 transition-opacity duration-300 ${!twinState.config.wifiEnabled ? 'opacity-40 pointer-events-none' : ''}`}>
              <h2 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] flex items-center">
                 <Network size={14} className="mr-2 text-indigo-500" /> Industrial IoT Cloud Integration
              </h2>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="bg-white/5 p-6 rounded-3xl border border-white/5 space-y-4">
                   <h3 className="text-[10px] font-black text-indigo-400 uppercase tracking-widest flex items-center">
                    <Cloud size={14} className="mr-2" /> ThingSpeak Analytical Platform
                  </h3>
                  <div className="space-y-4">
                    <div className="space-y-1">
                      <label className="text-[10px] font-black text-slate-500 uppercase ml-1 flex items-center">
                        <Key size={10} className="mr-1" /> Channel Write API Key
                      </label>
                      <input 
                        type="password"
                        value={twinState.config.thingSpeakKey}
                        onChange={(e) => onConfigChange({ thingSpeakKey: e.target.value })}
                        className="w-full bg-slate-900 border border-white/10 rounded-xl px-3 py-3 text-xs text-white outline-none focus:border-indigo-500 font-mono"
                        placeholder="Paste Write API Key Here..."
                      />
                    </div>
                  </div>
                </div>

                <div className="bg-white/5 p-6 rounded-3xl border border-white/5 space-y-4">
                  <h3 className="text-[10px] font-black text-emerald-400 uppercase tracking-widest flex items-center">
                    <Cpu size={14} className="mr-2" /> WiFi Direct Configuration (ESP32)
                  </h3>
                  <div className="space-y-3">
                    <div className="grid grid-cols-2 gap-3">
                      <div className="space-y-1">
                        <label className="text-[10px] font-black text-slate-500 uppercase ml-1">IP Address</label>
                        <input 
                          type="text"
                          value={twinState.config.espIp}
                          onChange={(e) => onConfigChange({ espIp: e.target.value })}
                          className="w-full bg-slate-900 border border-white/10 rounded-xl px-3 py-2 text-xs text-white"
                        />
                      </div>
                      <div className="space-y-1">
                        <label className="text-[10px] font-black text-slate-500 uppercase ml-1">Port</label>
                        <input 
                          type="text"
                          value={twinState.config.espPort}
                          onChange={(e) => onConfigChange({ espPort: e.target.value })}
                          className="w-full bg-slate-900 border border-white/10 rounded-xl px-3 py-2 text-xs text-white"
                        />
                      </div>
                    </div>
                    <div className="p-3 bg-emerald-500/5 border border-emerald-500/10 rounded-xl flex items-center justify-between">
                       <span className="text-[9px] font-black text-slate-300 uppercase">WiFi Link Health</span>
                       <span className={`text-[10px] font-black uppercase ${twinState.wifiStatus === 'CONNECTED' ? 'text-emerald-400' : (twinState.wifiStatus === 'CONNECTING' ? 'text-amber-400 animate-pulse' : 'text-slate-500')}`}>{twinState.wifiStatus}</span>
                    </div>
                  </div>
                </div>
              </div>
            </section>
          </div>
        );
      case 'HISTORY':
        return <ProcessHistory history={history} health={twinState.health} status={twinState.status} />;
      default:
        return null;
    }
  };

  return (
    <div className="h-full flex flex-col bg-[#020617] overflow-hidden">
      <div className="flex items-center px-6 py-2 bg-slate-900/30 border-b border-white/5 justify-between">
        <div className="flex space-x-1">
          {(['TWIN', 'ANALYTICS', 'HISTORY', 'SETUP', 'CONNECTIVITY'] as TabType[]).map((tab) => (
            <button
              key={tab}
              onClick={() => setActiveTab(tab)}
              className={`flex items-center space-x-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${
                activeTab === tab 
                ? 'bg-indigo-600 text-white shadow-lg' 
                : 'text-slate-500 hover:text-slate-300 hover:bg-white/5'
              }`}
            >
              {tab === 'TWIN' && <LayoutDashboard size={14} />}
              {tab === 'ANALYTICS' && <Binary size={14} />}
              {tab === 'HISTORY' && <History size={14} />}
              {tab === 'SETUP' && <Settings size={14} />}
              {tab === 'CONNECTIVITY' && <Network size={14} />}
              <span>{tab === 'SETUP' ? 'PROCESS SETUP' : tab}</span>
            </button>
          ))}
        </div>
        <div className="flex items-center space-x-6">
          <div className="flex flex-col items-end">
            <span className="text-[8px] font-black text-slate-500 uppercase tracking-tighter">System Health</span>
            <span className={`text-[10px] font-black uppercase ${twinState.health === MachineHealth.HEALTHY ? 'text-emerald-400' : 'text-red-400'}`}>{twinState.health}</span>
          </div>
