              {tab === 'HISTORY' && <History size={14} />}
              {tab === 'USER DATA' && <Beaker size={14} />}
              {tab === 'SETUP' && <Settings size={14} />}
              {tab === 'CONNECTIVITY' && <Network size={14} />}
              <span>{tab === 'SETUP' ? 'PROCESS SETUP' : tab}</span>
            </button>
          ))}
        </div>
        <div className="flex items-center space-x-6">
          <div className="flex flex-col items-end">
            <span className="text-[8px] font-black text-slate-500 uppercase tracking-tighter">{activeLinkLabel}</span>
            <span className={`text-[10px] font-black uppercase ${activeLinkStatus === 'CONNECTED' ? 'text-indigo-400' : (activeLinkStatus === 'CONNECTING' ? 'text-amber-400' : (activeLinkStatus === 'OFFLINE' ? 'text-slate-600' : 'text-slate-500'))}`}>{activeLinkStatus}</span>
          </div>
        </div>
      </div>
      <div className="flex-1 overflow-hidden">
        {renderTabContent()}
      </div>
    </div>
  );
};

