            <span className={`text-[10px] font-black uppercase ${activeLinkStatus === 'CONNECTED' ? 'text-indigo-400' : (activeLinkStatus === 'CONNECTING' ? 'text-amber-400' : (activeLinkStatus === 'OFFLINE' ? 'text-slate-600' : 'text-slate-500'))}`}>{activeLinkStatus}</span>
