                  <input type="range" min="0.1" max="10.0" step="0.1" className="w-full accent-indigo-500 bg-slate-900 rounded-xl" value={twinState.config.simulationSpeed} onChange={(e) => onConfigChange({ simulationSpeed: parseFloat(e.target.value) })} />
