                  </div>
                </div>
              </section>
            </div>
          </div>
        );
      case 'CONNECTIVITY':
        return (
          <div className="p-6 space-y-8 overflow-y-auto h-full scrollbar-hide">
            <section className="bg-indigo-600/5 border border-indigo-500/20 p-6 rounded-[2.5rem] flex items-center justify-between">
              <div className="flex items-center space-x-4">
                <div className={`p-3 rounded-2xl ${twinState.config.wifiEnabled ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-500'}`}><Wifi size={24} /></div>
                <div>
                  <h2 className="text-sm font-black text-white uppercase tracking-widest">WiFi Core</h2>
