                <div className={`w-6 h-6 rounded-full bg-white shadow-lg transition-all transform ${twinState.config.wifiEnabled ? 'translate-x-8' : 'translate-x-0'}`} />
              </button>
            </section>
          </div>
        );
      case 'HISTORY':
        return <ProcessHistory history={history} health={twinState.health} status={twinState.status} />;
      default:
        return null;
    }
  };

  return (
    <div className="h-full flex flex-col bg-[#020617] overflow-hidden">
      <div className="flex items-center px-6 py-2 bg-slate-900/30 border-b border-white/5 justify-between">
        <div className="flex space-x-1">
          {(['TWIN', 'ANALYTICS', 'HISTORY', 'USER DATA', 'SETUP', 'CONNECTIVITY'] as TabType[]).map((tab) => (
            <button key={tab} onClick={() => setActiveTab(tab)} className={`flex items-center space-x-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}>
              {tab === 'TWIN' && <LayoutDashboard size={14} />}
              {tab === 'ANALYTICS' && <Binary size={14} />}
              {tab === 'HISTORY' && <History size={14} />}
              {tab === 'USER DATA' && <Beaker size={14} />}
              {tab === 'SETUP' && <Settings size={14} />}
              {tab === 'CONNECTIVITY' && <Network size={14} />}
              <span>{tab === 'SETUP' ? 'PROCESS SETUP' : tab}</span>
            </button>
          ))}
        </div>
        <div className="flex items-center space-x-6 text-[10px] font-black uppercase tracking-tighter">
          <div className="flex flex-col items-end">
            <span className="text-slate-500">{activeLinkLabel}</span>
            <span className={activeLinkStatus === 'CONNECTED' ? 'text-indigo-400' : 'text-slate-600'}>{activeLinkStatus}</span>
          </div>
        </div>
      </div>
      <div className="flex-1 overflow-hidden">{renderTabContent()}</div>
    </div>
  );
};

