interface Alarm {
  type: 'CRITICAL' | 'WARNING';
  category: 'THERMAL' | 'VIBRATION' | 'WEAR' | 'SYSTEM' | 'LOAD' | 'FORCE';
  message: string;
  recommendations: string[];
}

interface NotificationItem {
  id: string;
  type: 'CRITICAL' | 'WARNING' | 'INFO';
  category: string;
  message: string;
  timestamp: number;
}

const App: React.FC = () => {
  const [twinState, setTwinState] = useState<TwinState>(INITIAL_STATE);
  const [history, setHistory] = useState<TelemetryData[]>([]);
  const [activeAlarm, setActiveAlarm] = useState<Alarm | null>(null);
  const [notifications, setNotifications] = useState<NotificationItem[]>([]);
  const [isScanning, setIsScanning] = useState(false);

  const stateRef = useRef<TwinState>(INITIAL_STATE);
  const mqttClientRef = useRef<any>(null);
  const lastCloudSyncRef = useRef<number>(0);
  const notificationThrottleRef = useRef<Record<string, number>>({});

  useEffect(() => {
    stateRef.current = twinState;
  }, [twinState]);

  const addNotification = useCallback((type: 'CRITICAL' | 'WARNING' | 'INFO', category: string, message: string) => {
    const key = `${category}-${type}`;
    const now = Date.now();
    if (notificationThrottleRef.current[key] && now - notificationThrottleRef.current[key] < 5000) return;

    notificationThrottleRef.current[key] = now;
    const newNotif: NotificationItem = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      category,
      message,
      timestamp: now
    };

    setNotifications(prev => [newNotif, ...prev].slice(0, 5));
    setTimeout(() => {
      setNotifications(prev => prev.filter(n => n.id !== newNotif.id));
    }, 8000);
  }, []);

  const scanForDevices = useCallback(async () => {
    if (isScanning || !stateRef.current.config.wifiEnabled) return;
    setIsScanning(true);

    const { espIp, espPort } = stateRef.current.config;
    const discovered: DiscoveredDevice[] = [];

    try {
      const startTime = Date.now();
      await fetch(`http://${espIp}:${espPort}/telemetry`, { 
        mode: 'no-cors',
        signal: AbortSignal.timeout(1500) 
      });
      discovered.push({
        id: 'node-current',
        name: 'Acu-Drill Pro ESP32',
        ip: espIp,
        port: espPort,
        latency: Date.now() - startTime,
        lastSeen: Date.now(),
        status: 'ONLINE'
      });
    } catch (e) {}

    discovered.push({
      id: 'node-sim-01',
      name: 'Workshop B - Lathe-04',
      ip: '192.168.1.105',
      port: '80',
      latency: 42,
      lastSeen: Date.now(),
      status: 'ONLINE'
    });

    setTwinState(s => ({ ...s, discoveredDevices: discovered }));
    setTimeout(() => setIsScanning(false), 2000);
  }, [isScanning]);

  const handleConfigChange = useCallback((cfg: any) => {
    setTwinState(s => {
      const newState = { ...s };
      if (cfg.materialTest) {
        newState.materialTest = { ...s.materialTest, ...cfg.materialTest };
      }
      if (cfg.thresholds) {
        newState.config = { ...s.config, thresholds: { ...s.config.thresholds, ...cfg.thresholds } };
      }
      if (cfg.material || cfg.toolGrade || cfg.hasOwnProperty('thingSpeakKey') || 
          cfg.mqttBroker || cfg.telemetryTopic || cfg.commandTopic || 
          cfg.hasOwnProperty('wifiEnabled') || cfg.wifiSsid || cfg.wifiPassword || 
          cfg.espIp || cfg.espPort || cfg.hasOwnProperty('simulationSpeed') || 
          cfg.hasOwnProperty('enabledSensors')) {
        newState.config = { ...s.config, ...cfg };
      }
      if (cfg.status) newState.status = cfg.status;
      return newState;
    });
  }, []);

  const handleSetMode = useCallback((mode: TwinState['mode']) => {
    setTwinState(s => ({ ...s, mode }));
  }, []);

  const syncToThingSpeak = useCallback(async (telemetry: TelemetryData, key: string) => {
    if (!key || key.trim() === '') return;
    const now = Date.now();
    if (now - lastCloudSyncRef.current < 16000) return;
    lastCloudSyncRef.current = now;

    setTwinState(s => ({ ...s, cloudSync: 'SYNCING' }));
    try {
      const baseUrl = 'https://api.thingspeak.com/update';
      const params = new URLSearchParams({
        api_key: key,
        field1: Math.round(telemetry.rpm).toString(),
        field2: telemetry.temperature.toFixed(2),
        field3: telemetry.toolWear.toFixed(2),
        field4: telemetry.vibration.toFixed(3),
        field5: Math.round(telemetry.forces.fz).toString()
      });
      const response = await fetch(`${baseUrl}?${params.toString()}`);
      if (response.ok) {
        setTwinState(s => ({ ...s, cloudSync: 'SYNCED', lastSyncTimestamp: now }));
      } else {
        setTwinState(s => ({ ...s, cloudSync: 'ERROR' }));
      }
    } catch (e) {
      setTwinState(s => ({ ...s, cloudSync: 'ERROR' }));
    }
  }, []);

  useEffect(() => {
    const { telemetry, config, status } = twinState;
    if (status === 'RUNNING' || twinState.mode !== 'SIMULATED') {
      syncToThingSpeak(telemetry, config.thingSpeakKey);
    }
  }, [twinState.telemetry, twinState.config.thingSpeakKey, syncToThingSpeak]);

  const sendHardwareCommand = useCallback(async (action: string, value?: string) => {
    const { espIp, espPort } = stateRef.current.config;
    if (!espIp) return;
    const url = `http://${espIp}:${espPort}/control?action=${action}${value ? `&value=${value}` : ''}`;
    try {
      setTwinState(s => ({ ...s, lastCommandSent: `UPLINK [HTTP]: ${action}${value ? `=${value}` : ''}` }));
      await fetch(url, { mode: 'no-cors' }); 
    } catch (error) {
      setTwinState(s => ({ ...s, lastCommandSent: 'UPLINK ERROR: TARGET UNREACHABLE' }));
    }
  }, []);

  const resetMachine = useCallback(() => {
    setActiveAlarm(null);
    setNotifications([]);
    if (stateRef.current.mode === 'SIMULATED') {
      setTwinState(prev => ({ 
        ...prev, 
        status: 'IDLE', 
        health: MachineHealth.HEALTHY,
        telemetry: { ...prev.telemetry, temperature: 24, toolWear: 0, rpm: 0, vibration: 0.1 },
        materialTest: { ...prev.materialTest, isActive: false, startTime: null }
      }));
    } else {
      sendHardwareCommand('RESET_SYSTEM');
    }
  }, [sendHardwareCommand]);

  useEffect(() => {
    if (twinState.mode === 'MQTT_LIVE') {
      try {
        const client = mqtt.connect(twinState.config.mqttBroker);
        mqttClientRef.current = client;
        client.on('connect', () => {
          setTwinState(s => ({ ...s, mqttStatus: 'CONNECTED' }));
          client.subscribe(stateRef.current.config.telemetryTopic);
        });
        client.on('message', (topic, message) => {
          if (topic === stateRef.current.config.telemetryTopic) {
            try {
              const payload = JSON.parse(message.toString());
              setTwinState(s => {
                const updatedTele = { ...s.telemetry, ...payload, timestamp: Date.now() };
                setHistory(prev => [...prev, updatedTele].slice(-50));
                return { ...s, telemetry: updatedTele, status: payload.status || s.status };
              });
            } catch (e) {}
          }
        });
        client.on('error', () => setTwinState(s => ({ ...s, mqttStatus: 'DISCONNECTED' })));
      } catch (e) {}
    } else if (mqttClientRef.current) {
      mqttClientRef.current.end();
      setTwinState(s => ({ ...s, mqttStatus: 'DISCONNECTED' }));
    }
    return () => { if (mqttClientRef.current) mqttClientRef.current.end(); };
  }, [twinState.mode, twinState.config.mqttBroker]);

  useEffect(() => {
    const interval = setInterval(() => {
      setTwinState(prev => {
        if (prev.mode !== 'SIMULATED') return prev;

        const { material, toolGrade, simulationSpeed, enabledSensors, thresholds } = prev.config;
        const { isActive, startTime, durationSeconds, targetWear: testTargetWear } = prev.materialTest;
        const scenario = prev.materialTest.scenario || 'NORMAL';

        let isRunning = prev.status === 'RUNNING';
        let currentStatus = prev.status;
        let testActive = isActive;

        if (isRunning && testActive && startTime) {
          const elapsed = (Date.now() - startTime) / 1000;
          if (elapsed >= durationSeconds) {
            addNotification('INFO', 'SYSTEM', `Material Test completed: Time Limit reached (${durationSeconds}s)`);
            isRunning = false;
            currentStatus = 'IDLE';
            testActive = false;
          }
        }

        const loadMod = material.hardnessFactor || 1;
        let wearMultiplier = testActive ? 8 : 1; 
        let heatMultiplier = 1;
        let forceMultiplier = 1;

        if (testActive) {
          switch(scenario) {
            case 'AGGRESSIVE': wearMultiplier *= 3.0; forceMultiplier = 2.2; break;
            case 'THERMAL': heatMultiplier = 3.5; wearMultiplier *= 1.5; break;
            case 'IMPACT': wearMultiplier *= 6.0; forceMultiplier = 3.5; break;
          }
        }

        const heatMod = ((loadMod / (material.thermalFactor || 1)) / (toolGrade.heatResistance || 1)) * heatMultiplier * simulationSpeed;
        const wearMod = (loadMod / (toolGrade.durabilityFactor || 1)) * (isRunning ? 0.0008 : 0) * wearMultiplier * simulationSpeed;

        const noise = (val: number, range: number) => val + (Math.random() - 0.5) * range;
        const cycleSec = (Date.now() / 1000) % 4;
        const isCutting = isRunning && cycleSec > 0.5 && cycleSec < 3.0;
        const baseForce = isCutting ? 180 * loadMod * forceMultiplier : 0;

        const nextTele: TelemetryData = {
          timestamp: Date.now(),
          rpm: isRunning ? noise(3200, 50) : 0,
          feedRate: isRunning ? noise(450, 20) : 0,
          spindleLoad: (isRunning && enabledSensors.spindleLoad) ? noise(42 * loadMod * forceMultiplier, 10) : 0,
          vibration: (isRunning && enabledSensors.vibration) ? noise(1.4 * loadMod * forceMultiplier, 0.4) : noise(0.05, 0.02),
          temperature: enabledSensors.temperature 
            ? (isRunning 
                ? Math.min(135, prev.telemetry.temperature + (1.2 * heatMod)) 
                : Math.max(24, prev.telemetry.temperature - (0.5 * simulationSpeed))) 
            : 24,
          toolWear: Math.min(100, prev.telemetry.toolWear + wearMod),
          current: isRunning ? noise(2.0 + (prev.telemetry.spindleLoad / 20), 0.2) : 0,
          noiseLevel: isRunning ? noise(75 + (wearMod * 1000), 5) : 35,
          powerConsumption: isRunning ? noise(4.8 * loadMod * forceMultiplier, 0.8) : 0.2,
          forces: {
            fx: (isCutting && enabledSensors.forces) ? noise(baseForce * 0.1, 10) : noise(0, 1),
            fy: (isCutting && enabledSensors.forces) ? noise(baseForce * 0.1, 10) : noise(0, 1),
            fz: (isCutting && enabledSensors.forces) ? noise(baseForce * 1.6, 40) : noise(0, 2)
          }
        };

        setHistory(h => [...h, nextTele].slice(-50));

        if (isRunning && testActive && nextTele.toolWear >= testTargetWear) {
          addNotification('INFO', 'SYSTEM', `Material Test completed: Wear Target reached (${testTargetWear}%)`);
          isRunning = false;
          currentStatus = 'IDLE';
          testActive = false;
        }

        if (isRunning && !activeAlarm) {
          let alarm: Alarm | null = null;
          if (nextTele.toolWear >= thresholds.toolWear) {
            alarm = { type: 'CRITICAL', category: 'WEAR', message: `LIMIT EXCEEDED: Tool Wear reached ${thresholds.toolWear}%`, recommendations: ["Tool change mandatory"] };
          } else if (enabledSensors.temperature && nextTele.temperature > thresholds.temperature) {
            alarm = { type: 'CRITICAL', category: 'THERMAL', message: `LIMIT EXCEEDED: Temperature reached ${nextTele.temperature.toFixed(1)}°C`, recommendations: ["Check cooling systems"] };
          } else if (enabledSensors.vibration && nextTele.vibration > thresholds.vibration) {
            alarm = { type: 'CRITICAL', category: 'VIBRATION', message: `LIMIT EXCEEDED: Vibration reached ${nextTele.vibration.toFixed(2)}g`, recommendations: ["Inspect tool seating"] };
          }

          if (alarm) { 
            setActiveAlarm(alarm); 
            addNotification('CRITICAL', alarm.category, alarm.message);
            isRunning = false; 
            currentStatus = 'IDLE'; 
            testActive = false; 
          }
        }

        let health = MachineHealth.HEALTHY;
        if (nextTele.temperature > thresholds.temperature * 0.8 || nextTele.toolWear > thresholds.toolWear * 0.8) health = MachineHealth.WARNING;
        if (nextTele.temperature > thresholds.temperature || nextTele.toolWear >= thresholds.toolWear) health = MachineHealth.CRITICAL;

        return { 
          ...prev, 
          status: currentStatus, 
          health, 
          telemetry: nextTele, 
          materialTest: { ...prev.materialTest, isActive: testActive }
        };
      });
    }, MACHINE_CONFIG.POLLING_INTERVAL_MS);
    return () => clearInterval(interval);
  }, [activeAlarm, addNotification]);

  const toggleMachine = useCallback(() => {
    const nextStatus = twinState.status === 'RUNNING' ? 'IDLE' : 'RUNNING';
    if (twinState.mode === 'SIMULATED') {
      setTwinState(prev => ({ 
        ...prev, 
        status: nextStatus,
        materialTest: {
          ...prev.materialTest,
          startTime: nextStatus === 'RUNNING' ? Date.now() : prev.materialTest.startTime
        }
      }));
    } else {
      sendHardwareCommand('SET_STATUS', nextStatus);
    }
  }, [twinState.status, twinState.mode, sendHardwareCommand]);

  return (
    <div className="w-full h-full bg-[#020617] flex flex-col overflow-hidden">
      <header className="px-6 py-4 bg-slate-900/50 backdrop-blur-xl border-b border-white/5 flex justify-between items-center z-50">
        <div className="flex items-center space-x-4">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <Wifi className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-xl font-black text-white tracking-tighter uppercase italic">Twin<span className="text-indigo-400">Core</span></h1>
            <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Digital Force Twin</span>
          </div>
        </div>
        <div className="flex items-center space-x-4">
          <div className="flex bg-black/40 p-1 rounded-lg border border-white/5">
            {['SIMULATED', 'MQTT_LIVE', 'WIFI_LIVE'].map(m => (
              <button 
                key={m}
                onClick={() => handleSetMode(m as any)}
                className={`px-4 py-1.5 rounded-md text-[10px] font-black tracking-widest uppercase transition-all ${twinState.mode === m ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-white'}`}
              >
                {m.split('_')[0]}
              </button>
            ))}
          </div>
          <div className="flex space-x-2">
             <button onClick={toggleMachine} className={`px-6 py-2 rounded-lg font-black text-[11px] uppercase tracking-wider transition-all shadow-lg ${twinState.status === 'RUNNING' ? 'bg-red-500 shadow-red-500/20' : 'bg-emerald-500 shadow-emerald-500/20'} text-white`}>{twinState.status === 'RUNNING' ? 'STOP' : 'START'}</button>
             <button onClick={resetMachine} className="px-6 py-2 bg-slate-800 hover:bg-slate-700 rounded-lg font-black text-[11px] uppercase tracking-wider text-white border border-white/5">RESET</button>
          </div>
        </div>
      </header>

      {/* Notifications Layer */}
      <div className="fixed top-24 right-6 z-[60] flex flex-col items-end space-y-3 pointer-events-none">
        {notifications.map((notif) => (
          <div key={notif.id} className={`w-72 p-4 rounded-2xl border backdrop-blur-xl shadow-2xl pointer-events-auto animate-in slide-in-from-right duration-300 flex items-start space-x-3 ${
            notif.type === 'CRITICAL' ? 'bg-red-500/10 border-red-500/30 text-red-100' : 
            notif.type === 'INFO' ? 'bg-indigo-500/10 border-indigo-500/30 text-indigo-100' : 'bg-amber-500/10 border-amber-500/30 text-amber-100'
          }`}>
            <div className={`p-1.5 rounded-lg ${notif.type === 'CRITICAL' ? 'bg-red-500' : notif.type === 'INFO' ? 'bg-indigo-500' : 'bg-amber-500'}`}>
               {notif.type === 'CRITICAL' ? <AlertCircle size={14} className="text-white" /> : notif.type === 'INFO' ? <Info size={14} className="text-white" /> : <AlertTriangle size={14} className="text-white" />}
            </div>
            <div className="flex-1">
              <p className="text-[11px] font-bold uppercase tracking-widest opacity-50 mb-1">{notif.category}</p>
              <p className="text-[11px] font-medium leading-tight">{notif.message}</p>
            </div>
          </div>
        ))}
      </div>

      {activeAlarm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
          <div className="w-full max-w-xl bg-[#0f172a] border-2 border-red-500/50 rounded-[2rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300">
            <div className="bg-red-600 p-6 flex items-center justify-between text-white">
              <div className="flex items-center space-x-4">
                <ShieldAlert size={28} />
                <h2 className="text-xl font-black uppercase tracking-tight">Industrial Safety Halt</h2>
              </div>
              <button onClick={() => setActiveAlarm(null)}><X size={24} /></button>
            </div>
            <div className="p-8 space-y-8">
              <p className="text-lg font-bold text-white leading-tight">{activeAlarm.message}</p>
              <button onClick={resetMachine} className="w-full bg-red-600 hover:bg-red-500 text-white font-black py-4 rounded-2xl uppercase text-sm tracking-widest">Confirm & Reset</button>
            </div>
          </div>
        </div>
      )}

      <main className="flex-1 relative overflow-hidden">
        <Dashboard 
          twinState={twinState} 
          history={history} 
          materials={MATERIALS} 
          toolGrades={TOOL_GRADES} 
          onConfigChange={handleConfigChange}
          onSetMode={handleSetMode}
          onScanDevices={scanForDevices}
          isScanning={isScanning}
        />
      </main>
    </div>
  );
};

