                 <h2 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] flex items-center mb-6"><Activity size={14} className="mr-2 text-indigo-500" /> Simulation Scale</h2>
                <div className="space-y-4">
                  <input type="range" min="0.1" max="10.0" step="0.1" className="w-full accent-indigo-500 bg-slate-900 rounded-xl" value={twinState.config.simulationSpeed} onChange={(e) => onConfigChange({ simulationSpeed: parseFloat(e.target.value) })} />
                  <div className="flex justify-between items-center"><span className="text-[10px] font-black text-slate-500 uppercase">Velocity</span><span className="text-lg font-black text-white font-mono">{twinState.config.simulationSpeed.toFixed(1)}x</span></div>
                </div>
              </section>
              <section className="bg-white/5 p-6 rounded-3xl border border-white/5 lg:col-span-3">
                <h2 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] flex items-center mb-6"><Shield size={14} className="mr-2 text-red-500" /> Safety Thresholds</h2>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-x-8 gap-y-6">
                  <div className="space-y-2">
                    <div className="flex justify-between text-[9px] font-black uppercase text-slate-500"><span>Temp Limit</span><span className="text-white">{twinState.config.thresholds.temperature}°C</span></div>
                    <input type="range" min="30" max="130" step="5" className="w-full accent-red-500 bg-slate-900 rounded-lg h-1.5" value={twinState.config.thresholds.temperature} onChange={(e) => handleThresholdChange('temperature', parseInt(e.target.value))} />
                  </div>
                  <div className="space-y-2">
                    <div className="flex justify-between text-[9px] font-black uppercase text-slate-500"><span>Vibration Limit</span><span className="text-white">{twinState.config.thresholds.vibration}g</span></div>
                    <input type="range" min="0.5" max="10.0" step="0.5" className="w-full accent-amber-500 bg-slate-900 rounded-lg h-1.5" value={twinState.config.thresholds.vibration} onChange={(e) => handleThresholdChange('vibration', parseFloat(e.target.value))} />
                  </div>
                  <div className="space-y-2">
                    <div className="flex justify-between text-[9px] font-black uppercase text-slate-500"><span>Spindle RPM Limit</span><span className="text-white">{twinState.config.thresholds.rpm} RPM</span></div>
                    <input type="range" min="500" max="6000" step="100" className="w-full accent-blue-500 bg-slate-900 rounded-lg h-1.5" value={twinState.config.thresholds.rpm} onChange={(e) => handleThresholdChange('rpm', parseInt(e.target.value))} />
                  </div>
                  <div className="space-y-2">
                    <div className="flex justify-between text-[9px] font-black uppercase text-slate-500"><span>Spindle Load Limit</span><span className="text-white">{twinState.config.thresholds.spindleLoad}%</span></div>
                    <input type="range" min="10" max="100" step="5" className="w-full accent-purple-500 bg-slate-900 rounded-lg h-1.5" value={twinState.config.thresholds.spindleLoad} onChange={(e) => handleThresholdChange('spindleLoad', parseInt(e.target.value))} />
                  </div>
                  <div className="space-y-2">
                    <div className="flex justify-between text-[9px] font-black uppercase text-slate-500"><span>Axial Force (Fz) Limit</span><span className="text-white">{twinState.config.thresholds.forceZ}N</span></div>
                    <input type="range" min="50" max="1500" step="50" className="w-full accent-indigo-500 bg-slate-900 rounded-lg h-1.5" value={twinState.config.thresholds.forceZ} onChange={(e) => handleThresholdChange('forceZ', parseInt(e.target.value))} />
                  </div>
                  <div className="space-y-2">
                    <div className="flex justify-between text-[9px] font-black uppercase text-slate-500"><span>Tool Wear Limit</span><span className="text-white">{twinState.config.thresholds.toolWear}%</span></div>
                    <input type="range" min="5" max="100" step="5" className="w-full accent-slate-400 bg-slate-900 rounded-lg h-1.5" value={twinState.config.thresholds.toolWear} onChange={(e) => handleThresholdChange('toolWear', parseInt(e.target.value))} />
                  </div>
                </div>
              </section>
            </div>
          </div>
        );
      case 'CONNECTIVITY':
        return (
          <div className="p-6 space-y-8 overflow-y-auto h-full scrollbar-hide">
            <section className="bg-indigo-600/5 border border-indigo-500/20 p-6 rounded-[2.5rem] flex items-center justify-between">
              <div className="flex items-center space-x-4">
                <div className={`p-3 rounded-2xl ${twinState.config.wifiEnabled ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-500'}`}><Wifi size={24} /></div>
                <div>
                  <h2 className="text-sm font-black text-white uppercase tracking-widest">WiFi Core</h2>
                  <p className="text-[9px] text-slate-500 font-bold uppercase">{twinState.config.wifiEnabled ? 'Enabled' : 'Disabled'}</p>
                </div>
              </div>
              <button onClick={() => onConfigChange({ wifiEnabled: !twinState.config.wifiEnabled })} className={`relative w-16 h-8 rounded-full transition-all flex items-center px-1 ${twinState.config.wifiEnabled ? 'bg-indigo-600' : 'bg-slate-800'}`}>
                <div className={`w-6 h-6 rounded-full bg-white shadow-lg transition-all transform ${twinState.config.wifiEnabled ? 'translate-x-8' : 'translate-x-0'}`} />
              </button>
            </section>
          </div>
        );
      case 'HISTORY':
        return <ProcessHistory history={history} health={twinState.health} status={twinState.status} />;
      default:
        return null;
    }
  };

  return (
    <div className="h-full flex flex-col bg-[#020617] overflow-hidden">
      <div className="flex items-center px-6 py-2 bg-slate-900/30 border-b border-white/5 justify-between">
        <div className="flex space-x-1">
          {(['TWIN', 'ANALYTICS', 'HISTORY', 'USER DATA', 'SETUP', 'CONNECTIVITY'] as TabType[]).map((tab) => (
            <button key={tab} onClick={() => setActiveTab(tab)} className={`flex items-center space-x-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}>
              {tab === 'TWIN' && <LayoutDashboard size={14} />}
              {tab === 'ANALYTICS' && <Binary size={14} />}
              {tab === 'HISTORY' && <History size={14} />}
              {tab === 'USER DATA' && <Beaker size={14} />}
              {tab === 'SETUP' && <Settings size={14} />}
              {tab === 'CONNECTIVITY' && <Network size={14} />}
              <span>{tab === 'SETUP' ? 'PROCESS SETUP' : tab}</span>
            </button>
          ))}
        </div>
        <div className="flex items-center space-x-6 text-[10px] font-black uppercase tracking-tighter">
          <div className="flex flex-col items-end">
            <span className="text-slate-500">{activeLinkLabel}</span>
            <span className={activeLinkStatus === 'CONNECTED' ? 'text-indigo-400' : 'text-slate-600'}>{activeLinkStatus}</span>
          </div>
        </div>
      </div>
      <div className="flex-1 overflow-hidden">{renderTabContent()}</div>
    </div>
  );
};
